.badge-needsmoreinfo { background: #fef3c7; color: #92400e; }
.badge-underreview { background: #e0e7ff; color: #4338ca; }
.badge-approved { background: #dcfce7; color: #166534; }
.badge-rejected { background: #fee2e2; color: #991b1b; }
.badge-cancelled { background: #f1f5f9; color: #64748b; }
.badge-waitlisted { background: #fce7f3; color: #9d174d; }

/* --- Audit Timeline --- */
.audit-timeline {
  position: relative;
  padding-left: 24px;
}

.audit-timeline::before {
  content: '';
  position: absolute;
  left: 8px;
  top: 0;
  bottom: 0;
  width: 2px;
  background: var(--color-border);
}

.audit-entry {
  position: relative;
  margin-bottom: 16px;
  padding-bottom: 16px;
}

.audit-entry::before {
  content: '';
  position: absolute;
  left: -20px;
  top: 4px;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--color-primary);
  border: 2px solid var(--color-surface);
}

.audit-entry .audit-time {
  font-size: 0.75rem;
  color: var(--color-text-muted);
}

.audit-entry .audit-desc {
  margin-top: 2px;
  font-size: 0.875rem;
}

/* --- Filters Bar --- */
.filters-bar {
  display: flex;
  gap: 12px;
  align-items: center;
  margin-bottom: 16px;
  flex-wrap: wrap;
}

.filters-bar .form-control {
  width: auto;
  min-width: 160px;
}

/* --- Charts placeholder --- */
.chart-container {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  padding: 20px;
  min-height: 200px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.charts-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(350px, 1fr));
  gap: 16px;
  margin-bottom: 24px;
}

/* --- Responsive --- */
@media (max-width: 768px) {
  .sidebar {
    position: fixed;
    left: -var(--sidebar-width);
    z-index: 800;
    transition: left var(--transition);
  }
  .sidebar.open { left: 0; }
  .kpi-grid { grid-template-columns: 1fr 1fr; }
  .drawer { width: 100vw; }
}

/* --- Login Page --- */
.login-page {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  background: var(--color-bg);
}

.login-card {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  box-shadow: var(--shadow-md);
  padding: 40px;
  width: 100%;
  max-width: 400px;
}

.login-card h1 {
  font-size: 1.3rem;
  margin-bottom: 4px;
}

.login-card .subtitle {
  color: var(--color-text-secondary);
  margin-bottom: 24px;
  font-size: 0.9rem;
}

/* --- Toast / Notifications --- */
.toast-container {
  position: fixed;
  top: 16px;
  right: 16px;
  z-index: 2000;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.toast {
  padding: 12px 20px;
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  box-shadow: var(--shadow-md);
  font-size: 0.875rem;
  min-width: 250px;
  animation: toast-in 200ms ease;
}

.toast-success { border-left: 4px solid var(--color-success); }
.toast-error { border-left: 4px solid var(--color-danger); }
.toast-warning { border-left: 4px solid var(--color-warning); }
.toast-info { border-left: 4px solid var(--color-info); }

@keyframes toast-in {
  from { opacity: 0; transform: translateX(20px); }
  to { opacity: 1; transform: translateX(0); }
}

/* --- Utility --- */
.text-center { text-align: center; }
.text-right { text-align: right; }
.mt-4 { margin-top: 16px; }
.mb-4 { margin-bottom: 16px; }
.flex { display: flex; }
.flex-between { display: flex; justify-content: space-between; align-items: center; }
.gap-2 { gap: 8px; }
.hidden { display: none !important; }

/* --- Print --- */
@media print {
  .sidebar, .main-header, .filters-bar, .btn { display: none !important; }
  .main-content { margin: 0; }
  .page-content { padding: 0; }
}
"}

