 * AuthService — user authentication, session management, lockout logic.
 */

import userRepository from '../repositories/UserRepository.js';
import sessionRepository from '../repositories/SessionRepository.js';
import cryptoService from './CryptoService.js';
import auditService from './AuditService.js';
import { createUser, USER_ROLES } from '../models/User.js';
import { generateId, now } from '../utils/helpers.js';

const SESSION_KEY = 'trainingops_session';
const MAX_LOGIN_ATTEMPTS = 5;
const LOCKOUT_MINUTES = 15;

export class AuthService {
  constructor() {
    this._currentUser = null;
    this._loginAttempts = {};  // username → count
  }

  /**
   * Initialize auth — check for existing session.
   */
  async init() {
    const sessionId = localStorage.getItem(SESSION_KEY);
    if (!sessionId) return null;

    const session = await sessionRepository.getById(sessionId);
    if (!session) {
      localStorage.removeItem(SESSION_KEY);
      return null;
    }

    const user = await userRepository.getById(session.userId);
    if (!user) {
      localStorage.removeItem(SESSION_KEY);
      return null;
    }

    this._currentUser = user;
    return user;
  }

  /**
   * Login with username and password.
   */
  async login(username, password) {
    const user = await userRepository.getByUsername(username);
    if (!user) {
      return { success: false, error: 'Invalid username or password.' };
    }

    // Check lockout
    if (user.lockoutUntil && new Date(user.lockoutUntil) > new Date()) {
      const remaining = Math.ceil((new Date(user.lockoutUntil) - new Date()) / 60000);
      return { success: false, error: `Account locked. Try again in ${remaining} minutes.` };
    }

    const [hash, salt] = user.passwordHash.split(':');
    const valid = await cryptoService.verifyPassword(password, hash, salt);

    if (!valid) {
      this._loginAttempts[username] = (this._loginAttempts[username] || 0) + 1;
      if (this._loginAttempts[username] >= MAX_LOGIN_ATTEMPTS) {
        user.lockoutUntil = new Date(Date.now() + LOCKOUT_MINUTES * 60000).toISOString();
        await userRepository.put(user);
        this._loginAttempts[username] = 0;
        return { success: false, error: `Too many failed attempts. Account locked for ${LOCKOUT_MINUTES} minutes.` };
      }
      return { success: false, error: 'Invalid username or password.' };
    }

    // Clear lockout and attempts on success
    this._loginAttempts[username] = 0;
    if (user.lockoutUntil) {
      user.lockoutUntil = null;
      await userRepository.put(user);
    }

    // Create session
    const session = { id: generateId(), userId: user.id, createdAt: now() };
    await sessionRepository.add(session);
    localStorage.setItem(SESSION_KEY, session.id);

    this._currentUser = user;

    await auditService.log('user', user.id, 'login', 'User logged in', user.id);

    return { success: true, user };
  }

  /**
   * Logout current user.
   */
  async logout() {
    const sessionId = localStorage.getItem(SESSION_KEY);
    if (sessionId) {
      try { await sessionRepository.delete(sessionId); } catch (_) { /* ignore */ }
    }
    localStorage.removeItem(SESSION_KEY);

    if (this._currentUser) {
      await auditService.log('user', this._currentUser.id, 'logout', 'User logged out', this._currentUser.id);
    }

    this._currentUser = null;
  }

  /**
   * Get the currently logged-in user.
   */
  getCurrentUser() {
    return this._currentUser;
  }

  /**
   * Check if user is authenticated.
   */
  isAuthenticated() {
    return this._currentUser !== null;
  }

  /**
   * Check if current user has one of the given roles.
   */
  hasRole(...roles) {
    return this._currentUser && roles.includes(this._currentUser.role);
  }

  /**
   * Register a new user (admin action).
   */
  async registerUser(username, password, role, displayName = '') {
    const existing = await userRepository.getByUsername(username);
    if (existing) {
      return { success: false, error: 'Username already exists.' };
    }

    const validRoles = Object.values(USER_ROLES);
    if (!validRoles.includes(role)) {
      return { success: false, error: `Invalid role. Must be one of: ${validRoles.join(', ')}` };
    }

    const { hash, salt } = await cryptoService.hashPassword(password);
    const user = createUser({
      id: generateId(),
      username,
      passwordHash: `${hash}:${salt}`,
      role,
      displayName: displayName || username,
    });

    await userRepository.add(user);
    await auditService.log('user', user.id, 'created', `User ${username} created with role ${role}`, this._currentUser?.id || 'system');

    return { success: true, user };
  }

  /**
   * Seed default users if none exist.
   */
  async seedDefaultUsers() {
    const count = await userRepository.count();
    if (count > 0) return;

    const defaults = [
      { username: 'admin', password: 'admin123', role: USER_ROLES.ADMINISTRATOR, displayName: 'System Admin' },
      { username: 'reviewer', password: 'reviewer123', role: USER_ROLES.STAFF_REVIEWER, displayName: 'Staff Reviewer' },
      { username: 'instructor', password: 'instructor123', role: USER_ROLES.INSTRUCTOR, displayName: 'Instructor One' },
      { username: 'learner', password: 'learner123', role: USER_ROLES.LEARNER, displayName: 'Learner One' },
    ];

    for (const d of defaults) {
      const { hash, salt } = await cryptoService.hashPassword(d.password);
      const user = createUser({
        id: generateId(),
        username: d.username,
        passwordHash: `${hash}:${salt}`,
        role: d.role,
        displayName: d.displayName,
      });
      await userRepository.add(user);
    }
  }
}

export default new AuthService();
"}

