   * Get the currently logged-in user.
   */
  getCurrentUser() {
    return this._currentUser;
  }

  /**
   * Check if user is authenticated.
   */
  isAuthenticated() {
    return this._currentUser !== null;
  }

  /**
   * Check if current user has one of the given roles.
   */
  hasRole(...roles) {
    return this._currentUser && roles.includes(this._currentUser.role);
  }

  /**
   * Register a new user (admin action).
   */
  async registerUser(username, password, role, displayName = '') {
    const existing = await userRepository.getByUsername(username);
    if (existing) {
      return { success: false, error: 'Username already exists.' };
    }

    const validRoles = Object.values(USER_ROLES);
    if (!validRoles.includes(role)) {
      return { success: false, error: `Invalid role. Must be one of: ${validRoles.join(', ')}` };
    }

    const { hash, salt } = await cryptoService.hashPassword(password);
    const user = createUser({
      id: generateId(),
      username,
      passwordHash: `${hash}:${salt}`,
      role,
      displayName: displayName || username,
    });

    await userRepository.add(user);
    await auditService.log('user', user.id, 'created', `User ${username} created with role ${role}`, this._currentUser?.id || 'system');

    return { success: true, user };
  }

  /**
   * Seed default users if none exist.
   */
  async seedDefaultUsers() {
    const count = await userRepository.count();
    if (count > 0) return;

    const defaults = [
      { username: 'admin', password: 'admin123', role: USER_ROLES.ADMINISTRATOR, displayName: 'System Admin' },
      { username: 'reviewer', password: 'reviewer123', role: USER_ROLES.STAFF_REVIEWER, displayName: 'Staff Reviewer' },
      { username: 'instructor', password: 'instructor123', role: USER_ROLES.INSTRUCTOR, displayName: 'Instructor One' },
      { username: 'learner', password: 'learner123', role: USER_ROLES.LEARNER, displayName: 'Learner One' },
    ];

    for (const d of defaults) {
      const { hash, salt } = await cryptoService.hashPassword(d.password);
      const user = createUser({
        id: generateId(),
        username: d.username,
        passwordHash: `${hash}:${salt}`,
        role: d.role,
        displayName: d.displayName,
      });
      await userRepository.add(user);
    }
  }
}

export default new AuthService();
"}

