 * RegistrationService — registration CRUD, state machine, waitlist, audit logging.
 */

import registrationRepository from '../repositories/RegistrationRepository.js';
import registrationEventRepository from '../repositories/RegistrationEventRepository.js';
import classRepository from '../repositories/ClassRepository.js';
import auditService from './AuditService.js';
import { createRegistration, createRegistrationEvent, REGISTRATION_STATUS, canTransition } from '../models/Registration.js';
import { generateId, now } from '../utils/helpers.js';
import eventBus from '../utils/EventBus.js';

export class RegistrationService {
  /**
   * Create a new draft registration.
   */
  async create(userId, classId, notes = '') {
    const registration = createRegistration({
      id: generateId(),
      userId,
      classId,
      status: REGISTRATION_STATUS.DRAFT,
      notes,
    });
    await registrationRepository.add(registration);
    await this._logEvent(registration.id, null, REGISTRATION_STATUS.DRAFT, 'Registration created', userId);
    await auditService.log('registration', registration.id, 'created', 'Registration created in Draft', userId);
    eventBus.emit('registration:created', registration);
    return registration;
  }

  /**
   * Transition a registration to a new status.
   * @param {string} registrationId
   * @param {string} newStatus
   * @param {string} comment — required for rejection (≥20 chars)
   * @param {string} userId — who is performing the transition
   */
  async transition(registrationId, newStatus, comment, userId) {
    const reg = await registrationRepository.getById(registrationId);
    if (!reg) throw new Error('Registration not found.');

    if (!canTransition(reg.status, newStatus)) {
      throw new Error(`Cannot transition from ${reg.status} to ${newStatus}.`);
    }

    // Rejection requires ≥20 char comment
    if (newStatus === REGISTRATION_STATUS.REJECTED) {
      if (!comment || comment.trim().length < 20) {
        throw new Error('Rejection comment must be at least 20 characters.');
      }
    }

    const fromStatus = reg.status;
    reg.status = newStatus;
    reg.updatedAt = now();
    await registrationRepository.put(reg);

    await this._logEvent(reg.id, fromStatus, newStatus, comment || '', userId);
    await auditService.log('registration', reg.id, 'status_change', `${fromStatus} → ${newStatus}${comment ? ': ' + comment : ''}`, userId);

    eventBus.emit('registration:transition', { registration: reg, fromStatus, toStatus: newStatus });

    // If an approved registration is cancelled/changed, check waitlist promotion
    if (fromStatus === REGISTRATION_STATUS.APPROVED || newStatus === REGISTRATION_STATUS.CANCELLED) {
      await this._checkWaitlistPromotion(reg.classId, userId);
    }

    return reg;
  }

  /**
   * Batch transition multiple registrations.
   */
  async batchTransition(registrationIds, newStatus, comment, userId) {
    const results = [];
    for (const id of registrationIds) {
      try {
        const reg = await this.transition(id, newStatus, comment, userId);
        results.push({ id, success: true, registration: reg });
      } catch (err) {
        results.push({ id, success: false, error: err.message });
      }
    }
    return results;
  }

  /**
   * Get a registration by ID.
   */
  async getById(registrationId) {
    return registrationRepository.getById(registrationId);
  }

  /**
   * Get all registrations.
   */
  async getAll() {
    return registrationRepository.getAll();
  }

  /**
   * Get registrations by user.
   */
  async getByUserId(userId) {
    return registrationRepository.getByUserId(userId);
  }

  /**
   * Get registrations by status.
   */
  async getByStatus(status) {
    return registrationRepository.getByStatus(status);
  }

  /**
   * Get registrations by class.
   */
  async getByClassId(classId) {
    return registrationRepository.getByClassId(classId);
  }

  /**
   * Get audit timeline for a registration.
   */
  async getEvents(registrationId) {
    return registrationEventRepository.getByRegistrationId(registrationId);
  }

  /**
   * Compute fill rate for a class.
   */
  async getClassFillRate(classId) {
    const cls = await classRepository.getById(classId);
    if (!cls || !cls.capacity) return 0;

    const regs = await registrationRepository.getByClassId(classId);
    const approvedCount = regs.filter(r => r.status === REGISTRATION_STATUS.APPROVED).length;
    return approvedCount / cls.capacity;
  }

  /**
   * Check and promote waitlisted registrations for a class (FIFO).
   */
  async _checkWaitlistPromotion(classId, userId) {
    const fillRate = await this.getClassFillRate(classId);
    if (fillRate >= 0.95) return; // only promote if below 95%

    const waitlisted = await registrationRepository.filter(
      r => r.classId === classId && r.status === REGISTRATION_STATUS.WAITLISTED
    );
    if (waitlisted.length === 0) return;

    // Sort by creation date (FIFO)
    waitlisted.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));

    const next = waitlisted[0];
    await this.transition(next.id, REGISTRATION_STATUS.UNDER_REVIEW, 'Promoted from waitlist', userId);
  }

  async _logEvent(registrationId, fromStatus, toStatus, comment, userId) {
    const event = createRegistrationEvent({
      id: generateId(),
      registrationId,
      fromStatus,
      toStatus,
      comment,
      userId,
      timestamp: now(),
    });
    await registrationEventRepository.add(event);
    return event;
  }
}

export default new RegistrationService();
"}

