 * QuizService — question bank CRUD, bulk import, paper generation, auto-grading, wrong-question tracking.
 */

import questionRepository from '../repositories/QuestionRepository.js';
import quizRepository from '../repositories/QuizRepository.js';
import quizResultRepository from '../repositories/QuizResultRepository.js';
import wrongQuestionRepository from '../repositories/WrongQuestionRepository.js';
import auditService from './AuditService.js';
import { createQuestion, QUESTION_TYPES } from '../models/Question.js';
import { createQuiz, createQuizResult } from '../models/Quiz.js';
import { createWrongQuestion } from '../models/WrongQuestion.js';
import { generateId, now } from '../utils/helpers.js';
import { validateQuestionRow } from '../utils/validators.js';

export class QuizService {
  // --- Question Bank CRUD ---

  async createQuestion(data) {
    const question = createQuestion({ id: generateId(), ...data });
    await questionRepository.add(question);
    await auditService.log('question', question.id, 'created', `Question created: ${question.type}`, data.createdBy || 'system');
    return question;
  }

  async updateQuestion(id, updates) {
    const question = await questionRepository.getById(id);
    if (!question) throw new Error('Question not found.');
    Object.assign(question, updates, { updatedAt: now() });
    await questionRepository.put(question);
    return question;
  }

  async deleteQuestion(id) {
    await questionRepository.delete(id);
  }

  async getQuestionById(id) {
    return questionRepository.getById(id);
  }

  async getAllQuestions() {
    return questionRepository.getAll();
  }

  async getQuestionsByType(type) {
    return questionRepository.getByType(type);
  }

  async getQuestionsByDifficulty(difficulty) {
    return questionRepository.getByDifficulty(difficulty);
  }

  // --- Bulk Import ---

  /**
   * Validate and import questions from parsed JSON/Excel data.
   * Rejects entire batch if any row is invalid.
   * @param {Array} rows — array of { questionText, type, correctAnswer, difficulty, tags, ... }
   * @returns {{ success: boolean, errors?: string[], count?: number }}
   */
  async bulkImport(rows, createdBy = 'system') {
    const allErrors = [];
    for (let i = 0; i < rows.length; i++) {
      const errors = validateQuestionRow(rows[i], i + 1);
      allErrors.push(...errors);
    }
    if (allErrors.length > 0) {
      return { success: false, errors: allErrors };
    }

    const questions = rows.map(row => createQuestion({
      id: generateId(),
      questionText: row.questionText,
      type: row.type,
      options: row.options || [],
      correctAnswer: row.correctAnswer,
      difficulty: Number(row.difficulty),
      tags: row.tags,
      chapter: row.chapter || '',
      explanation: row.explanation || '',
    }));

    await questionRepository.bulkAdd(questions);
    await auditService.log('question', 'bulk', 'bulk_import', `Imported ${questions.length} questions`, createdBy);

    return { success: true, count: questions.length };
  }

  // --- Paper Generation ---

  /**
   * Generate a quiz paper based on rules.
   * @param {object} rules — { totalQuestions, difficultyDistribution: { 3: 0.4, 4: 0.4, 5: 0.2 }, chapterConstraints: { 'ch1': 1 } }
   */
  async generatePaper(title, classId, rules, createdBy) {
    const allQuestions = await questionRepository.getAll();
    const selected = this._selectQuestions(allQuestions, rules);

    const quiz = createQuiz({
      id: generateId(),
      title,
      classId,
      questionIds: selected.map(q => q.id),
      rules,
      createdBy,
    });

    await quizRepository.add(quiz);
    await auditService.log('quiz', quiz.id, 'created', `Paper generated: ${title}`, createdBy);
    return quiz;
  }

  _selectQuestions(allQuestions, rules) {
    const total = rules.totalQuestions || 30;
    const distribution = rules.difficultyDistribution || {};
    const chapterMin = rules.chapterConstraints || {};

    // Calculate counts per difficulty level
    const difficultyCounts = {};
    let allocated = 0;
    const difficulties = Object.keys(distribution).map(Number).sort();

    for (const d of difficulties) {
      difficultyCounts[d] = Math.floor(total * distribution[d]);
      allocated += difficultyCounts[d];
    }
    // Distribute remainder to highest difficulty
    if (allocated < total && difficulties.length > 0) {
      difficultyCounts[difficulties[difficulties.length - 1]] += total - allocated;
    }

    // Group questions by difficulty
    const byDifficulty = {};
    for (const q of allQuestions) {
      if (!byDifficulty[q.difficulty]) byDifficulty[q.difficulty] = [];
      byDifficulty[q.difficulty].push(q);
    }

    // Shuffle each group
    for (const d of Object.keys(byDifficulty)) {
      byDifficulty[d] = this._shuffle(byDifficulty[d]);
    }

    const selected = [];
    const usedIds = new Set();

    // Satisfy chapter constraints first
    for (const [chapter, minCount] of Object.entries(chapterMin)) {
      const chapterQs = allQuestions.filter(q => q.chapter === chapter && !usedIds.has(q.id));
      for (let i = 0; i < Math.min(minCount, chapterQs.length); i++) {
        selected.push(chapterQs[i]);
        usedIds.add(chapterQs[i].id);
      }
    }

    // Fill by difficulty
    for (const [d, count] of Object.entries(difficultyCounts)) {
      const pool = (byDifficulty[d] || []).filter(q => !usedIds.has(q.id));
      const needed = count - selected.filter(q => q.difficulty === Number(d)).length;
      for (let i = 0; i < Math.min(needed, pool.length); i++) {
        selected.push(pool[i]);
        usedIds.add(pool[i].id);
      }
    }

    return selected.slice(0, total);
  }

  _shuffle(arr) {
    const a = [...arr];
    for (let i = a.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [a[i], a[j]] = [a[j], a[i]];
    }
    return a;
  }

  // --- Answer Evaluation ---

  /**
   * Submit answers for a quiz and auto-grade objective items.
   */
  async submitAnswers(quizId, userId, answers) {
    const quiz = await quizRepository.getById(quizId);
    if (!quiz) throw new Error('Quiz not found.');

    const gradedAnswers = [];
    let objectiveCorrect = 0;
    let objectiveTotal = 0;

    for (const ans of answers) {
      const question = await questionRepository.getById(ans.questionId);
      if (!question) continue;

      const graded = { questionId: ans.questionId, answer: ans.answer, autoGraded: false, isCorrect: null };

      if (question.type === QUESTION_TYPES.SUBJECTIVE) {
        graded.autoGraded = false;
      } else {
        graded.autoGraded = true;
        objectiveTotal++;
        if (question.type === QUESTION_TYPES.MULTIPLE) {
          const correct = Array.isArray(question.correctAnswer) ? question.correctAnswer.sort() : [];
          const given = Array.isArray(ans.answer) ? ans.answer.sort() : [];
          graded.isCorrect = JSON.stringify(correct) === JSON.stringify(given);
        } else {
          graded.isCorrect = String(ans.answer).trim().toLowerCase() === String(question.correctAnswer).trim().toLowerCase();
        }
        if (graded.isCorrect) objectiveCorrect++;

        // Track wrong questions
        if (!graded.isCorrect) {
          await this._addWrongQuestion(userId, question, ans.answer, quizId);
        }
      }

      gradedAnswers.push(graded);
    }

    const result = createQuizResult({
      id: generateId(),
      quizId,
      userId,
      answers: gradedAnswers,
      objectiveScore: objectiveTotal > 0 ? Math.round((objectiveCorrect / objectiveTotal) * 100) : null,
    });

    await quizResultRepository.add(result);
    return result;
  }

  /**
   * Get quiz results for a user.
   */
  async getResultsByUserId(userId) {
    return quizResultRepository.getByUserId(userId);
  }

  /**
   * Get quiz results for a quiz.
   */
  async getResultsByQuizId(quizId) {
    return quizResultRepository.getByQuizId(quizId);
  }

  /**
   * Get wrong-question notebook for a user.
   */
  async getWrongQuestions(userId) {
    return wrongQuestionRepository.getByUserId(userId);
  }

  async _addWrongQuestion(userId, question, userAnswer, quizId) {
    const entry = createWrongQuestion({
      id: generateId(),
      userId,
      questionId: question.id,
      userAnswer: JSON.stringify(userAnswer),
      correctAnswer: JSON.stringify(question.correctAnswer),
      explanation: question.explanation,
      quizId,
    });
    await wrongQuestionRepository.add(entry);
  }
}

export default new QuizService();
"}

