 * ModerationService — sensitive-word filtering, abuse reports, resolution tracking.
 */

import reportRepository from '../repositories/ReportRepository.js';
import auditService from './AuditService.js';
import { createReport, REPORT_STATUS, REPORT_OUTCOMES } from '../models/Report.js';
import { generateId, now } from '../utils/helpers.js';

const RESOLUTION_DEADLINE_DAYS = 7;

// Loaded once at init
let sensitiveWords = [];

export class ModerationService {
  /**
   * Load the sensitive word dictionary.
   */
  async loadSensitiveWords() {
    try {
      const response = await fetch('../src/config/sensitiveWords.json');
      const data = await response.json();
      sensitiveWords = (data.words || []).map(w => w.toLowerCase());
    } catch (e) {
      console.warn('Could not load sensitive words config, using empty list.');
      sensitiveWords = [];
    }
  }

  /**
   * Check text for sensitive words. Returns flagged words.
   */
  checkContent(text) {
    if (!text) return { flagged: false, words: [] };
    const lower = text.toLowerCase();
    const found = sensitiveWords.filter(w => lower.includes(w));
    return { flagged: found.length > 0, words: found };
  }

  /**
   * Submit an abuse report.
   */
  async submitReport(reporterId, targetId, targetType, reason) {
    const report = createReport({
      id: generateId(),
      reporterId,
      targetId,
      targetType,
      reason,
    });
    await reportRepository.add(report);
    await auditService.log('report', report.id, 'created', `Abuse report filed against ${targetType}:${targetId}`, reporterId);
    return report;
  }

  /**
   * Resolve a report with an outcome.
   * @param {string} reportId
   * @param {string} outcome — 'dismissed', 'removed', 'warned'
   * @param {string} resolvedBy — reviewer user ID
   */
  async resolveReport(reportId, outcome, resolvedBy) {
    const report = await reportRepository.getById(reportId);
    if (!report) throw new Error('Report not found.');

    const validOutcomes = Object.values(REPORT_OUTCOMES);
    if (!validOutcomes.includes(outcome)) {
      throw new Error(`Outcome must be one of: ${validOutcomes.join(', ')}`);
    }

    report.status = REPORT_STATUS.RESOLVED;
    report.resolution = outcome;
    report.resolvedBy = resolvedBy;
    report.resolvedAt = now();
    await reportRepository.put(report);

    await auditService.log('report', report.id, 'resolved', `Report resolved: ${outcome}`, resolvedBy);
    return report;
  }

  /**
   * Get all open/pending reports.
   */
  async getOpenReports() {
    const open = await reportRepository.getByStatus(REPORT_STATUS.OPEN);
    const underReview = await reportRepository.getByStatus(REPORT_STATUS.UNDER_REVIEW);
    return [...open, ...underReview];
  }

  /**
   * Get overdue reports (open > 7 days).
   */
  async getOverdueReports() {
    const open = await this.getOpenReports();
    const cutoff = Date.now() - RESOLUTION_DEADLINE_DAYS * 24 * 60 * 60 * 1000;
    return open.filter(r => new Date(r.createdAt).getTime() < cutoff);
  }

  /**
   * Get all reports.
   */
  async getAllReports() {
    return reportRepository.getAll();
  }

  async getReportById(reportId) {
    return reportRepository.getById(reportId);
  }
}

export default new ModerationService();
