 * ContractService — template management, placeholder substitution, versioning,
 * signature handling, signing workflow states, PDF-like print export.
 */

import contractRepository from '../repositories/ContractRepository.js';
import templateRepository from '../repositories/TemplateRepository.js';
import auditService from './AuditService.js';
import cryptoService from './CryptoService.js';
import { createContract, createTemplate, CONTRACT_STATUS, CONTRACT_TRANSITIONS } from '../models/Contract.js';
import { generateId, now, downloadBlob } from '../utils/helpers.js';

export class ContractService {
  // --- Template Management ---

  async createTemplate(data) {
    // Extract placeholders from content
    const placeholders = (data.content.match(/\{[^}]+\}/g) || []);

    const template = createTemplate({
      id: generateId(),
      name: data.name,
      content: data.content,
      placeholders,
      active: true,
      version: 1,
      effectiveDate: data.effectiveDate || now(),
    });

    await templateRepository.add(template);
    await auditService.log('template', template.id, 'created', `Template "${data.name}" v1 created`, data.createdBy || 'system');
    return template;
  }

  async updateTemplate(templateId, updates, updatedBy) {
    const existing = await templateRepository.getById(templateId);
    if (!existing) throw new Error('Template not found.');

    // Deactivate old version
    existing.active = false;
    existing.updatedAt = now();
    await templateRepository.put(existing);

    // Create new version
    const newVersion = createTemplate({
      id: generateId(),
      name: updates.name || existing.name,
      content: updates.content || existing.content,
      placeholders: (updates.content || existing.content).match(/\{[^}]+\}/g) || [],
      active: true,
      version: existing.version + 1,
      effectiveDate: updates.effectiveDate || now(),
    });

    await templateRepository.add(newVersion);
    await auditService.log('template', newVersion.id, 'versioned', `Template "${newVersion.name}" v${newVersion.version}`, updatedBy);
    return newVersion;
  }

  async getActiveTemplates() {
    return templateRepository.getActive();
  }

  async getTemplateById(templateId) {
    return templateRepository.getById(templateId);
  }

  async getAllTemplates() {
    return templateRepository.getAll();
  }

  // --- Contract Generation ---

  /**
   * Generate a contract from a template with variable substitution.
   */
  async generateContract(templateId, variables, createdBy) {
    const template = await templateRepository.getById(templateId);
    if (!template) throw new Error('Template not found.');

    let content = template.content;
    for (const [key, value] of Object.entries(variables)) {
      content = content.replace(new RegExp(`\\{${key}\\}`, 'g'), value);
    }

    const contract = createContract({
      id: generateId(),
      templateId,
      templateVersion: template.version,
      content,
      status: CONTRACT_STATUS.INITIATED,
      createdBy,
    });

    await contractRepository.add(contract);
    await auditService.log('contract', contract.id, 'created', 'Contract generated from template', createdBy);
    return contract;
  }

  // --- Signing Workflow ---

  /**
   * Transition a contract's signing status.
   */
  async transitionStatus(contractId, newStatus, userId) {
    const contract = await contractRepository.getById(contractId);
    if (!contract) throw new Error('Contract not found.');

    const allowed = CONTRACT_TRANSITIONS[contract.status] || [];
    if (!allowed.includes(newStatus)) {
      throw new Error(`Cannot transition contract from ${contract.status} to ${newStatus}.`);
    }

    contract.status = newStatus;
    contract.updatedAt = now();
    await contractRepository.put(contract);

    await auditService.log('contract', contractId, 'status_change', `${contract.status} → ${newStatus}`, userId);
    return contract;
  }

  /**
   * Sign a contract — attach typed name or canvas signature + SHA-256 hash.
   */
  async signContract(contractId, signatureData, signerName, userId) {
    const contract = await contractRepository.getById(contractId);
    if (!contract) throw new Error('Contract not found.');

    if (contract.status !== CONTRACT_STATUS.INITIATED) {
      throw new Error('Contract can only be signed when in initiated status.');
    }

    const timestamp = now();
    const hash = await cryptoService.generateSignatureHash(contract.content, signerName, timestamp);

    contract.signatureData = signatureData; // base64 canvas or typed name
    contract.signatureHash = hash;
    contract.signedBy = userId;
    contract.signedAt = timestamp;
    contract.status = CONTRACT_STATUS.SIGNED;
    contract.updatedAt = timestamp;

    await contractRepository.put(contract);
    await auditService.log('contract', contractId, 'signed', `Signed by ${signerName}, hash: ${hash.substring(0, 16)}...`, userId);
    return contract;
  }

  /**
   * Withdraw a contract.
   */
  async withdrawContract(contractId, userId) {
    return this.transitionStatus(contractId, CONTRACT_STATUS.WITHDRAWN, userId);
  }

  /**
   * Void a contract.
   */
  async voidContract(contractId, userId) {
    return this.transitionStatus(contractId, CONTRACT_STATUS.VOIDED, userId);
  }

  // --- Export ---

  /**
   * Export contract to a printable HTML blob for PDF-like output.
   */
  exportToPrintableHTML(contract) {
    const html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"><title>Contract ${contract.id}</title>
<style>
  body { font-family: serif; max-width: 800px; margin: 40px auto; padding: 20px; line-height: 1.6; }
  h1 { text-align: center; border-bottom: 2px solid #333; padding-bottom: 10px; }
  .sig-block { margin-top: 40px; border-top: 1px solid #999; padding-top: 10px; }
  .hash { font-size: 0.7em; color: #666; word-break: break-all; }
  @media print { body { margin: 0; } }
</style></head><body>
<h1>Training Contract</h1>
<div class="content">${contract.content.replace(/\n/g, '<br>')}</div>
${contract.signedBy ? `
<div class="sig-block">
  <p><strong>Signed by:</strong> ${contract.signedBy}</p>
  <p><strong>Date:</strong> ${contract.signedAt}</p>
  <p class="hash"><strong>Integrity Hash:</strong> ${contract.signatureHash}</p>
</div>` : ''}
</body></html>`;
    return new Blob([html], { type: 'text/html' });
  }

  /**
   * Trigger download of a printable contract.
   */
  downloadContract(contract) {
    const blob = this.exportToPrintableHTML(contract);
    downloadBlob(blob, `contract-${contract.id}.html`);
  }

  async getContractById(contractId) {
    return contractRepository.getById(contractId);
  }

  async getAllContracts() {
    return contractRepository.getAll();
  }

  async getContractsByStatus(status) {
    return contractRepository.getByStatus(status);
  }
}

export default new ContractService();
"}

