 * RatingService — two-way ratings with tag-based feedback and appeal flow.
 */

import ratingRepository from '../repositories/RatingRepository.js';
import appealRepository from '../repositories/AppealRepository.js';
import auditService from './AuditService.js';
import { createRating, createAppeal, APPEAL_STATUS } from '../models/Rating.js';
import { generateId, now } from '../utils/helpers.js';

export class RatingService {
  /**
   * Submit a two-way rating.
   */
  async submitRating({ fromUserId, toUserId, classId, score, tags, comment }) {
    if (!Number.isInteger(score) || score < 1 || score > 5) {
      throw new Error('Score must be between 1 and 5.');
    }

    const rating = createRating({
      id: generateId(),
      fromUserId,
      toUserId,
      classId,
      score,
      tags: tags || [],
      comment: comment || '',
    });

    await ratingRepository.add(rating);
    await auditService.log('rating', rating.id, 'created', `Rating ${score}/5 from ${fromUserId} to ${toUserId}`, fromUserId);
    return rating;
  }

  /**
   * File an appeal on a rating.
   */
  async fileAppeal(ratingId, appealerId, reason) {
    const rating = await ratingRepository.getById(ratingId);
    if (!rating) throw new Error('Rating not found.');

    const existingAppeals = await appealRepository.getByRatingId(ratingId);
    const pending = existingAppeals.find(a => a.status === APPEAL_STATUS.PENDING);
    if (pending) throw new Error('An appeal is already pending for this rating.');

    const appeal = createAppeal({
      id: generateId(),
      ratingId,
      appealerId,
      reason,
    });

    await appealRepository.add(appeal);
    await auditService.log('appeal', appeal.id, 'filed', `Appeal filed for rating ${ratingId}`, appealerId);
    return appeal;
  }

  /**
   * Resolve an appeal (reviewer decision: uphold, adjust, void).
   */
  async resolveAppeal(appealId, decision, rationale, reviewerId, adjustedScore = null) {
    const appeal = await appealRepository.getById(appealId);
    if (!appeal) throw new Error('Appeal not found.');

    if (!rationale || rationale.trim().length === 0) {
      throw new Error('Written rationale is required.');
    }

    const validDecisions = [APPEAL_STATUS.UPHELD, APPEAL_STATUS.ADJUSTED, APPEAL_STATUS.VOIDED];
    if (!validDecisions.includes(decision)) {
      throw new Error(`Decision must be one of: ${validDecisions.join(', ')}`);
    }

    if (decision === APPEAL_STATUS.ADJUSTED && (adjustedScore === null || adjustedScore < 1 || adjustedScore > 5)) {
      throw new Error('Adjusted score must be between 1 and 5.');
    }

    appeal.status = decision;
    appeal.decision = decision;
    appeal.rationale = rationale;
    appeal.reviewerId = reviewerId;
    appeal.adjustedScore = adjustedScore;
    appeal.resolvedAt = now();

    await appealRepository.put(appeal);

    // If adjusted, update the original rating
    if (decision === APPEAL_STATUS.ADJUSTED) {
      const rating = await ratingRepository.getById(appeal.ratingId);
      if (rating) {
        rating.score = adjustedScore;
        await ratingRepository.put(rating);
      }
    }

    // If voided, we could mark the rating as void — for now just log it
    await auditService.log('appeal', appealId, 'resolved', `Decision: ${decision}, rationale: ${rationale}`, reviewerId);
    return appeal;
  }

  async getRatingById(ratingId) {
    return ratingRepository.getById(ratingId);
  }

  async getRatingsForUser(toUserId) {
    return ratingRepository.getByToUserId(toUserId);
  }

  async getRatingsByUser(fromUserId) {
    return ratingRepository.getByFromUserId(fromUserId);
  }

  async getAllRatings() {
    return ratingRepository.getAll();
  }

  async getPendingAppeals() {
    return appealRepository.getByStatus(APPEAL_STATUS.PENDING);
  }

  async getAppealsByRatingId(ratingId) {
    return appealRepository.getByRatingId(ratingId);
  }

  async getAllAppeals() {
    return appealRepository.getAll();
  }
}

export default new RatingService();
"}

