 * SchedulerService — periodic checks for moderation deadlines, cleanup, etc.
 */

import moderationService from './ModerationService.js';
import notificationService from './NotificationService.js';

export class SchedulerService {
  constructor() {
    this._intervals = [];
  }

  /**
   * Start all scheduled tasks.
   */
  start() {
    // Check for overdue moderation reports every 30 minutes
    this._intervals.push(
      setInterval(() => this._checkOverdueReports(), 30 * 60 * 1000)
    );

    // Run an initial check immediately
    this._checkOverdueReports();
  }

  /**
   * Stop all scheduled tasks.
   */
  stop() {
    for (const id of this._intervals) {
      clearInterval(id);
    }
    this._intervals = [];
  }

  /**
   * Check for overdue abuse reports and notify.
   */
  async _checkOverdueReports() {
    try {
      const overdue = await moderationService.getOverdueReports();
      for (const report of overdue) {
        // Only notify if not already notified (basic dedup via report status)
        if (report.status === 'open') {
          await notificationService.notify(
            'system',
            'Overdue Report',
            `Abuse report ${report.id} is overdue for resolution.`,
            'warning',
            '#/reviews'
          );
        }
      }
    } catch (err) {
      console.error('Scheduler: overdue report check failed', err);
    }
  }
}

export default new SchedulerService();
"}

