 * app.js — Application entry point.
 * Initializes database, seeds data, sets up routing, and boots the app shell.
 */

import { openDatabase } from './store/Database.js';
import { Router } from './router/Router.js';
import { AppShell } from './components/AppShell.js';
import authService from './services/AuthService.js';
import moderationService from './services/ModerationService.js';
import schedulerService from './services/SchedulerService.js';

import { LoginPage } from './pages/LoginPage.js';
import { DashboardPage } from './pages/DashboardPage.js';
import { RegistrationsPage } from './pages/RegistrationsPage.js';
import { QuizPage } from './pages/QuizPage.js';
import { ReviewsPage } from './pages/ReviewsPage.js';
import { ContractsPage } from './pages/ContractsPage.js';
import { AdminPage } from './pages/AdminPage.js';

const appEl = document.getElementById('app');

async function boot() {
  try {
    // 1. Open IndexedDB
    await openDatabase();

    // 2. Seed default users if empty
    await authService.seedDefaultUsers();

    // 3. Load config
    await moderationService.loadSensitiveWords();

    // 4. Check existing session
    await authService.init();

    // 5. Setup router
    const router = new Router();
    const appShell = new AppShell(router);

    // Page instances (lazy-ish — created once)
    const loginPage = new LoginPage(router);
    const dashboardPage = new DashboardPage(appShell);
    const registrationsPage = new RegistrationsPage(appShell);
    const quizPage = new QuizPage(appShell);
    const reviewsPage = new ReviewsPage(appShell);
    const contractsPage = new ContractsPage(appShell);
    const adminPage = new AdminPage(appShell);

    // Helper: ensure shell is rendered, then call page render
    const renderPage = async (page) => {
      if (!document.querySelector('.app-shell')) {
        appShell.render(appEl);
      }
      await page.render();
    };

    // Route guard: redirect to login if not authenticated
    router.beforeEach((to) => {
      if (to.path !== '/login' && !authService.isAuthenticated()) {
        router.navigate('/login');
        return false;
      }
      if (to.path === '/login' && authService.isAuthenticated()) {
        router.navigate('/dashboard');
        return false;
      }
      return true;
    });

    // Register routes
    router.route('/login', async () => {
      appEl.innerHTML = '';
      await loginPage.render(appEl);
    });

    router.route('/dashboard', () => renderPage(dashboardPage));
    router.route('/registrations', () => renderPage(registrationsPage));
    router.route('/quiz', () => renderPage(quizPage));
    router.route('/reviews', () => renderPage(reviewsPage));
    router.route('/contracts', () => renderPage(contractsPage));
    router.route('/admin', () => renderPage(adminPage));

    router.notFound(() => {
      if (authService.isAuthenticated()) {
        router.navigate('/dashboard');
      } else {
        router.navigate('/login');
      }
    });

    // Highlight active nav link on navigation
    router.onNavigate(({ path }) => {
      document.querySelectorAll('.sidebar-nav a').forEach(a => {
        const href = a.getAttribute('href')?.replace('#', '');
        a.classList.toggle('active', href === path);
      });
    });

    // 6. Start scheduler
    schedulerService.start();

    // 7. Start router
    router.start();
  } catch (err) {
    console.error('Boot failed:', err);
    appEl.innerHTML = `<div class="loading-screen" style="color:var(--color-danger)">
      <div>
        <p>Failed to start application.</p>
        <p style="font-size:0.85rem;margin-top:8px">${err.message}</p>
      </div>
    </div>`;
  }
}

boot();
"}

