3	 */
4	
5	import registrationService from '../services/RegistrationService.js';
6	import authService from '../services/AuthService.js';
7	import auditService from '../services/AuditService.js';
8	import DataTable from '../components/DataTable.js';
9	import Drawer from '../components/Drawer.js';
10	import AuditTimeline from '../components/AuditTimeline.js';
11	import Toast from '../components/Toast.js';
12	import { REGISTRATION_STATUS } from '../models/Registration.js';
13	import { escapeHtml, formatDate } from '../utils/helpers.js';
14	
15	export class RegistrationsPage {
16	  constructor(appShell) {
17	    this.appShell = appShell;
18	    this.table = null;
19	    this.currentFilter = '';
20	  }
21	
22	  async render() {
23	    this.appShell.setPageTitle('Registrations');
24	    const container = this.appShell.getContentContainer();
25	
26	    const statusOptions = Object.values(REGISTRATION_STATUS).map(s =>
27	      `<option value="${s}">${s}</option>`
28	    ).join('');
29	
30	    container.innerHTML = `
31	      <div class="filters-bar">
32	        <select id="filter-status" class="form-control">
33	          <option value="">All Statuses</option>
34	          ${statusOptions}
35	        </select>
36	        <button class="btn btn-primary" id="btn-new-reg">+ New Registration</button>
37	        <button class="btn btn-secondary" id="btn-batch-approve">Batch Approve</button>
38	        <button class="btn btn-danger btn-sm" id="btn-batch-reject">Batch Reject</button>
39	      </div>
40	      <div id="registrations-table"></div>
41	    `;
42	
43	    await this._loadTable(container);
44	
45	    // Filter
46	    container.querySelector('#filter-status').addEventListener('change', async (e) => {
47	      this.currentFilter = e.target.value;
48	      await this._loadTable(container);
49	    });
50	
51	    // New registration
52	    container.querySelector('#btn-new-reg').addEventListener('click', () => {
53	      this._createRegistration();
54	    });
55	
56	    // Batch approve
57	    container.querySelector('#btn-batch-approve').addEventListener('click', async () => {
58	      const ids = this.table.getSelectedIds();
59	      if (ids.length === 0) { Toast.warning('Select registrations first.'); return; }
60	      const user = authService.getCurrentUser();
61	      const results = await registrationService.batchTransition(ids, REGISTRATION_STATUS.APPROVED, '', user.id);
62	      const succeeded = results.filter(r => r.success).length;
63	      Toast.success(`${succeeded} of ${ids.length} approved.`);
64	      await this._loadTable(container);
65	    });
66	
67	    // Batch reject
68	    container.querySelector('#btn-batch-reject').addEventListener('click', async () => {
69	      const ids = this.table.getSelectedIds();
70	      if (ids.length === 0) { Toast.warning('Select registrations first.'); return; }
71	      Toast.warning('Batch rejection requires individual comments of 20+ chars.');
72	    });
73	  }
74	
75	  async _loadTable(container) {
76	    let data;
77	    if (this.currentFilter) {
78	      data = await registrationService.getByStatus(this.currentFilter);
79	    } else {
80	      data = await registrationService.getAll();
81	    }
82	
83	    // Sort newest first
84	    data.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
85	
86	    this.table = new DataTable({
87	      columns: [
88	        { key: 'id', label: 'ID', render: (r) => escapeHtml(r.id.substring(0, 8)) + '...' },
89	        { key: 'userId', label: 'User', render: (r) => escapeHtml(r.userId.substring(0, 8)) + '...' },
90	        { key: 'status', label: 'Status', render: (r) => `<span class="badge badge-${r.status.toLowerCase()}">${escapeHtml(r.status)}</span>` },
91	        { key: 'createdAt', label: 'Created', render: (r) => formatDate(r.createdAt) },
92	        { key: 'updatedAt', label: 'Updated', render: (r) => formatDate(r.updatedAt) },
93	      ],
94	      data,
95	      selectable: true,
96	      onRowClick: (row) => this._openDetail(row),
97	    });
98	
99	    this.table.render(container.querySelector('#registrations-table'));
100	  }
101	
102	  async _openDetail(registration) {
103	    const events = await registrationService.getEvents(registration.id);
104	    const auditLogs = await auditService.getTimeline(registration.id);
105	
106	    Drawer.open('Registration Detail', `
107	      <div class="form-group">
108	        <label>ID</label>
109	        <p>${escapeHtml(registration.id)}</p>
110	      </div>
111	      <div class="form-group">
112	        <label>Status</label>
113	        <p><span class="badge badge-${registration.status.toLowerCase()}">${escapeHtml(registration.status)}</span></p>
114	      </div>
115	      <div class="form-group">
116	        <label>Notes</label>
117	        <p>${escapeHtml(registration.notes || 'None')}</p>
118	      </div>
119	      <div class="form-group">
120	        <label>Created</label>
121	        <p>${formatDate(registration.createdAt)}</p>
122	      </div>
123	      <hr style="margin:16px 0;border:none;border-top:1px solid var(--color-border)">
124	      <h3 style="margin-bottom:12px">Audit Timeline</h3>
125	      <div id="drawer-audit-timeline"></div>
126	    `, (drawerEl) => {
127	      AuditTimeline.render(drawerEl.querySelector('#drawer-audit-timeline'), auditLogs);
128	    });
129	  }
130	
131	  async _createRegistration() {
132	    const user = authService.getCurrentUser();
133	    if (!user) return;
134	    try {
135	      const reg = await registrationService.create(user.id, '', '');
136	      Toast.success('Draft registration created.');
137	      const container = this.appShell.getContentContainer();
138	      await this._loadTable(container);
139	    } catch (err) {
140	      Toast.error(err.message);
141	    }
142	  }
143	}
