1	/**
2	 * RegistrationService — registration CRUD, state machine, waitlist, audit logging.
3	 */
4	
5	import registrationRepository from '../repositories/RegistrationRepository.js';
6	import registrationEventRepository from '../repositories/RegistrationEventRepository.js';
7	import classRepository from '../repositories/ClassRepository.js';
8	import auditService from './AuditService.js';
9	import { createRegistration, createRegistrationEvent, REGISTRATION_STATUS, canTransition } from '../models/Registration.js';
10	import { generateId, now } from '../utils/helpers.js';
11	import eventBus from '../utils/EventBus.js';
12	
13	export class RegistrationService {
14	  /**
15	   * Create a new draft registration.
16	   */
17	  async create(userId, classId, notes = '') {
18	    const registration = createRegistration({
19	      id: generateId(),
20	      userId,
21	      classId,
22	      status: REGISTRATION_STATUS.DRAFT,
23	      notes,
24	    });
25	    await registrationRepository.add(registration);
26	    await this._logEvent(registration.id, null, REGISTRATION_STATUS.DRAFT, 'Registration created', userId);
27	    await auditService.log('registration', registration.id, 'created', 'Registration created in Draft', userId);
28	    eventBus.emit('registration:created', registration);
29	    return registration;
30	  }
31	
32	  /**
33	   * Transition a registration to a new status.
34	   * @param {string} registrationId
35	   * @param {string} newStatus
36	   * @param {string} comment — required for rejection (≥20 chars)
37	   * @param {string} userId — who is performing the transition
38	   */
39	  async transition(registrationId, newStatus, comment, userId) {
40	    const reg = await registrationRepository.getById(registrationId);
41	    if (!reg) throw new Error('Registration not found.');
42	
43	    if (!canTransition(reg.status, newStatus)) {
44	      throw new Error(`Cannot transition from ${reg.status} to ${newStatus}.`);
45	    }
46	
47	    // Rejection requires ≥20 char comment
48	    if (newStatus === REGISTRATION_STATUS.REJECTED) {
49	      if (!comment || comment.trim().length < 20) {
50	        throw new Error('Rejection comment must be at least 20 characters.');
51	      }
52	    }
53	
54	    const fromStatus = reg.status;
55	    reg.status = newStatus;
56	    reg.updatedAt = now();
57	    await registrationRepository.put(reg);
58	
59	    await this._logEvent(reg.id, fromStatus, newStatus, comment || '', userId);
60	    await auditService.log('registration', reg.id, 'status_change', `${fromStatus} → ${newStatus}${comment ? ': ' + comment : ''}`, userId);
61	
62	    eventBus.emit('registration:transition', { registration: reg, fromStatus, toStatus: newStatus });
63	
64	    // If an approved registration is cancelled/changed, check waitlist promotion
65	    if (fromStatus === REGISTRATION_STATUS.APPROVED || newStatus === REGISTRATION_STATUS.CANCELLED) {
66	      await this._checkWaitlistPromotion(reg.classId, userId);
67	    }
68	
69	    return reg;
70	  }
71	
72	  /**
73	   * Batch transition multiple registrations.
74	   */
75	  async batchTransition(registrationIds, newStatus, comment, userId) {
76	    const results = [];
77	    for (const id of registrationIds) {
78	      try {
79	        const reg = await this.transition(id, newStatus, comment, userId);
80	        results.push({ id, success: true, registration: reg });
81	      } catch (err) {
82	        results.push({ id, success: false, error: err.message });
83	      }
84	    }
85	    return results;
86	  }
87	
88	  /**
89	   * Get a registration by ID.
90	   */
91	  async getById(registrationId) {
92	    return registrationRepository.getById(registrationId);
93	  }
94	
95	  /**
96	   * Get all registrations.
97	   */
98	  async getAll() {
99	    return registrationRepository.getAll();
100	  }
101	
102	  /**
103	   * Get registrations by user.
104	   */
105	  async getByUserId(userId) {
106	    return registrationRepository.getByUserId(userId);
107	  }
108	
109	  /**
110	   * Get registrations by status.
111	   */
112	  async getByStatus(status) {
113	    return registrationRepository.getByStatus(status);
114	  }
115	
116	  /**
117	   * Get registrations by class.
118	   */
119	  async getByClassId(classId) {
120	    return registrationRepository.getByClassId(classId);
121	  }
122	
123	  /**
124	   * Get audit timeline for a registration.
125	   */
126	  async getEvents(registrationId) {
127	    return registrationEventRepository.getByRegistrationId(registrationId);
128	  }
129	
130	  /**
131	   * Compute fill rate for a class.
132	   */
133	  async getClassFillRate(classId) {
134	    const cls = await classRepository.getById(classId);
135	    if (!cls || !cls.capacity) return 0;
136	
137	    const regs = await registrationRepository.getByClassId(classId);
138	    const approvedCount = regs.filter(r => r.status === REGISTRATION_STATUS.APPROVED).length;
139	    return approvedCount / cls.capacity;
140	  }
141	
142	  /**
143	   * Check and promote waitlisted registrations for a class (FIFO).
144	   */
145	  async _checkWaitlistPromotion(classId, userId) {
146	    const fillRate = await this.getClassFillRate(classId);
147	    if (fillRate >= 0.95) return; // only promote if below 95%
148	
149	    const waitlisted = await registrationRepository.filter(
150	      r => r.classId === classId && r.status === REGISTRATION_STATUS.WAITLISTED
151	    );
152	    if (waitlisted.length === 0) return;
153	
154	    // Sort by creation date (FIFO)
155	    waitlisted.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
156	
157	    const next = waitlisted[0];
158	    await this.transition(next.id, REGISTRATION_STATUS.UNDER_REVIEW, 'Promoted from waitlist', userId);
159	  }
160	
161	  async _logEvent(registrationId, fromStatus, toStatus, comment, userId) {
162	    const event = createRegistrationEvent({
163	      id: generateId(),
164	      registrationId,
165	      fromStatus,
166	      toStatus,
167	      comment,
168	      userId,
169	      timestamp: now(),
170	    });
171	    await registrationEventRepository.add(event);
172	    return event;
173	  }
174	}
175	
176	export default new RegistrationService();
177

1	/**
2	 * ReviewService — review CRUD, follow-up logic, two-way reviews, tag-based feedback.
3	 */
4	
5	import reviewRepository from '../repositories/ReviewRepository.js';
6	import auditService from './AuditService.js';
7	import { createReview } from '../models/Review.js';
8	import { generateId, now } from '../utils/helpers.js';
9	
10	const MAX_IMAGES = 6;
11	const MAX_IMAGE_SIZE_MB = 2;
12	const MAX_TEXT_LENGTH = 2000;
13	const FOLLOW_UP_WINDOW_DAYS = 14;
14	
15	export class ReviewService {
16	  /**
17	   * Submit a new review.
18	   */
19	  async submitReview({ userId, targetUserId, targetClassId, direction, rating, text, images, tags }) {
20	    // Validate rating
21	    if (!Number.isInteger(rating) || rating < 1 || rating > 5) {
22	      throw new Error('Rating must be between 1 and 5.');
23	    }
24	
25	    // Validate text length
26	    if (text && text.length > MAX_TEXT_LENGTH) {
27	      throw new Error(`Review text must be at most ${MAX_TEXT_LENGTH} characters.`);
28	    }
29	
30	    // Validate images
31	    if (images && images.length > MAX_IMAGES) {
32	      throw new Error(`Maximum ${MAX_IMAGES} images allowed.`);
33	    }
34	    if (images) {
35	      for (const img of images) {
36	        if (img.size > MAX_IMAGE_SIZE_MB * 1024 * 1024) {
37	          throw new Error(`Each image must be under ${MAX_IMAGE_SIZE_MB}MB.`);
38	        }
39	      }
40	    }
41	
42	    const review = createReview({
43	      id: generateId(),
44	      userId,
45	      targetUserId,
46	      targetClassId,
47	      direction,
48	      rating,
49	      text: text || '',
50	      images: images || [],
51	      tags: tags || [],
52	    });
53	
54	    await reviewRepository.add(review);
55	    await auditService.log('review', review.id, 'created', `Review submitted: ${rating} stars`, userId);
56	    return review;
57	  }
58	
59	  /**
60	   * Submit a follow-up review (max 1 per original, within 14 days).
61	   */
62	  async submitFollowUp(originalReviewId, { text, rating, images, tags }, userId) {
63	    const original = await reviewRepository.getById(originalReviewId);
64	    if (!original) throw new Error('Original review not found.');
65	    if (original.userId !== userId) throw new Error('Only the original reviewer can follow up.');
66	
67	    // Check if follow-up already exists
68	    const allReviews = await reviewRepository.getByUserId(userId);
69	    const existingFollowUp = allReviews.find(r => r.followUpOf === originalReviewId);
70	    if (existingFollowUp) {
71	      throw new Error('A follow-up review has already been submitted.');
72	    }
73	
74	    // Check 14-day window
75	    const daysSince = (Date.now() - new Date(original.createdAt).getTime()) / (1000 * 60 * 60 * 24);
76	    if (daysSince > FOLLOW_UP_WINDOW_DAYS) {
77	      throw new Error(`Follow-up reviews must be submitted within ${FOLLOW_UP_WINDOW_DAYS} days.`);
78	    }
79	
80	    const followUp = createReview({
81	      id: generateId(),
82	      userId,
83	      targetUserId: original.targetUserId,
84	      targetClassId: original.targetClassId,
85	      direction: original.direction,
86	      rating,
87	      text: text || '',
88	      images: images || [],
89	      tags: tags || [],
90	      followUpOf: originalReviewId,
91	    });
92	
93	    await reviewRepository.add(followUp);
94	    await auditService.log('review', followUp.id, 'follow_up', `Follow-up to review ${originalReviewId}`, userId);
95	    return followUp;
96	  }
97	
98	  async getById(reviewId) {
99	    return reviewRepository.getById(reviewId);
100	  }
101	
102	  async getAll() {
103	    return reviewRepository.getAll();
104	  }
105	
106	  async getByUserId(userId) {
107	    return reviewRepository.getByUserId(userId);
108	  }
109	
110	  async getByTargetUserId(targetUserId) {
111	    return reviewRepository.getByTargetUserId(targetUserId);
112	  }
113	
114	  async getByDirection(direction) {
115	    return reviewRepository.getByDirection(direction);
116	  }
117	}
118	
119	export default new ReviewService();
