  async _takeQuiz(quizId) {
    const quiz = await quizService.getQuizById(quizId);
    if (!quiz) { Toast.error('Quiz not found.'); return; }

    const questions = [];
    for (const qId of quiz.questionIds) {
      const q = await quizService.getQuestionById(qId);
