    const user = authService.getCurrentUser();
    const otherUsers = users.filter(u => u.id !== user.id);
    const userOptions = otherUsers.map(u => `<option value="${u.id}">${escapeHtml(u.displayName || u.username)} (${u.role})</option>`).join('');

    Modal.custom('Submit Rating', `
      <form id="rating-form">
        <div class="form-group">
          <label for="rt-to">Rate User</label>
          <select id="rt-to" class="form-control" required>${userOptions}</select>
        </div>
        <div class="form-group">
          <label for="rt-score">Score (1–5)</label>
          <input id="rt-score" class="form-control" type="number" min="1" max="5" required>
        </div>
        <div class="form-group">
