      for (const u of allUsers) {
        const userRegs = allRegs.filter(r => r.userId === u.id);
        if (userRegs.length === 0) continue;

        const total = userRegs.length;
        const approved = userRegs.filter(r => r.status === 'Approved').length;
        const rejected = userRegs.filter(r => r.status === 'Rejected').length;
        const cancelled = userRegs.filter(r => r.status === 'Cancelled').length;

        const fulfillmentRate = total > 0 ? approved / total : 1;
        const lateRate = 0; // No late tracking yet, default 0
        const complaintRate = total > 0 ? rejected / total : 0;

        await reputationService.computeScore(u.id, { fulfillmentRate, lateRate, complaintRate });
