78	    router.route('/registrations', () => renderPage(registrationsPage));
79	    router.route('/quiz', () => renderPage(quizPage));
80	    router.route('/reviews', () => renderPage(reviewsPage));
81	    router.route('/contracts', () => renderPage(contractsPage));
82	    router.route('/admin', () => renderPage(adminPage));
83	
84	    router.notFound(() => {
85	      if (authService.isAuthenticated()) {
86	        router.navigate('/dashboard');
87	      } else {
88	        router.navigate('/login');
89	      }
90	    });
91	
92	    // Highlight active nav link on navigation
93	    router.onNavigate(({ path }) => {
94	      document.querySelectorAll('.sidebar-nav a').forEach(a => {
95	        const href = a.getAttribute('href')?.replace('#', '');
96	        a.classList.toggle('active', href === path);
97	      });
