26	  { name: 'reputationScores',   keyPath: 'id', indexes: [{ name: 'userId', keyPath: 'userId' }] },
27	  { name: 'appConfig',          keyPath: 'key' },
28	  { name: 'browsingHistory',    keyPath: 'id', indexes: [{ name: 'userId', keyPath: 'userId' }, { name: 'timestamp', keyPath: 'timestamp' }] },
29	  { name: 'questionThreads',    keyPath: 'id', indexes: [{ name: 'authorId', keyPath: 'authorId' }] },
30	  { name: 'answers',            keyPath: 'id', indexes: [{ name: 'threadId', keyPath: 'threadId' }, { name: 'authorId', keyPath: 'authorId' }] },
31	  { name: 'favorites',          keyPath: 'id', indexes: [{ name: 'userId', keyPath: 'userId' }, { name: 'itemType', keyPath: 'itemType' }] },
32	  { name: 'wrongQuestions',     keyPath: 'id', indexes: [{ name: 'userId', keyPath: 'userId' }, { name: 'questionId', keyPath: 'questionId' }] },
33	  { name: 'ratings',            keyPath: 'id', indexes: [{ name: 'fromUserId', keyPath: 'fromUserId' }, { name: 'toUserId', keyPath: 'toUserId' }] },
34	  { name: 'appeals',            keyPath: 'id', indexes: [{ name: 'ratingId', keyPath: 'ratingId' }, { name: 'status', keyPath: 'status' }] },
35	];
36	
37	/**
38	 * Opens (or creates) the IndexedDB database.
39	 * @returns {Promise<IDBDatabase>}
40	 */
41	export function openDatabase() {
42	  if (dbInstance) return Promise.resolve(dbInstance);
43	
44	  return new Promise((resolve, reject) => {
45	    const request = indexedDB.open(DB_NAME, DB_VERSION);
46	
47	    request.onupgradeneeded = (event) => {
48	      const db = event.target.result;
49	
50	      for (const storeDef of STORES) {
51	        if (db.objectStoreNames.contains(storeDef.name)) continue;
52	
53	        const store = db.createObjectStore(storeDef.name, {
54	          keyPath: storeDef.keyPath,
55	        });
56	
57	        if (storeDef.indexes) {
58	          for (const idx of storeDef.indexes) {
59	            store.createIndex(idx.name, idx.keyPath, { unique: !!idx.unique });
60	          }
61	        }
62	      }
63	    };
64	
65	    request.onsuccess = (event) => {
66	      dbInstance = event.target.result;
67	      resolve(dbInstance);
68	    };
69	
70	    request.onerror = (event) => {
71	      reject(new Error(`IndexedDB open failed: ${event.target.error}`));
72	    };
73	  });
74	}
75	
76	/**
77	 * Returns the current DB instance (must call openDatabase first).
78	 */
79	export function getDatabase() {
80	  return dbInstance;
81	}
82	
83	/**
84	 * Closes the database connection.
85	 */
86	export function closeDatabase() {
87	  if (dbInstance) {
88	    dbInstance.close();
89	    dbInstance = null;
90	  }
91	}
92	
93	/**
94	 * Deletes the entire database (used for full reset / import).
95	 */
96	export function deleteDatabase() {
97	  closeDatabase();
98	  return new Promise((resolve, reject) => {
99	    const request = indexedDB.deleteDatabase(DB_NAME);
100	    request.onsuccess = () => resolve();
101	    request.onerror = (e) => reject(e.target.error);
102	  });
103	}
104	
105	export { DB_NAME, DB_VERSION, STORES };
