1	/**
2	 * ContractService — template management, placeholder substitution, versioning,
3	 * signature handling, signing workflow states, PDF-like print export.
4	 */
5	
6	import contractRepository from '../repositories/ContractRepository.js';
7	import templateRepository from '../repositories/TemplateRepository.js';
8	import auditService from './AuditService.js';
9	import cryptoService from './CryptoService.js';
10	import { createContract, createTemplate, CONTRACT_STATUS, CONTRACT_TRANSITIONS } from '../models/Contract.js';
11	import { generateId, now, downloadBlob } from '../utils/helpers.js';
12	
13	export class ContractService {
14	  // --- Template Management ---
15	
16	  async createTemplate(data) {
17	    // Extract placeholders from content
18	    const placeholders = (data.content.match(/\{[^}]+\}/g) || []);
19	
20	    const template = createTemplate({
21	      id: generateId(),
22	      name: data.name,
23	      content: data.content,
24	      placeholders,
25	      active: true,
26	      version: 1,
27	      effectiveDate: data.effectiveDate || now(),
28	    });
29	
30	    await templateRepository.add(template);
31	    await auditService.log('template', template.id, 'created', `Template "${data.name}" v1 created`, data.createdBy || 'system');
32	    return template;
33	  }
34	
35	  async updateTemplate(templateId, updates, updatedBy) {
36	    const existing = await templateRepository.getById(templateId);
37	    if (!existing) throw new Error('Template not found.');
38	
39	    // Deactivate old version
40	    existing.active = false;
41	    existing.updatedAt = now();
42	    await templateRepository.put(existing);
43	
44	    // Create new version
45	    const newVersion = createTemplate({
46	      id: generateId(),
47	      name: updates.name || existing.name,
48	      content: updates.content || existing.content,
49	      placeholders: (updates.content || existing.content).match(/\{[^}]+\}/g) || [],
50	      active: true,
51	      version: existing.version + 1,
52	      effectiveDate: updates.effectiveDate || now(),
53	    });
54	
55	    await templateRepository.add(newVersion);
56	    await auditService.log('template', newVersion.id, 'versioned', `Template "${newVersion.name}" v${newVersion.version}`, updatedBy);
57	    return newVersion;
58	  }
59	
60	  async getActiveTemplates() {
61	    return templateRepository.getActive();
62	  }
63	
64	  async getTemplateById(templateId) {
65	    return templateRepository.getById(templateId);
66	  }
67	
68	  async getAllTemplates() {
69	    return templateRepository.getAll();
70	  }
71	
72	  // --- Contract Generation ---
73	
74	  /**
75	   * Generate a contract from a template with variable substitution.
76	   */
77	  async generateContract(templateId, variables, createdBy) {
78	    const template = await templateRepository.getById(templateId);
79	    if (!template) throw new Error('Template not found.');
80	
81	    let content = template.content;
82	    for (const [key, value] of Object.entries(variables)) {
83	      content = content.replace(new RegExp(`\\{${key}\\}`, 'g'), value);
84	    }
85	
86	    const contract = createContract({
87	      id: generateId(),
88	      templateId,
89	      templateVersion: template.version,
90	      content,
91	      status: CONTRACT_STATUS.INITIATED,
92	      createdBy,
93	    });
94	
95	    await contractRepository.add(contract);
96	    await auditService.log('contract', contract.id, 'created', 'Contract generated from template', createdBy);
97	    return contract;
98	  }
99	
100	  // --- Signing Workflow ---
101	
102	  /**
103	   * Transition a contract's signing status.
104	   */
105	  async transitionStatus(contractId, newStatus, userId) {
106	    const contract = await contractRepository.getById(contractId);
107	    if (!contract) throw new Error('Contract not found.');
108	
109	    const allowed = CONTRACT_TRANSITIONS[contract.status] || [];
110	    if (!allowed.includes(newStatus)) {
111	      throw new Error(`Cannot transition contract from ${contract.status} to ${newStatus}.`);
112	    }
113	
114	    const fromStatus = contract.status;
115	    contract.status = newStatus;
116	    contract.updatedAt = now();
117	    await contractRepository.put(contract);
118	
119	    await auditService.log('contract', contractId, 'status_change', `${fromStatus} → ${newStatus}`, userId);
120	    return contract;
121	  }
122	
123	  /**
124	   * Sign a contract — attach typed name or canvas signature + SHA-256 hash.
125	   */
126	  async signContract(contractId, signatureData, signerName, userId) {
127	    const contract = await contractRepository.getById(contractId);
128	    if (!contract) throw new Error('Contract not found.');
129	
130	    if (contract.status !== CONTRACT_STATUS.INITIATED) {
131	      throw new Error('Contract can only be signed when in initiated status.');
132	    }
133	
134	    const timestamp = now();
135	    const hash = await cryptoService.generateSignatureHash(contract.content, signerName, timestamp);
136	
137	    contract.signatureData = signatureData; // base64 canvas or typed name
138	    contract.signatureHash = hash;
139	    contract.signedBy = userId;
140	    contract.signedAt = timestamp;
141	    contract.status = CONTRACT_STATUS.SIGNED;
142	    contract.updatedAt = timestamp;
143	
144	    await contractRepository.put(contract);
145	    await auditService.log('contract', contractId, 'signed', `Signed by ${signerName}, hash: ${hash.substring(0, 16)}...`, userId);
146	    return contract;
147	  }
148	
149	  /**
150	   * Withdraw a contract.
151	   */
152	  async withdrawContract(contractId, userId) {
153	    return this.transitionStatus(contractId, CONTRACT_STATUS.WITHDRAWN, userId);
154	  }
155	
156	  /**
157	   * Void a contract.
158	   */
159	  async voidContract(contractId, userId) {
160	    return this.transitionStatus(contractId, CONTRACT_STATUS.VOIDED, userId);
161	  }
162	
163	  // --- Export ---
164	
165	  /**
166	   * Export contract to a printable HTML blob for PDF-like output.
167	   */
168	  exportToPrintableHTML(contract) {
169	    const html = `<!DOCTYPE html>
170	<html><head><meta charset="UTF-8"><title>Contract ${contract.id}</title>
171	<style>
172	  body { font-family: serif; max-width: 800px; margin: 40px auto; padding: 20px; line-height: 1.6; }
173	  h1 { text-align: center; border-bottom: 2px solid #333; padding-bottom: 10px; }
174	  .sig-block { margin-top: 40px; border-top: 1px solid #999; padding-top: 10px; }
175	  .hash { font-size: 0.7em; color: #666; word-break: break-all; }
176	  @media print { body { margin: 0; } }
177	</style></head><body>
