    if (text && text.length > MAX_TEXT_LENGTH) {
      throw new Error(`Review text must be at most ${MAX_TEXT_LENGTH} characters.`);
    }

    // Sensitive word filtering — block at service level
    if (text) {
      const modCheck = moderationService.checkContent(text);
      if (modCheck.flagged) {
        throw new Error(`Follow-up contains prohibited content: ${modCheck.words.join(', ')}. Please revise.`);
      }
    }

    // Validate images
    if (images && images.length > MAX_IMAGES) {
      throw new Error(`Maximum ${MAX_IMAGES} images allowed.`);
    }

    const followUp = createReview({
      id: generateId(),
      userId,
      targetUserId: original.targetUserId,
      targetClassId: original.targetClassId,
      direction: original.direction,
      rating: rating || original.rating,
      text: text || '',
      images: images || [],
      tags: tags || [],
      followUpOf: originalReviewId,
    });

    await reviewRepository.add(followUp);
    await auditService.log('review', followUp.id, 'follow_up', `Follow-up to review ${originalReviewId}`, userId);
    return followUp;
  }

  async getById(reviewId) {
    return reviewRepository.getById(reviewId);
  }

  async getAll() {
    return reviewRepository.getAll();
  }

  async getByUserId(userId) {
    return reviewRepository.getByUserId(userId);
  }

  async getByTargetUserId(targetUserId) {
    return reviewRepository.getByTargetUserId(targetUserId);
  }

  async getByDirection(direction) {
    return reviewRepository.getByDirection(direction);
  }
}

export default new ReviewService();
"}

