1	/**
2	 * RegistrationService — registration CRUD, state machine, waitlist, audit logging.
3	 * All business rules enforced at service level.
4	 */
5	
6	import registrationRepository from '../repositories/RegistrationRepository.js';
7	import registrationEventRepository from '../repositories/RegistrationEventRepository.js';
8	import classRepository from '../repositories/ClassRepository.js';
9	import userRepository from '../repositories/UserRepository.js';
10	import auditService from './AuditService.js';
11	import { createRegistration, createRegistrationEvent, REGISTRATION_STATUS, REGISTRATION_TRANSITIONS, canTransition, TERMINAL_STATES } from '../models/Registration.js';
12	import { USER_ROLES } from '../models/User.js';
13	import { generateId, now } from '../utils/helpers.js';
14	import eventBus from '../utils/EventBus.js';
15	
16	// Transitions only reviewers/admins may perform
17	const REVIEWER_ONLY_TRANSITIONS = [
18	  REGISTRATION_STATUS.UNDER_REVIEW,
19	  REGISTRATION_STATUS.APPROVED,
20	  REGISTRATION_STATUS.REJECTED,
21	  REGISTRATION_STATUS.NEEDS_MORE_INFO,
22	  REGISTRATION_STATUS.WAITLISTED,
23	];
24	
25	export class RegistrationService {
26	  /**
27	   * Create a new draft registration.
28	   */
29	  async create(userId, classId, notes = '') {
30	    const registration = createRegistration({
31	      id: generateId(),
32	      userId,
33	      classId,
34	      status: REGISTRATION_STATUS.DRAFT,
35	      notes,
36	    });
37	    await registrationRepository.add(registration);
38	    await this._logEvent(registration.id, null, REGISTRATION_STATUS.DRAFT, 'Registration created', userId);
39	    await auditService.log('registration', registration.id, 'created', 'Registration created in Draft', userId);
40	    eventBus.emit('registration:created', registration);
41	    return registration;
42	  }
43	
44	  /**
45	   * Transition a registration to a new status.
46	   * Enforces: state machine, role-based access, rejection comment validation.
47	   */
48	  async transition(registrationId, newStatus, comment, userId) {
49	    const reg = await registrationRepository.getById(registrationId);
50	    if (!reg) throw new Error('Registration not found.');
51	
52	    // State machine enforcement
53	    if (!canTransition(reg.status, newStatus)) {
54	      throw new Error(`Cannot transition from ${reg.status} to ${newStatus}.`);
55	    }
56	
57	    // Role-based enforcement
58	    const actingUser = await userRepository.getById(userId);
59	    if (actingUser) {
60	      const isReviewerOrAdmin = [USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(actingUser.role);
61	      const isOwner = reg.userId === userId;
62	
63	      if (REVIEWER_ONLY_TRANSITIONS.includes(newStatus) && !isReviewerOrAdmin) {
64	        throw new Error(`Only administrators or staff reviewers can transition to ${newStatus}.`);
65	      }
66	
67	      // Learners/Instructors can only Submit their own drafts or Cancel their own registrations
68	      if (!isReviewerOrAdmin) {
69	        if (!isOwner) {
70	          throw new Error('You can only modify your own registrations.');
71	        }
72	        const selfAllowed = [REGISTRATION_STATUS.SUBMITTED, REGISTRATION_STATUS.CANCELLED];
73	        if (!selfAllowed.includes(newStatus)) {
74	          throw new Error(`You do not have permission to transition to ${newStatus}.`);
75	        }
76	      }
77	    }
78	
79	    // Rejection requires >=20 char comment
80	    if (newStatus === REGISTRATION_STATUS.REJECTED) {
81	      if (!comment || comment.trim().length < 20) {
82	        throw new Error('Rejection comment must be at least 20 characters.');
83	      }
84	    }
85	
86	    const fromStatus = reg.status;
87	    reg.status = newStatus;
88	    reg.updatedAt = now();
89	    await registrationRepository.put(reg);
90	
91	    await this._logEvent(reg.id, fromStatus, newStatus, comment || '', userId);
92	    await auditService.log('registration', reg.id, 'status_change', `${fromStatus} → ${newStatus}${comment ? ': ' + comment : ''}`, userId);
93	
94	    eventBus.emit('registration:transition', { registration: reg, fromStatus, toStatus: newStatus });
95	
96	    // Waitlist promotion: only when a previously APPROVED seat is freed
97	    // (i.e., an approved registration is cancelled, freeing capacity)
98	    if (fromStatus === REGISTRATION_STATUS.APPROVED && newStatus === REGISTRATION_STATUS.CANCELLED) {
99	      await this._checkWaitlistPromotion(reg.classId, userId);
100	    }
101	
102	    return reg;
103	  }
104	
105	  /**
106	   * Batch transition multiple registrations.
107	   */
108	  async batchTransition(registrationIds, newStatus, comment, userId) {
109	    const results = [];
110	    for (const id of registrationIds) {
111	      try {
112	        const reg = await this.transition(id, newStatus, comment, userId);
113	        results.push({ id, success: true, registration: reg });
114	      } catch (err) {
115	        results.push({ id, success: false, error: err.message });
116	      }
117	    }
118	    return results;
119	  }
120	
121	  async getById(registrationId) {
122	    return registrationRepository.getById(registrationId);
123	  }
124	
125	  async getAll() {
126	    return registrationRepository.getAll();
127	  }
128	
129	  async getByUserId(userId) {
130	    return registrationRepository.getByUserId(userId);
131	  }
132	
133	  async getByStatus(status) {
134	    return registrationRepository.getByStatus(status);
135	  }
136	
137	  async getByClassId(classId) {
138	    return registrationRepository.getByClassId(classId);
139	  }
140	
141	  async getEvents(registrationId) {
142	    return registrationEventRepository.getByRegistrationId(registrationId);
143	  }
144	
145	  /**
146	   * Compute fill rate for a class (approved / capacity).
147	   */
148	  async getClassFillRate(classId) {
149	    if (!classId) return 0;
150	    const cls = await classRepository.getById(classId);
151	    if (!cls || !cls.capacity) return 0;
152	
153	    const regs = await registrationRepository.getByClassId(classId);
154	    const approvedCount = regs.filter(r => r.status === REGISTRATION_STATUS.APPROVED).length;
155	    return approvedCount / cls.capacity;
156	  }
157	
158	  /**
159	   * Check and promote waitlisted registrations for a class (FIFO).
160	   * Triggers only when fill rate drops below 95%.
161	   */
162	  async _checkWaitlistPromotion(classId, userId) {
163	    if (!classId) return;
164	
165	    const fillRate = await this.getClassFillRate(classId);
166	    if (fillRate >= 0.95) return; // only promote if below 95%
167	
168	    const waitlisted = await registrationRepository.filter(
169	      r => r.classId === classId && r.status === REGISTRATION_STATUS.WAITLISTED
170	    );
171	    if (waitlisted.length === 0) return;
172	
173	    // Sort by creation date (FIFO)
174	    waitlisted.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
175	
176	    // Promote the next in line — use system/admin userId to bypass role check
177	    const next = waitlisted[0];
178	    const fromStatus = next.status;
179	    next.status = REGISTRATION_STATUS.UNDER_REVIEW;
180	    next.updatedAt = now();
181	    await registrationRepository.put(next);
182	
183	    await this._logEvent(next.id, fromStatus, REGISTRATION_STATUS.UNDER_REVIEW, 'Auto-promoted from waitlist (seat available, fill rate < 95%)', userId);
184	    await auditService.log('registration', next.id, 'status_change', `${fromStatus} → ${REGISTRATION_STATUS.UNDER_REVIEW}: Waitlist promotion`, userId);
185	
186	    eventBus.emit('registration:transition', { registration: next, fromStatus, toStatus: REGISTRATION_STATUS.UNDER_REVIEW });
187	  }
188	
189	  async _logEvent(registrationId, fromStatus, toStatus, comment, userId) {
190	    const event = createRegistrationEvent({
191	      id: generateId(),
192	      registrationId,
193	      fromStatus,
194	      toStatus,
195	      comment,
196	      userId,
197	      timestamp: now(),
198	    });
199	    await registrationEventRepository.add(event);
200	    return event;
201	  }
202	}
203	
204	export default new RegistrationService();
205

1	/**
2	 * QuizService — question bank CRUD, bulk import, paper generation, auto-grading, wrong-question tracking.
3	 */
4	
5	import questionRepository from '../repositories/QuestionRepository.js';
6	import quizRepository from '../repositories/QuizRepository.js';
7	import quizResultRepository from '../repositories/QuizResultRepository.js';
8	import wrongQuestionRepository from '../repositories/WrongQuestionRepository.js';
9	import auditService from './AuditService.js';
10	import { createQuestion, QUESTION_TYPES } from '../models/Question.js';
11	import { createQuiz, createQuizResult } from '../models/Quiz.js';
12	import { createWrongQuestion } from '../models/WrongQuestion.js';
13	import { generateId, now } from '../utils/helpers.js';
14	import { validateQuestionRow } from '../utils/validators.js';
15	
16	export class QuizService {
17	  // --- Question Bank CRUD ---
18	
19	  async createQuestion(data) {
20	    const question = createQuestion({ id: generateId(), ...data });
21	    await questionRepository.add(question);
22	    await auditService.log('question', question.id, 'created', `Question created: ${question.type}`, data.createdBy || 'system');
23	    return question;
24	  }
25	
26	  async updateQuestion(id, updates) {
27	    const question = await questionRepository.getById(id);
28	    if (!question) throw new Error('Question not found.');
29	    Object.assign(question, updates, { updatedAt: now() });
30	    await questionRepository.put(question);
31	    return question;
32	  }
33	
34	  async deleteQuestion(id) {
35	    await questionRepository.delete(id);
36	  }
37	
38	  async getQuestionById(id) {
39	    return questionRepository.getById(id);
40	  }
41	
42	  async getAllQuestions() {
43	    return questionRepository.getAll();
44	  }
45	
46	  async getQuestionsByType(type) {
47	    return questionRepository.getByType(type);
48	  }
49	
50	  async getQuestionsByDifficulty(difficulty) {
51	    return questionRepository.getByDifficulty(difficulty);
52	  }
53	
54	  // --- Bulk Import ---
55	
56	  /**
57	   * Validate and import questions from parsed JSON/Excel data.
58	   * Rejects entire batch if any row is invalid.
59	   * @param {Array} rows — array of { questionText, type, correctAnswer, difficulty, tags, ... }
60	   * @returns {{ success: boolean, errors?: string[], count?: number }}
61	   */
62	  async bulkImport(rows, createdBy = 'system') {
63	    const allErrors = [];
64	    for (let i = 0; i < rows.length; i++) {
65	      const errors = validateQuestionRow(rows[i], i + 1);
66	      allErrors.push(...errors);
67	    }
68	    if (allErrors.length > 0) {
69	      return { success: false, errors: allErrors };
70	    }
71	
72	    const questions = rows.map(row => createQuestion({
73	      id: generateId(),
74	      questionText: row.questionText,
75	      type: row.type,
76	      options: row.options || [],
77	      correctAnswer: row.correctAnswer,
78	      difficulty: Number(row.difficulty),
79	      tags: row.tags,
80	      chapter: row.chapter || '',
81	      explanation: row.explanation || '',
82	    }));
83	
84	    await questionRepository.bulkAdd(questions);
85	    await auditService.log('question', 'bulk', 'bulk_import', `Imported ${questions.length} questions`, createdBy);
86	
87	    return { success: true, count: questions.length };
88	  }
89	
90	  // --- Paper Generation ---
91	
92	  /**
93	   * Generate a quiz paper based on rules.
94	   * @param {object} rules — { totalQuestions, difficultyDistribution: { 3: 0.4, 4: 0.4, 5: 0.2 }, chapterConstraints: { 'ch1': 1 } }
95	   */
96	  async generatePaper(title, classId, rules, createdBy) {
97	    const allQuestions = await questionRepository.getAll();
98	    const selected = this._selectQuestions(allQuestions, rules);
99	
100	    const quiz = createQuiz({
101	      id: generateId(),
102	      title,
103	      classId,
104	      questionIds: selected.map(q => q.id),
105	      rules,
106	      createdBy,
107	    });
108	
109	    await quizRepository.add(quiz);
110	    await auditService.log('quiz', quiz.id, 'created', `Paper generated: ${title}`, createdBy);
111	    return quiz;
112	  }
113	
114	  _selectQuestions(allQuestions, rules) {
115	    const total = rules.totalQuestions || 30;
116	    const distribution = rules.difficultyDistribution || {};
117	    const chapterMin = rules.chapterConstraints || {};
118	
119	    // Calculate counts per difficulty level
120	    const difficultyCounts = {};
121	    let allocated = 0;
122	    const difficulties = Object.keys(distribution).map(Number).sort();
123	
124	    for (const d of difficulties) {
125	      difficultyCounts[d] = Math.floor(total * distribution[d]);
126	      allocated += difficultyCounts[d];
127	    }
128	    // Distribute remainder to highest difficulty
129	    if (allocated < total && difficulties.length > 0) {
130	      difficultyCounts[difficulties[difficulties.length - 1]] += total - allocated;
131	    }
132	
133	    // Group questions by difficulty
134	    const byDifficulty = {};
135	    for (const q of allQuestions) {
136	      if (!byDifficulty[q.difficulty]) byDifficulty[q.difficulty] = [];
137	      byDifficulty[q.difficulty].push(q);
138	    }
139	
140	    // Shuffle each group
141	    for (const d of Object.keys(byDifficulty)) {
142	      byDifficulty[d] = this._shuffle(byDifficulty[d]);
143	    }
144	
145	    const selected = [];
146	    const usedIds = new Set();
147	
148	    // Satisfy chapter constraints first
149	    for (const [chapter, minCount] of Object.entries(chapterMin)) {
150	      const chapterQs = allQuestions.filter(q => q.chapter === chapter && !usedIds.has(q.id));
151	      for (let i = 0; i < Math.min(minCount, chapterQs.length); i++) {
152	        selected.push(chapterQs[i]);
153	        usedIds.add(chapterQs[i].id);
154	      }
155	    }
156	
157	    // Fill by difficulty
158	    for (const [d, count] of Object.entries(difficultyCounts)) {
159	      const pool = (byDifficulty[d] || []).filter(q => !usedIds.has(q.id));
160	      const needed = count - selected.filter(q => q.difficulty === Number(d)).length;
161	      for (let i = 0; i < Math.min(needed, pool.length); i++) {
162	        selected.push(pool[i]);
163	        usedIds.add(pool[i].id);
164	      }
165	    }
166	
167	    return selected.slice(0, total);
168	  }
169	
170	  _shuffle(arr) {
171	    const a = [...arr];
172	    for (let i = a.length - 1; i > 0; i--) {
173	      const j = Math.floor(Math.random() * (i + 1));
174	      [a[i], a[j]] = [a[j], a[i]];
175	    }
176	    return a;
177	  }
178	
179	  // --- Answer Evaluation ---
180	
181	  /**
182	   * Submit answers for a quiz and auto-grade objective items.
183	   */
184	  async submitAnswers(quizId, userId, answers) {
185	    const quiz = await quizRepository.getById(quizId);
186	    if (!quiz) throw new Error('Quiz not found.');
187	
188	    const gradedAnswers = [];
189	    let objectiveCorrect = 0;
190	    let objectiveTotal = 0;
191	
192	    for (const ans of answers) {
193	      const question = await questionRepository.getById(ans.questionId);
194	      if (!question) continue;
195	
196	      const graded = { questionId: ans.questionId, answer: ans.answer, autoGraded: false, isCorrect: null };
197	
198	      if (question.type === QUESTION_TYPES.SUBJECTIVE) {
199	        graded.autoGraded = false;
200	      } else {
201	        graded.autoGraded = true;
202	        objectiveTotal++;
203	        if (question.type === QUESTION_TYPES.MULTIPLE) {
204	          const correct = Array.isArray(question.correctAnswer) ? question.correctAnswer.sort() : [];
205	          const given = Array.isArray(ans.answer) ? ans.answer.sort() : [];
206	          graded.isCorrect = JSON.stringify(correct) === JSON.stringify(given);
207	        } else {
208	          graded.isCorrect = String(ans.answer).trim().toLowerCase() === String(question.correctAnswer).trim().toLowerCase();
209	        }
210	        if (graded.isCorrect) objectiveCorrect++;
211	
212	        // Track wrong questions
213	        if (!graded.isCorrect) {
214	          await this._addWrongQuestion(userId, question, ans.answer, quizId);
215	        }
216	      }
217	
218	      gradedAnswers.push(graded);
219	    }
220	
221	    const result = createQuizResult({
222	      id: generateId(),
223	      quizId,
224	      userId,
225	      answers: gradedAnswers,
226	      objectiveScore: objectiveTotal > 0 ? Math.round((objectiveCorrect / objectiveTotal) * 100) : null,
227	    });
228	
229	    await quizResultRepository.add(result);
230	    return result;
231	  }
232	
233	  /**
234	   * Get quiz results for a user.
235	   */
236	  async getResultsByUserId(userId) {
237	    return quizResultRepository.getByUserId(userId);
238	  }
239	
240	  /**
241	   * Get quiz results for a quiz.
242	   */
243	  async getResultsByQuizId(quizId) {
244	    return quizResultRepository.getByQuizId(quizId);
245	  }
