275	  async _addWrongQuestion(userId, question, userAnswer, quizId) {
276	    const entry = createWrongQuestion({
277	      id: generateId(),
278	      userId,
279	      questionId: question.id,
280	      userAnswer: JSON.stringify(userAnswer),
281	      correctAnswer: JSON.stringify(question.correctAnswer),
282	      explanation: question.explanation,
