1	/**
2	 * RatingService — two-way ratings with tag-based feedback and appeal flow.
3	 */
4	
5	import ratingRepository from '../repositories/RatingRepository.js';
6	import appealRepository from '../repositories/AppealRepository.js';
7	import auditService from './AuditService.js';
8	import { createRating, createAppeal, APPEAL_STATUS } from '../models/Rating.js';
9	import { generateId, now } from '../utils/helpers.js';
10	
11	export class RatingService {
12	  /**
13	   * Submit a two-way rating.
14	   */
15	  async submitRating({ fromUserId, toUserId, classId, score, tags, comment }) {
16	    if (!Number.isInteger(score) || score < 1 || score > 5) {
17	      throw new Error('Score must be between 1 and 5.');
18	    }
19	
20	    const rating = createRating({
21	      id: generateId(),
22	      fromUserId,
23	      toUserId,
24	      classId,
25	      score,
26	      tags: tags || [],
27	      comment: comment || '',
28	    });
29	
30	    await ratingRepository.add(rating);
31	    await auditService.log('rating', rating.id, 'created', `Rating ${score}/5 from ${fromUserId} to ${toUserId}`, fromUserId);
32	    return rating;
33	  }
34	
35	  /**
36	   * File an appeal on a rating.
37	   */
38	  async fileAppeal(ratingId, appealerId, reason) {
39	    const rating = await ratingRepository.getById(ratingId);
40	    if (!rating) throw new Error('Rating not found.');
41	
42	    const existingAppeals = await appealRepository.getByRatingId(ratingId);
43	    const pending = existingAppeals.find(a => a.status === APPEAL_STATUS.PENDING);
44	    if (pending) throw new Error('An appeal is already pending for this rating.');
45	
46	    const appeal = createAppeal({
47	      id: generateId(),
48	      ratingId,
49	      appealerId,
50	      reason,
51	    });
52	
53	    await appealRepository.add(appeal);
54	    await auditService.log('appeal', appeal.id, 'filed', `Appeal filed for rating ${ratingId}`, appealerId);
55	    return appeal;
56	  }
57	
58	  /**
59	   * Resolve an appeal (reviewer decision: uphold, adjust, void).
60	   */
61	  async resolveAppeal(appealId, decision, rationale, reviewerId, adjustedScore = null) {
62	    const appeal = await appealRepository.getById(appealId);
63	    if (!appeal) throw new Error('Appeal not found.');
64	
65	    if (!rationale || rationale.trim().length === 0) {
66	      throw new Error('Written rationale is required.');
67	    }
68	
69	    const validDecisions = [APPEAL_STATUS.UPHELD, APPEAL_STATUS.ADJUSTED, APPEAL_STATUS.VOIDED];
70	    if (!validDecisions.includes(decision)) {
71	      throw new Error(`Decision must be one of: ${validDecisions.join(', ')}`);
72	    }
73	
74	    if (decision === APPEAL_STATUS.ADJUSTED && (adjustedScore === null || adjustedScore < 1 || adjustedScore > 5)) {
75	      throw new Error('Adjusted score must be between 1 and 5.');
76	    }
77	
78	    appeal.status = decision;
79	    appeal.decision = decision;
80	    appeal.rationale = rationale;
81	    appeal.reviewerId = reviewerId;
82	    appeal.adjustedScore = adjustedScore;
83	    appeal.resolvedAt = now();
84	
85	    await appealRepository.put(appeal);
86	
87	    // If adjusted, update the original rating
88	    if (decision === APPEAL_STATUS.ADJUSTED) {
89	      const rating = await ratingRepository.getById(appeal.ratingId);
90	      if (rating) {
91	        rating.score = adjustedScore;
92	        await ratingRepository.put(rating);
93	      }
94	    }
95	
96	    // If voided, we could mark the rating as void — for now just log it
97	    await auditService.log('appeal', appealId, 'resolved', `Decision: ${decision}, rationale: ${rationale}`, reviewerId);
98	    return appeal;
99	  }
100	
101	  async getRatingById(ratingId) {
102	    return ratingRepository.getById(ratingId);
103	  }
104	
105	  async getRatingsForUser(toUserId) {
106	    return ratingRepository.getByToUserId(toUserId);
107	  }
108	
109	  async getRatingsByUser(fromUserId) {
110	    return ratingRepository.getByFromUserId(fromUserId);
111	  }
112	
113	  async getAllRatings() {
114	    return ratingRepository.getAll();
115	  }
116	
117	  async getPendingAppeals() {
118	    return appealRepository.getByStatus(APPEAL_STATUS.PENDING);
119	  }
120	
121	  async getAppealsByRatingId(ratingId) {
122	    return appealRepository.getByRatingId(ratingId);
123	  }
124	
125	  async getAllAppeals() {
126	    return appealRepository.getAll();
127	  }
128	}
