1	/**
2	 * ModerationService — sensitive-word filtering, abuse reports, resolution tracking.
3	 */
4	
5	import reportRepository from '../repositories/ReportRepository.js';
6	import auditService from './AuditService.js';
7	import { createReport, REPORT_STATUS, REPORT_OUTCOMES } from '../models/Report.js';
8	import { generateId, now } from '../utils/helpers.js';
9	
10	const RESOLUTION_DEADLINE_DAYS = 7;
11	
12	// Fallback dictionary in case fetch fails (e.g. file:// protocol)
13	const FALLBACK_WORDS = ['spam', 'scam', 'fake', 'fraud', 'abuse', 'harassment', 'threat', 'exploit', 'illegal', 'offensive'];
14	
15	// Loaded once at init
16	let sensitiveWords = [];
17	
18	export class ModerationService {
19	  /**
20	   * Load the sensitive word dictionary.
21	   */
22	  async loadSensitiveWords() {
23	    try {
24	      const response = await fetch('../src/config/sensitiveWords.json');
25	      const data = await response.json();
26	      sensitiveWords = (data.words || []).map(w => w.toLowerCase());
27	    } catch (e) {
28	      console.warn('Could not load sensitive words config, using fallback list.');
29	      sensitiveWords = FALLBACK_WORDS;
30	    }
31	  }
32	
33	  /**
34	   * Check text for sensitive words. Returns flagged words.
35	   */
36	  checkContent(text) {
37	    if (!text) return { flagged: false, words: [] };
38	    const lower = text.toLowerCase();
39	    const found = sensitiveWords.filter(w => lower.includes(w));
40	    return { flagged: found.length > 0, words: found };
41	  }
42	
43	  /**
44	   * Submit an abuse report.
45	   */
46	  async submitReport(reporterId, targetId, targetType, reason) {
47	    const report = createReport({
48	      id: generateId(),
49	      reporterId,
50	      targetId,
51	      targetType,
52	      reason,
53	    });
54	    await reportRepository.add(report);
55	    await auditService.log('report', report.id, 'created', `Abuse report filed against ${targetType}:${targetId}`, reporterId);
56	    return report;
57	  }
58	
59	  /**
60	   * Resolve a report with an outcome.
61	   * @param {string} reportId
62	   * @param {string} outcome — 'dismissed', 'removed', 'warned'
63	   * @param {string} resolvedBy — reviewer user ID
64	   */
65	  async resolveReport(reportId, outcome, resolvedBy) {
66	    const report = await reportRepository.getById(reportId);
67	    if (!report) throw new Error('Report not found.');
68	
69	    const validOutcomes = Object.values(REPORT_OUTCOMES);
70	    if (!validOutcomes.includes(outcome)) {
71	      throw new Error(`Outcome must be one of: ${validOutcomes.join(', ')}`);
72	    }
73	
74	    report.status = REPORT_STATUS.RESOLVED;
75	    report.resolution = outcome;
76	    report.resolvedBy = resolvedBy;
77	    report.resolvedAt = now();
78	    await reportRepository.put(report);
79	
80	    await auditService.log('report', report.id, 'resolved', `Report resolved: ${outcome}`, resolvedBy);
81	    return report;
82	  }
83	
84	  /**
85	   * Get all open/pending reports.
86	   */
87	  async getOpenReports() {
88	    const open = await reportRepository.getByStatus(REPORT_STATUS.OPEN);
89	    const underReview = await reportRepository.getByStatus(REPORT_STATUS.UNDER_REVIEW);
90	    return [...open, ...underReview];
91	  }
92	
93	  /**
94	   * Get overdue reports (open > 7 days).
95	   */
96	  async getOverdueReports() {
97	    const open = await this.getOpenReports();
98	    const cutoff = Date.now() - RESOLUTION_DEADLINE_DAYS * 24 * 60 * 60 * 1000;
99	    return open.filter(r => new Date(r.createdAt).getTime() < cutoff);
100	  }
101	
102	  /**
103	   * Get all reports.
104	   */
105	  async getAllReports() {
106	    return reportRepository.getAll();
107	  }
108	
109	  async getReportById(reportId) {
110	    return reportRepository.getById(reportId);
111	  }
112	}
113	
114	export default new ModerationService();
