1	/**
2	 * ReputationService — score calculation, threshold enforcement, rating aggregation.
3	 */
4	
5	import reputationScoreRepository from '../repositories/ReputationScoreRepository.js';
6	import auditService from './AuditService.js';
7	import { createReputationScore, REPUTATION_THRESHOLD } from '../models/ReputationScore.js';
8	import { generateId, now } from '../utils/helpers.js';
9	
10	// Default weights — can be overridden from appConfig
11	const DEFAULT_WEIGHTS = {
12	  fulfillmentRate: 0.5,
13	  lateRate: 0.3,
14	  complaintRate: 0.2,
15	};
16	
17	export class ReputationService {
18	  /**
19	   * Compute and store reputation score for a user.
20	   * @param {string} userId
21	   * @param {object} metrics — { fulfillmentRate: 0–1, lateRate: 0–1, complaintRate: 0–1 }
22	   * @param {object} [weights] — optional custom weights
23	   */
24	  async computeScore(userId, metrics, weights = DEFAULT_WEIGHTS) {
25	    const score = Math.round(
26	      (metrics.fulfillmentRate * weights.fulfillmentRate +
27	        (1 - metrics.lateRate) * weights.lateRate +
28	        (1 - metrics.complaintRate) * weights.complaintRate) * 100
29	    );
30	
31	    const clampedScore = Math.max(0, Math.min(100, score));
32	
33	    const existing = await reputationScoreRepository.getByUserId(userId);
34	
35	    const record = createReputationScore({
36	      id: existing ? existing.id : generateId(),
37	      userId,
38	      score: clampedScore,
39	      fulfillmentRate: metrics.fulfillmentRate,
40	      lateRate: metrics.lateRate,
41	      complaintRate: metrics.complaintRate,
42	    });
43	
44	    await reputationScoreRepository.put(record);
45	    await auditService.log('reputation', userId, 'computed', `Score: ${clampedScore}`, 'system');
46	
47	    return record;
48	  }
49	
50	  /**
51	   * Get the current reputation score for a user.
52	   */
53	  async getScore(userId) {
54	    return reputationScoreRepository.getByUserId(userId);
55	  }
56	
57	  /**
58	   * Check if user is below threshold and should be restricted.
59	   */
60	  async isRestricted(userId) {
61	    const record = await this.getScore(userId);
62	    if (!record) return false; // no score computed yet, not restricted
63	    return record.score < REPUTATION_THRESHOLD;
64	  }
65	
66	  /**
67	   * Get all reputation scores.
68	   */
69	  async getAllScores() {
70	    return reputationScoreRepository.getAll();
71	  }
72	}
73	
74	export default new ReputationService();
