 * Test Helpers — In-memory IndexedDB mock and test utilities.
 * Allows service-layer tests to run in Node.js without a browser.
 */

// ============================================================
// In-memory store that mimics BaseRepository interface
// ============================================================

export class InMemoryStore {
  constructor() {
    this._data = new Map();
    this._indexes = {};
  }

  async getById(id) {
    return this._data.get(id) || null;
  }

  async getAll() {
    return [...this._data.values()];
  }

  async getByIndex(indexName, value) {
    return [...this._data.values()].filter(r => r[indexName] === value);
  }

  async add(record) {
    const key = record.id || record.key;
    if (this._data.has(key)) throw new Error(`Duplicate key: ${key}`);
    this._data.set(key, structuredClone ? structuredClone(record) : JSON.parse(JSON.stringify(record)));
    return key;
  }

  async put(record) {
    const key = record.id || record.key;
    this._data.set(key, structuredClone ? structuredClone(record) : JSON.parse(JSON.stringify(record)));
    return key;
  }

  async delete(id) {
    this._data.delete(id);
  }

  async clear() {
    this._data.clear();
  }

  async count() {
    return this._data.size;
  }

  async filter(predicate) {
    return [...this._data.values()].filter(predicate);
  }

  async bulkAdd(records) {
    for (const r of records) await this.add(r);
  }

  async bulkPut(records) {
    for (const r of records) await this.put(r);
  }
}

// ============================================================
// Test assertion helpers
// ============================================================

let _passCount = 0;
let _failCount = 0;
let _currentSuite = '';
const _failures = [];

export function describe(name, fn) {
  _currentSuite = name;
  console.log(`\n  ${name}`);
  fn();
}

export async function it(name, fn) {
  try {
    await fn();
    _passCount++;
    console.log(`    ✓ ${name}`);
  } catch (err) {
    _failCount++;
    _failures.push({ suite: _currentSuite, test: name, error: err.message });
    console.log(`    ✗ ${name}`);
    console.log(`      Error: ${err.message}`);
  }
}

export function assert(condition, message = 'Assertion failed') {
  if (!condition) throw new Error(message);
}

export function assertEqual(actual, expected, message) {
  if (actual !== expected) {
    throw new Error(message || `Expected ${JSON.stringify(expected)}, got ${JSON.stringify(actual)}`);
  }
}

export function assertThrows(fn, expectedMessage) {
  let threw = false;
  let error = null;
  try {
    const result = fn();
    if (result && typeof result.then === 'function') {
      throw new Error('Use assertThrowsAsync for async functions');
    }
  } catch (e) {
    threw = true;
    error = e;
  }
  if (!threw) throw new Error(`Expected function to throw${expectedMessage ? ` "${expectedMessage}"` : ''}`);
  if (expectedMessage && !error.message.includes(expectedMessage)) {
    throw new Error(`Expected error containing "${expectedMessage}", got "${error.message}"`);
  }
}

export async function assertThrowsAsync(fn, expectedMessage) {
  let threw = false;
  let error = null;
  try {
    await fn();
  } catch (e) {
    threw = true;
    error = e;
  }
  if (!threw) throw new Error(`Expected async function to throw${expectedMessage ? ` "${expectedMessage}"` : ''}`);
  if (expectedMessage && !error.message.includes(expectedMessage)) {
    throw new Error(`Expected error containing "${expectedMessage}", got "${error.message}"`);
  }
}

export function printSummary() {
  console.log(`\n${'='.repeat(50)}`);
  console.log(`  ${_passCount} passing, ${_failCount} failing`);
  if (_failures.length > 0) {
    console.log('\n  Failures:');
    _failures.forEach((f, i) => {
      console.log(`    ${i + 1}) ${f.suite} > ${f.test}`);
      console.log(`       ${f.error}`);
    });
  }
  console.log(`${'='.repeat(50)}\n`);
  return { passed: _passCount, failed: _failCount, failures: _failures };
}

export function resetCounters() {
  _passCount = 0;
  _failCount = 0;
  _failures.length = 0;
}

// ============================================================
// Factory helpers for test data
// ============================================================

export function makeUser(overrides = {}) {
  return {
    id: overrides.id || `user-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
    username: overrides.username || `user_${Math.random().toString(36).slice(2, 8)}`,
    passwordHash: overrides.passwordHash || 'fakehash:fakesalt',
    role: overrides.role || 'Learner',
    displayName: overrides.displayName || 'Test User',
    email: '',
    lockoutUntil: null,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
}

export function makeClass(overrides = {}) {
  return {
    id: overrides.id || `class-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
    title: overrides.title || 'Test Class',
    description: '',
    instructorId: overrides.instructorId || '',
    capacity: overrides.capacity || 30,
    startDate: '2026-05-01',
    endDate: '2026-07-01',
    status: 'active',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
}

export function makeQuestion(overrides = {}) {
  return {
    id: overrides.id || `q-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
    questionText: overrides.questionText || 'What is 2+2?',
    type: overrides.type || 'single',
    options: overrides.options || [{ label: '3', value: 'A' }, { label: '4', value: 'B' }],
    correctAnswer: overrides.correctAnswer || 'B',
    difficulty: overrides.difficulty || 3,
    tags: overrides.tags || ['math'],
    chapter: overrides.chapter || 'ch1',
    explanation: overrides.explanation || '2+2=4',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
}
"}

