import { describe, it, assert, assertEqual, assertThrowsAsync, InMemoryStore, makeUser, makeClass } from '../test-helpers.js';
import { REGISTRATION_STATUS, canTransition, REGISTRATION_TRANSITIONS } from '../../src/models/Registration.js';
import { USER_ROLES } from '../../src/models/User.js';

// Build a minimal RegistrationService with in-memory stores
function createTestService() {
  const registrationRepo = new InMemoryStore();
  const eventRepo = new InMemoryStore();
  const classRepo = new InMemoryStore();
  const userRepo = new InMemoryStore();
  const auditLogs = [];

  const auditService = {
    async log(entityType, entityId, action, details, userId) {
      auditLogs.push({ entityType, entityId, action, details, userId, timestamp: new Date().toISOString() });
    },
  };

  // Minimal service that mirrors RegistrationService logic
  const service = {
    async create(userId, classId, notes = '') {
      if (!userId) throw new Error('userId is required to create a registration.');
      const reg = {
        id: `reg-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
        userId, classId, notes,
        status: REGISTRATION_STATUS.DRAFT,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };
      await registrationRepo.add(reg);
      await auditService.log('registration', reg.id, 'created', 'Registration created in Draft', userId);
      return reg;
    },

    async transition(registrationId, newStatus, comment, userId) {
      if (!registrationId) throw new Error('registrationId is required.');
      if (!newStatus) throw new Error('newStatus is required.');
      if (!userId) throw new Error('userId is required for transition.');

      const reg = await registrationRepo.getById(registrationId);
      if (!reg) throw new Error('Registration not found.');

      if (!canTransition(reg.status, newStatus)) {
        throw new Error(`Cannot transition from ${reg.status} to ${newStatus}.`);
      }

      const actingUser = await userRepo.getById(userId);
      if (actingUser) {
        const isReviewerOrAdmin = [USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(actingUser.role);
        const isOwner = reg.userId === userId;
        const REVIEWER_ONLY = [REGISTRATION_STATUS.UNDER_REVIEW, REGISTRATION_STATUS.APPROVED, REGISTRATION_STATUS.REJECTED, REGISTRATION_STATUS.NEEDS_MORE_INFO, REGISTRATION_STATUS.WAITLISTED];

        if (REVIEWER_ONLY.includes(newStatus) && !isReviewerOrAdmin) {
          throw new Error(`Only administrators or staff reviewers can transition to ${newStatus}.`);
        }
        if (!isReviewerOrAdmin) {
          if (!isOwner) throw new Error('You can only modify your own registrations.');
          const selfAllowed = [REGISTRATION_STATUS.SUBMITTED, REGISTRATION_STATUS.CANCELLED];
          if (!selfAllowed.includes(newStatus)) throw new Error(`You do not have permission to transition to ${newStatus}.`);
        }
      }

      if (newStatus === REGISTRATION_STATUS.REJECTED) {
        if (!comment || comment.trim().length < 20) {
          throw new Error('Rejection comment must be at least 20 characters.');
        }
      }

      const fromStatus = reg.status;
      reg.status = newStatus;
      reg.updatedAt = new Date().toISOString();
      await registrationRepo.put(reg);

      await auditService.log('registration', reg.id, 'status_change', `${fromStatus} → ${newStatus}`, userId);

      // Waitlist promotion only on APPROVED → CANCELLED
      if (fromStatus === REGISTRATION_STATUS.APPROVED && newStatus === REGISTRATION_STATUS.CANCELLED) {
        await service._checkWaitlistPromotion(reg.classId, userId);
      }

      return reg;
    },

    async getClassFillRate(classId) {
      if (!classId) return 0;
      const cls = await classRepo.getById(classId);
      if (!cls || !cls.capacity) return 0;
      const regs = await registrationRepo.filter(r => r.classId === classId);
      const approved = regs.filter(r => r.status === REGISTRATION_STATUS.APPROVED).length;
      return approved / cls.capacity;
    },

    async _checkWaitlistPromotion(classId, userId) {
      if (!classId) return;
      const fillRate = await service.getClassFillRate(classId);
      if (fillRate >= 0.95) return;
      const waitlisted = await registrationRepo.filter(r => r.classId === classId && r.status === REGISTRATION_STATUS.WAITLISTED);
      if (waitlisted.length === 0) return;
      waitlisted.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
      const next = waitlisted[0];
      next.status = REGISTRATION_STATUS.UNDER_REVIEW;
      next.updatedAt = new Date().toISOString();
      await registrationRepo.put(next);
      await auditService.log('registration', next.id, 'status_change', `Waitlisted → UnderReview: Waitlist promotion`, userId);
    },
  };

  return { service, registrationRepo, eventRepo, classRepo, userRepo, auditLogs };
}

