      const reviewer = makeUser({ id: 'rev1', role: USER_ROLES.STAFF_REVIEWER });
      await userRepo.add(learner);
      await userRepo.add(reviewer);

      await registrationRepo.add({ id: 'r1', userId: 'u1', classId: 'c1', status: REGISTRATION_STATUS.UNDER_REVIEW, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });

