      for (let i = 0; i < 10; i++) {
        await registrationRepo.add({ id: `r-a-${i}`, userId: `u${i}`, classId: 'c1', status: REGISTRATION_STATUS.APPROVED, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });
