      const cls = makeClass({ id: 'c1', capacity: 10 });
      await classRepo.add(cls);

      // 2 waitlisted, second was created first
      await registrationRepo.add({ id: 'w-later', userId: 'u2', classId: 'c1', status: REGISTRATION_STATUS.WAITLISTED, createdAt: new Date('2026-03-02').toISOString(), updatedAt: new Date().toISOString() });
      await registrationRepo.add({ id: 'w-earlier', userId: 'u1', classId: 'c1', status: REGISTRATION_STATUS.WAITLISTED, createdAt: new Date('2026-03-01').toISOString(), updatedAt: new Date().toISOString() });

