      // NOTE: In our model APPROVED has empty transitions, so it IS terminal
      assert(!canTransition(REGISTRATION_STATUS.REJECTED, REGISTRATION_STATUS.CANCELLED), 'Rejected → Cancelled should not be valid');
    });
  });

  describe('RegistrationService.transition() — Role Enforcement', async () => {
    await it('should prevent Learner from approving', async () => {
      const { service, userRepo, registrationRepo } = createTestService();
      const learner = makeUser({ id: 'u1', role: USER_ROLES.LEARNER });
      const reviewer = makeUser({ id: 'rev1', role: USER_ROLES.STAFF_REVIEWER });
      await userRepo.add(learner);
      await userRepo.add(reviewer);

      await registrationRepo.add({ id: 'r1', userId: 'u1', classId: 'c1', status: REGISTRATION_STATUS.UNDER_REVIEW, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });

      await assertThrowsAsync(
        () => service.transition('r1', REGISTRATION_STATUS.APPROVED, '', 'u1'),
        'Only administrators or staff reviewers'
      );
    });

    await it('should allow Admin to approve', async () => {
      const { service, userRepo, registrationRepo } = createTestService();
      const admin = makeUser({ id: 'admin1', role: USER_ROLES.ADMINISTRATOR });
      await userRepo.add(admin);
      await registrationRepo.add({ id: 'r1', userId: 'u1', classId: 'c1', status: REGISTRATION_STATUS.UNDER_REVIEW, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });

      const result = await service.transition('r1', REGISTRATION_STATUS.APPROVED, '', 'admin1');
      assertEqual(result.status, REGISTRATION_STATUS.APPROVED);
    });

    await it('should prevent Learner from modifying another users registration', async () => {
      const { service, userRepo, registrationRepo } = createTestService();
      await userRepo.add(makeUser({ id: 'u1', role: USER_ROLES.LEARNER }));
      await userRepo.add(makeUser({ id: 'u2', role: USER_ROLES.LEARNER }));
      await registrationRepo.add({ id: 'r1', userId: 'u1', classId: 'c1', status: REGISTRATION_STATUS.DRAFT, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });

      await assertThrowsAsync(
        () => service.transition('r1', REGISTRATION_STATUS.SUBMITTED, '', 'u2'),
        'You can only modify your own'
      );
    });
  });

  describe('RegistrationService.transition() — Rejection Comment', async () => {
    await it('should require >=20 char comment for rejection', async () => {
      const { service, userRepo, registrationRepo } = createTestService();
      await userRepo.add(makeUser({ id: 'rev1', role: USER_ROLES.STAFF_REVIEWER }));
      await registrationRepo.add({ id: 'r1', userId: 'u1', classId: 'c1', status: REGISTRATION_STATUS.UNDER_REVIEW, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });

      await assertThrowsAsync(
        () => service.transition('r1', REGISTRATION_STATUS.REJECTED, 'too short', 'rev1'),
        'Rejection comment must be at least 20 characters'
      );
    });

    await it('should accept valid rejection comment', async () => {
      const { service, userRepo, registrationRepo } = createTestService();
      await userRepo.add(makeUser({ id: 'rev1', role: USER_ROLES.STAFF_REVIEWER }));
      await registrationRepo.add({ id: 'r1', userId: 'u1', classId: 'c1', status: REGISTRATION_STATUS.UNDER_REVIEW, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });

      const result = await service.transition('r1', REGISTRATION_STATUS.REJECTED, 'This registration is incomplete and missing required documents.', 'rev1');
      assertEqual(result.status, REGISTRATION_STATUS.REJECTED);
    });
  });

  describe('RegistrationService — Waitlist Promotion', async () => {
    await it('should promote waitlisted user when approved seat freed and fill < 95%', async () => {
      const { service, registrationRepo, classRepo, userRepo } = createTestService();
      await userRepo.add(makeUser({ id: 'admin1', role: USER_ROLES.ADMINISTRATOR }));

      const cls = makeClass({ id: 'c1', capacity: 10 });
      await classRepo.add(cls);

      // 5 approved, 1 waitlisted
      for (let i = 0; i < 5; i++) {
        await registrationRepo.add({ id: `r-approved-${i}`, userId: `u${i}`, classId: 'c1', status: REGISTRATION_STATUS.APPROVED, createdAt: new Date(Date.now() - i * 1000).toISOString(), updatedAt: new Date().toISOString() });
      }
      await registrationRepo.add({ id: 'r-waitlisted', userId: 'u-wait', classId: 'c1', status: REGISTRATION_STATUS.WAITLISTED, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });

      // Cancel one approved → triggers waitlist promotion
      // Manually transition since we need the APPROVED → CANCELLED trigger
      const approvedReg = await registrationRepo.getById('r-approved-0');
      approvedReg.status = REGISTRATION_STATUS.CANCELLED;
      await registrationRepo.put(approvedReg);
      await service._checkWaitlistPromotion('c1', 'admin1');

      const promoted = await registrationRepo.getById('r-waitlisted');
      assertEqual(promoted.status, REGISTRATION_STATUS.UNDER_REVIEW);
    });

    await it('should NOT promote when fill rate >= 95%', async () => {
      const { service, registrationRepo, classRepo } = createTestService();
      const cls = makeClass({ id: 'c1', capacity: 10 });
      await classRepo.add(cls);

      // 10 approved (100% fill), 1 waitlisted
      for (let i = 0; i < 10; i++) {
        await registrationRepo.add({ id: `r-a-${i}`, userId: `u${i}`, classId: 'c1', status: REGISTRATION_STATUS.APPROVED, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });
      }
      await registrationRepo.add({ id: 'r-w', userId: 'u-wait', classId: 'c1', status: REGISTRATION_STATUS.WAITLISTED, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });

      await service._checkWaitlistPromotion('c1', 'admin1');

      const stillWaitlisted = await registrationRepo.getById('r-w');
      assertEqual(stillWaitlisted.status, REGISTRATION_STATUS.WAITLISTED);
    });

    await it('should promote FIFO — earliest waitlisted first', async () => {
      const { service, registrationRepo, classRepo } = createTestService();
      const cls = makeClass({ id: 'c1', capacity: 10 });
      await classRepo.add(cls);

      // 2 waitlisted, second was created first
      await registrationRepo.add({ id: 'w-later', userId: 'u2', classId: 'c1', status: REGISTRATION_STATUS.WAITLISTED, createdAt: new Date('2026-03-02').toISOString(), updatedAt: new Date().toISOString() });
      await registrationRepo.add({ id: 'w-earlier', userId: 'u1', classId: 'c1', status: REGISTRATION_STATUS.WAITLISTED, createdAt: new Date('2026-03-01').toISOString(), updatedAt: new Date().toISOString() });

      await service._checkWaitlistPromotion('c1', 'admin1');

      const earlier = await registrationRepo.getById('w-earlier');
      const later = await registrationRepo.getById('w-later');
      assertEqual(earlier.status, REGISTRATION_STATUS.UNDER_REVIEW);
      assertEqual(later.status, REGISTRATION_STATUS.WAITLISTED);
    });
  });

  describe('RegistrationService — Audit Trail', async () => {
    await it('should log creation and transitions', async () => {
      const { service, userRepo, auditLogs } = createTestService();
      await userRepo.add(makeUser({ id: 'u1', role: USER_ROLES.LEARNER }));
      const reg = await service.create('u1', 'c1');
      await service.transition(reg.id, REGISTRATION_STATUS.SUBMITTED, '', 'u1');

      assert(auditLogs.length >= 2, `Expected at least 2 audit logs, got ${auditLogs.length}`);
      assertEqual(auditLogs[0].action, 'created');
      assertEqual(auditLogs[1].action, 'status_change');
    });
  });

  describe('State Machine Model — canTransition()', async () => {
    await it('should define correct transitions for every status', async () => {
      // Draft can go to Submitted and Cancelled
      assert(canTransition('Draft', 'Submitted'));
      assert(canTransition('Draft', 'Cancelled'));
      assert(!canTransition('Draft', 'Approved'));

      // Submitted can go to NeedsMoreInfo, UnderReview, Cancelled, Waitlisted
      assert(canTransition('Submitted', 'NeedsMoreInfo'));
      assert(canTransition('Submitted', 'UnderReview'));
      assert(canTransition('Submitted', 'Cancelled'));
      assert(canTransition('Submitted', 'Waitlisted'));
      assert(!canTransition('Submitted', 'Approved'));

      // UnderReview can go to Approved, Rejected, NeedsMoreInfo, Cancelled
      assert(canTransition('UnderReview', 'Approved'));
      assert(canTransition('UnderReview', 'Rejected'));
      assert(canTransition('UnderReview', 'NeedsMoreInfo'));
      assert(canTransition('UnderReview', 'Cancelled'));

      // Terminal states cannot transition
      assert(!canTransition('Approved', 'Draft'));
      assert(!canTransition('Rejected', 'Draft'));
      assert(!canTransition('Cancelled', 'Draft'));
    });
  });
}
"}

