 * Unit Tests — ReviewService
 * Tests validation, sensitive word filtering, follow-up logic, image constraints.
 */

import { describe, it, assert, assertEqual, assertThrowsAsync, InMemoryStore } from '../test-helpers.js';

function createTestService() {
  const reviewRepo = new InMemoryStore();
  const auditLogs = [];

  let sensitiveWords = ['spam', 'scam', 'fraud'];

  const moderationService = {
    checkContent(text) {
      if (!text) return { flagged: false, words: [] };
      const lower = text.toLowerCase();
      const found = sensitiveWords.filter(w => lower.includes(w));
      return { flagged: found.length > 0, words: found };
    },
  };

  const auditService = {
    async log(entityType, entityId, action, details, userId) {
      auditLogs.push({ entityType, entityId, action, details, userId });
    },
  };

  const service = {
    async submitReview({ userId, targetUserId, targetClassId, direction, rating, text, images, tags }) {
      if (!userId) throw new Error('userId is required.');
      if (!Number.isInteger(rating) || rating < 1 || rating > 5) throw new Error('Rating must be between 1 and 5.');
      if (text && text.length > 2000) throw new Error('Review text must be at most 2000 characters.');

      if (text) {
        const modCheck = moderationService.checkContent(text);
        if (modCheck.flagged) throw new Error(`Review contains prohibited content: ${modCheck.words.join(', ')}. Please revise.`);
      }

      if (images && images.length > 6) throw new Error('Maximum 6 images allowed.');
      if (images) {
        for (const img of images) {
          if (img.size > 2 * 1024 * 1024) throw new Error('Each image must be under 2MB.');
        }
      }

      const review = {
        id: `rev-${Date.now()}`,
        userId, targetUserId, targetClassId, direction,
        rating, text: text || '', images: images || [], tags: tags || [],
        followUpOf: null,
        createdAt: new Date().toISOString(),
      };

      await reviewRepo.add(review);
      await auditService.log('review', review.id, 'created', `Review submitted: ${rating} stars`, userId);
      return review;
    },

    async submitFollowUp(originalReviewId, { text, rating, images, tags }, userId) {
      const original = await reviewRepo.getById(originalReviewId);
      if (!original) throw new Error('Original review not found.');
      if (original.userId !== userId) throw new Error('Only the original reviewer can follow up.');

      const allReviews = await reviewRepo.getAll();
      const existingFollowUp = allReviews.find(r => r.followUpOf === originalReviewId);
      if (existingFollowUp) throw new Error('A follow-up review has already been submitted.');

      const daysSince = (Date.now() - new Date(original.createdAt).getTime()) / (1000 * 60 * 60 * 24);
      if (daysSince > 14) throw new Error('Follow-up reviews must be submitted within 14 days.');

      if (text && text.length > 2000) throw new Error('Review text must be at most 2000 characters.');

      if (text) {
        const modCheck = moderationService.checkContent(text);
        if (modCheck.flagged) throw new Error(`Follow-up contains prohibited content: ${modCheck.words.join(', ')}. Please revise.`);
      }

      const followUp = {
        id: `rev-fu-${Date.now()}`,
        userId, rating: rating || original.rating,
        text: text || '', images: images || [], tags: tags || [],
        followUpOf: originalReviewId,
        createdAt: new Date().toISOString(),
      };

      await reviewRepo.add(followUp);
      return followUp;
    },
  };

  return { service, reviewRepo, auditLogs };
}

export async function runReviewTests() {
  describe('ReviewService.submitReview() — Validation', async () => {
    await it('should create a valid review', async () => {
      const { service } = createTestService();
      const review = await service.submitReview({ userId: 'u1', rating: 4, text: 'Great class', direction: 'learner_to_class' });
      assertEqual(review.rating, 4);
      assert(review.id);
    });

    await it('should reject missing userId', async () => {
      const { service } = createTestService();
      await assertThrowsAsync(() => service.submitReview({ userId: '', rating: 3 }), 'userId is required');
    });

    await it('should reject rating < 1', async () => {
      const { service } = createTestService();
      await assertThrowsAsync(() => service.submitReview({ userId: 'u1', rating: 0 }), 'Rating must be between 1 and 5');
    });

    await it('should reject rating > 5', async () => {
      const { service } = createTestService();
      await assertThrowsAsync(() => service.submitReview({ userId: 'u1', rating: 6 }), 'Rating must be between 1 and 5');
    });

    await it('should reject non-integer rating', async () => {
      const { service } = createTestService();
      await assertThrowsAsync(() => service.submitReview({ userId: 'u1', rating: 3.5 }), 'Rating must be between 1 and 5');
    });

    await it('should reject text > 2000 characters', async () => {
      const { service } = createTestService();
      await assertThrowsAsync(() => service.submitReview({ userId: 'u1', rating: 3, text: 'a'.repeat(2001) }), 'at most 2000');
    });

    await it('should accept text exactly 2000 characters', async () => {
      const { service } = createTestService();
      const review = await service.submitReview({ userId: 'u1', rating: 3, text: 'a'.repeat(2000) });
      assertEqual(review.text.length, 2000);
    });
  });

  describe('ReviewService.submitReview() — Sensitive Word Filtering', async () => {
    await it('should block review with sensitive words', async () => {
      const { service } = createTestService();
      await assertThrowsAsync(
        () => service.submitReview({ userId: 'u1', rating: 3, text: 'This is a spam review' }),
        'prohibited content'
      );
    });

    await it('should allow clean text', async () => {
      const { service } = createTestService();
      const review = await service.submitReview({ userId: 'u1', rating: 3, text: 'Great class, learned a lot' });
      assert(review.id);
    });
  });

  describe('ReviewService.submitReview() — Image Validation', async () => {
    await it('should reject more than 6 images', async () => {
      const { service } = createTestService();
      const images = Array(7).fill({ size: 100, type: 'image/png' });
      await assertThrowsAsync(
        () => service.submitReview({ userId: 'u1', rating: 3, images }),
        'Maximum 6 images'
      );
    });

    await it('should reject image > 2MB', async () => {
      const { service } = createTestService();
      const images = [{ size: 3 * 1024 * 1024, type: 'image/png' }];
      await assertThrowsAsync(
        () => service.submitReview({ userId: 'u1', rating: 3, images }),
        'under 2MB'
      );
    });

    await it('should accept valid images', async () => {
      const { service } = createTestService();
      const images = [{ size: 1024 * 1024, type: 'image/jpeg' }];
      const review = await service.submitReview({ userId: 'u1', rating: 3, images });
      assertEqual(review.images.length, 1);
    });
  });

  describe('ReviewService.submitFollowUp()', async () => {
    await it('should allow follow-up within 14 days', async () => {
      const { service } = createTestService();
      const original = await service.submitReview({ userId: 'u1', rating: 3, text: 'Original' });
      const followUp = await service.submitFollowUp(original.id, { rating: 4, text: 'Updated' }, 'u1');
      assertEqual(followUp.followUpOf, original.id);
    });

    await it('should block second follow-up', async () => {
      const { service } = createTestService();
      const original = await service.submitReview({ userId: 'u1', rating: 3, text: 'Original' });
      await service.submitFollowUp(original.id, { rating: 4, text: 'First follow-up' }, 'u1');
      await assertThrowsAsync(
        () => service.submitFollowUp(original.id, { rating: 5, text: 'Second follow-up' }, 'u1'),
        'already been submitted'
      );
    });

    await it('should block follow-up by different user', async () => {
      const { service } = createTestService();
      const original = await service.submitReview({ userId: 'u1', rating: 3, text: 'Original' });
      await assertThrowsAsync(
        () => service.submitFollowUp(original.id, { rating: 4 }, 'u2'),
        'Only the original reviewer'
      );
    });

    await it('should block follow-up with sensitive words', async () => {
      const { service } = createTestService();
      const original = await service.submitReview({ userId: 'u1', rating: 3, text: 'Good' });
      await assertThrowsAsync(
        () => service.submitFollowUp(original.id, { text: 'This is a fraud!' }, 'u1'),
        'prohibited content'
      );
    });

    await it('should block follow-up after 14 days', async () => {
      const { service, reviewRepo } = createTestService();
      // Create a review dated 15 days ago
      const oldReview = {
        id: 'old-review', userId: 'u1', rating: 3, text: 'Old',
        images: [], tags: [], followUpOf: null,
        createdAt: new Date(Date.now() - 15 * 24 * 60 * 60 * 1000).toISOString(),
      };
      await reviewRepo.add(oldReview);

      await assertThrowsAsync(
        () => service.submitFollowUp('old-review', { rating: 4 }, 'u1'),
        'within 14 days'
      );
    });
  });
}
"}

