{"file_path": "/Users/tsiontesfaye/Projects/EaglePoint/training-ops/repo/tests/unit/test-quiz-service.js", "content": "/**
 * Unit Tests — QuizService
 * Tests question CRUD validation, bulk import, paper generation, grading.
 */

import { describe, it, assert, assertEqual, assertThrowsAsync, InMemoryStore, makeQuestion } from '../test-helpers.js';
import { QUESTION_TYPES } from '../../src/models/Question.js';
import { validateQuestionRow } from '../../src/utils/validators.js';

function createTestService() {
  const questionRepo = new InMemoryStore();
  const quizRepo = new InMemoryStore();
  const quizResultRepo = new InMemoryStore();
  const wrongQRepo = new InMemoryStore();
  const auditLogs = [];
  const auditService = { async log(...args) { auditLogs.push(args); } };

  const service = {
    async createQuestion(data) {
      if (!data.questionText || String(data.questionText).trim() === '') throw new Error('questionText is required.');
      const validTypes = Object.values(QUESTION_TYPES);
      if (!validTypes.includes(data.type)) throw new Error(`type must be one of: ${validTypes.join(', ')}`);
      if (data.type !== QUESTION_TYPES.SUBJECTIVE && (!data.correctAnswer || String(data.correctAnswer).toString().trim() === '')) {
        throw new Error('correctAnswer is required for non-subjective questions.');
      }
      const diff = Number(data.difficulty);
      if (!Number.isInteger(diff) || diff < 1 || diff > 5) throw new Error('difficulty must be an integer between 1 and 5.');

      const question = { id: `q-${Date.now()}-${Math.random().toString(36).slice(2)}`, ...data, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() };
      await questionRepo.add(question);
      return question;
    },

    async bulkImport(rows) {
      if (!Array.isArray(rows) || rows.length === 0) return { success: false, errors: ['Import data must be a non-empty array.'] };
      const allErrors = [];
      for (let i = 0; i < rows.length; i++) {
        allErrors.push(...validateQuestionRow(rows[i], i + 1));
      }
      if (allErrors.length > 0) return { success: false, errors: allErrors };
      for (const row of rows) {
        await questionRepo.add({ id: `q-${Date.now()}-${Math.random().toString(36).slice(2)}`, ...row, createdAt: new Date().toISOString() });
      }
      return { success: true, count: rows.length };
    },

    async submitAnswers(quizId, userId, answers) {
      if (!quizId) throw new Error('quizId is required.');
      if (!userId) throw new Error('userId is required.');
      if (!Array.isArray(answers)) throw new Error('answers must be an array.');
      const quiz = await quizRepo.getById(quizId);
      if (!quiz) throw new Error('Quiz not found.');
      if (!quiz.questionIds || quiz.questionIds.length === 0) throw new Error('Quiz has no questions.');

      let objectiveCorrect = 0, objectiveTotal = 0;
      const gradedAnswers = [];

      for (const ans of answers) {
        const q = await questionRepo.getById(ans.questionId);
        if (!q) continue;
        const graded = { questionId: ans.questionId, answer: ans.answer, autoGraded: false, isCorrect: null };
        if (q.type === 'subjective') {
          graded.autoGraded = false;
        } else {
          graded.autoGraded = true;
          objectiveTotal++;
          if (q.type === 'multiple') {
            const correct = Array.isArray(q.correctAnswer) ? [...q.correctAnswer].sort() : [];
            const given = Array.isArray(ans.answer) ? [...ans.answer].sort() : [];
            graded.isCorrect = JSON.stringify(correct) === JSON.stringify(given);
          } else {
            graded.isCorrect = String(ans.answer).trim().toLowerCase() === String(q.correctAnswer).trim().toLowerCase();
          }
          if (graded.isCorrect) objectiveCorrect++;
          if (!graded.isCorrect) {
            await wrongQRepo.add({ id: `wq-${Date.now()}`, userId, questionId: q.id, userAnswer: JSON.stringify(ans.answer), correctAnswer: JSON.stringify(q.correctAnswer), explanation: q.explanation || '', createdAt: new Date().toISOString() });
          }
        }
        gradedAnswers.push(graded);
      }

      const result = {
        id: `result-${Date.now()}`, quizId, userId, answers: gradedAnswers,
        objectiveScore: objectiveTotal > 0 ? Math.round((objectiveCorrect / objectiveTotal) * 100) : null,
        subjectiveScores: {}, totalScore: null,
        submittedAt: new Date().toISOString(),
      };
      await quizResultRepo.add(result);
      return result;
    },
  };

  return { service, questionRepo, quizRepo, quizResultRepo, wrongQRepo };
}

export async function runQuizTests() {
  describe('QuizService.createQuestion() — Validation', async () => {
    await it('should create a valid single-choice question', async () => {
      const { service } = createTestService();
      const q = await service.createQuestion({ questionText: 'What is 2+2?', type: 'single', correctAnswer: 'B', difficulty: 3, tags: ['math'] });
      assertEqual(q.type, 'single');
    });

    await it('should reject empty questionText', async () => {
      const { service } = createTestService();
      await assertThrowsAsync(() => service.createQuestion({ questionText: '', type: 'single', correctAnswer: 'A', difficulty: 3 }), 'questionText is required');
    });

    await it('should reject invalid type', async () => {
      const { service } = createTestService();
      await assertThrowsAsync(() => service.createQuestion({ questionText: 'Q', type: 'essay', correctAnswer: 'A', difficulty: 3 }), 'type must be one of');
    });

    await it('should reject missing correctAnswer for non-subjective', async () => {
      const { service } = createTestService();
      await assertThrowsAsync(() => service.createQuestion({ questionText: 'Q', type: 'single', correctAnswer: '', difficulty: 3 }), 'correctAnswer is required');
    });

    await it('should allow missing correctAnswer for subjective', async () => {
      const { service } = createTestService();
      const q = await service.createQuestion({ questionText: 'Explain X', type: 'subjective', difficulty: 2 });
      assertEqual(q.type, 'subjective');
    });

    await it('should reject difficulty outside 1-5', async () => {
      const { service } = createTestService();
      await assertThrowsAsync(() => service.createQuestion({ questionText: 'Q', type: 'single', correctAnswer: 'A', difficulty: 0 }), 'difficulty must be');
      await assertThrowsAsync(() => service.createQuestion({ questionText: 'Q', type: 'single', correctAnswer: 'A', difficulty: 6 }), 'difficulty must be');
    });

    await it('should reject non-integer difficulty', async () => {
      const { service } = createTestService();
      await assertThrowsAsync(() => service.createQuestion({ questionText: 'Q', type: 'single', correctAnswer: 'A', difficulty: 3.5 }), 'difficulty must be');
    });
  });

  describe('QuizService.bulkImport() — Validation', async () => {
    await it('should import valid rows', async () => {
      const { service } = createTestService();
      const rows = [
        { questionText: 'Q1', type: 'single', correctAnswer: 'A', difficulty: 3, tags: 'math' },
        { questionText: 'Q2', type: 'fill-in', correctAnswer: 'yes', difficulty: 2, tags: 'science' },
      ];
      const result = await service.bulkImport(rows);
      assert(result.success);
      assertEqual(result.count, 2);
    });

    await it('should reject empty array', async () => {
      const { service } = createTestService();
      const result = await service.bulkImport([]);
      assert(!result.success);
    });

    await it('should reject batch if any row fails', async () => {
      const { service } = createTestService();
      const rows = [
        { questionText: 'Q1', type: 'single', correctAnswer: 'A', difficulty: 3, tags: 'math' },
        { questionText: '', type: 'single', correctAnswer: 'A', difficulty: 3, tags: 'math' }, // invalid
      ];
      const result = await service.bulkImport(rows);
      assert(!result.success);
      assert(result.errors.length > 0);
    });

    await it('should validate required columns', async () => {
      const errors = validateQuestionRow({}, 1);
      assert(errors.length >= 4, `Expected at least 4 errors for empty row, got ${errors.length}`);
    });

    await it('should validate difficulty range', async () => {
      const errors = validateQuestionRow({ questionText: 'Q', type: 'single', correctAnswer: 'A', difficulty: 10, tags: 'x' }, 1);
      assert(errors.some(e => e.includes('difficulty')));
    });
  });

  describe('QuizService.submitAnswers() — Auto-grading', async () => {
    await it('should auto-grade single choice correctly', async () => {
      const { service, questionRepo, quizRepo } = createTestService();
      const q = makeQuestion({ id: 'q1', type: 'single', correctAnswer: 'B' });
      await questionRepo.add(q);
      await quizRepo.add({ id: 'quiz1', questionIds: ['q1'], title: 'Test' });

      const result = await service.submitAnswers('quiz1', 'u1', [{ questionId: 'q1', answer: 'B' }]);
      assertEqual(result.objectiveScore, 100);
      assertEqual(result.answers[0].isCorrect, true);
    });

    await it('should mark wrong answer and track in wrong-question notebook', async () => {
      const { service, questionRepo, quizRepo, wrongQRepo } = createTestService();
      const q = makeQuestion({ id: 'q1', type: 'single', correctAnswer: 'B' });
      await questionRepo.add(q);
      await quizRepo.add({ id: 'quiz1', questionIds: ['q1'], title: 'Test' });

      await service.submitAnswers('quiz1', 'u1', [{ questionId: 'q1', answer: 'A' }]);
      const wrongQs = await wrongQRepo.getAll();
      assert(wrongQs.length > 0, 'Wrong question should be tracked');
    });

    await it('should auto-grade multiple choice correctly', async () => {
      const { service, questionRepo, quizRepo } = createTestService();
      await questionRepo.add({ ...makeQuestion({ id: 'q1' }), type: 'multiple', correctAnswer: ['A', 'C'] });
      await quizRepo.add({ id: 'quiz1', questionIds: ['q1'], title: 'Test' });

      const result = await service.submitAnswers('quiz1', 'u1', [{ questionId: 'q1', answer: ['A', 'C'] }]);
      assertEqual(result.answers[0].isCorrect, true);
    });

    await it('should not auto-grade subjective questions', async () => {
      const { service, questionRepo, quizRepo } = createTestService();
      await questionRepo.add({ ...makeQuestion({ id: 'q1' }), type: 'subjective', correctAnswer: '' });
      await quizRepo.add({ id: 'quiz1', questionIds: ['q1'], title: 'Test' });

      const result = await service.submitAnswers('quiz1', 'u1', [{ questionId: 'q1', answer: 'My essay answer' }]);
      assertEqual(result.answers[0].autoGraded, false);
      assertEqual(result.answers[0].isCorrect, null);
      assertEqual(result.objectiveScore, null);
    });

    await it('should throw for missing quizId', async () => {
      const { service } = createTestService();
      await assertThrowsAsync(() => service.submitAnswers('', 'u1', []), 'quizId is required');
    });

    await it('should throw for quiz with no questions', async () => {
      const { service, quizRepo } = createTestService();
      await quizRepo.add({ id: 'empty-quiz', questionIds: [], title: 'Empty' });
      await assertThrowsAsync(() => service.submitAnswers('empty-quiz', 'u1', []), 'Quiz has no questions');
    });
  });
}
"}

