  describe('ModerationService.checkContent()', async () => {
    await it('should flag sensitive words', async () => {
      const { service } = createModTestService();
      const result = service.checkContent('This is spam content');
      assert(result.flagged);
      assert(result.words.includes('spam'));
    });

    await it('should not flag clean content', async () => {
      const { service } = createModTestService();
      const result = service.checkContent('This is great content');
      assert(!result.flagged);
    });

    await it('should handle null/empty text', async () => {
      const { service } = createModTestService();
      assert(!service.checkContent(null).flagged);
      assert(!service.checkContent('').flagged);
    });
  });

  describe('ModerationService.resolveReport()', async () => {
    await it('should resolve a report', async () => {
      const { service } = createModTestService();
      const report = await service.submitReport('u1', 'target1', 'review', 'Bad content');
      const resolved = await service.resolveReport(report.id, REPORT_OUTCOMES.DISMISSED, 'rev1');
      assertEqual(resolved.status, REPORT_STATUS.RESOLVED);
      assertEqual(resolved.resolution, REPORT_OUTCOMES.DISMISSED);
    });

    await it('should reject double resolution', async () => {
      const { service } = createModTestService();
      const report = await service.submitReport('u1', 'target1', 'review', 'Bad');
      await service.resolveReport(report.id, REPORT_OUTCOMES.DISMISSED, 'rev1');
      await assertThrowsAsync(
        () => service.resolveReport(report.id, REPORT_OUTCOMES.REMOVED, 'rev1'),
        'already been resolved'
      );
    });

    await it('should reject invalid outcome', async () => {
      const { service } = createModTestService();
      const report = await service.submitReport('u1', 'target1', 'review', 'Bad');
      await assertThrowsAsync(
        () => service.resolveReport(report.id, 'invalid_outcome', 'rev1'),
        'Outcome must be one of'
      );
    });
  });
}

// ============================================================
// ReputationService Tests
// ============================================================

export async function runReputationTests() {
  describe('ReputationService — Score Computation', async () => {
    await it('should compute score in 0-100 range', async () => {
      // Perfect metrics: fulfillment=1, lateRate=0, complaintRate=0
      // score = (1*0.5 + (1-0)*0.3 + (1-0)*0.2) * 100 = 100
      const score = Math.round((1 * 0.5 + (1 - 0) * 0.3 + (1 - 0) * 0.2) * 100);
      assertEqual(score, 100);
    });

    await it('should compute low score for bad metrics', async () => {
      // fulfillment=0.2, lateRate=0.8, complaintRate=0.5
      // score = (0.2*0.5 + 0.2*0.3 + 0.5*0.2) * 100 = (0.1 + 0.06 + 0.1) * 100 = 26
      const score = Math.round((0.2 * 0.5 + (1 - 0.8) * 0.3 + (1 - 0.5) * 0.2) * 100);
      assertEqual(score, 26);
    });

    await it('should clamp to 0 minimum', async () => {
      const score = Math.max(0, Math.min(100, -10));
      assertEqual(score, 0);
    });

    await it('should flag users below threshold 60 as restricted', async () => {
      assert(26 < 60, 'Score 26 should be below threshold');
      assert(!(100 < 60), 'Score 100 should not be below threshold');
    });
  });
}

