 * Integration Test — Full Registration Lifecycle
 * Tests the complete journey: Draft → Submitted → Review → Approved/Rejected
 * Including role-based access, batch operations, and waitlist promotion.
 */

import { describe, it, assert, assertEqual, assertThrowsAsync, InMemoryStore, makeUser, makeClass } from '../test-helpers.js';
import { REGISTRATION_STATUS } from '../../src/models/Registration.js';
import { USER_ROLES } from '../../src/models/User.js';

function createFullTestEnv() {
  const registrationRepo = new InMemoryStore();
  const eventRepo = new InMemoryStore();
  const classRepo = new InMemoryStore();
  const userRepo = new InMemoryStore();
  const auditLogs = [];
  const auditService = { async log(et, ei, action, details, uid) { auditLogs.push({ entityType: et, entityId: ei, action, details, userId: uid, timestamp: new Date().toISOString() }); } };

  // Full service mirroring RegistrationService
  const REVIEWER_ONLY = [REGISTRATION_STATUS.UNDER_REVIEW, REGISTRATION_STATUS.APPROVED, REGISTRATION_STATUS.REJECTED, REGISTRATION_STATUS.NEEDS_MORE_INFO, REGISTRATION_STATUS.WAITLISTED];
  const { canTransition } = { canTransition: (from, to) => {
    const transitions = {
      Draft: ['Submitted', 'Cancelled'],
      Submitted: ['NeedsMoreInfo', 'UnderReview', 'Cancelled', 'Waitlisted'],
      NeedsMoreInfo: ['Submitted', 'Cancelled'],
      UnderReview: ['Approved', 'Rejected', 'NeedsMoreInfo', 'Cancelled'],
      Waitlisted: ['UnderReview', 'Cancelled'],
      Approved: [], Rejected: [], Cancelled: [],
    };
    return (transitions[from] || []).includes(to);
  }};

  const service = {
    async create(userId, classId, notes) {
      if (!userId) throw new Error('userId is required to create a registration.');
      const reg = { id: `reg-${Math.random().toString(36).slice(2)}`, userId, classId, notes: notes || '', status: REGISTRATION_STATUS.DRAFT, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() };
      await registrationRepo.add(reg);
      await auditService.log('registration', reg.id, 'created', 'Draft', userId);
      return reg;
    },
    async transition(regId, newStatus, comment, userId) {
      if (!regId || !newStatus || !userId) throw new Error('Missing required parameters.');
      const reg = await registrationRepo.getById(regId);
      if (!reg) throw new Error('Registration not found.');
      if (!canTransition(reg.status, newStatus)) throw new Error(`Cannot transition from ${reg.status} to ${newStatus}.`);
      const user = await userRepo.getById(userId);
      if (user) {
        const isRA = [USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(user.role);
        if (REVIEWER_ONLY.includes(newStatus) && !isRA) throw new Error(`Only reviewers can transition to ${newStatus}.`);
        if (!isRA && reg.userId !== userId) throw new Error('You can only modify your own registrations.');
        if (!isRA && ![REGISTRATION_STATUS.SUBMITTED, REGISTRATION_STATUS.CANCELLED].includes(newStatus)) throw new Error('Insufficient permissions.');
      }
      if (newStatus === REGISTRATION_STATUS.REJECTED && (!comment || comment.trim().length < 20)) throw new Error('Rejection comment must be at least 20 characters.');
      const from = reg.status;
      reg.status = newStatus;
      reg.updatedAt = new Date().toISOString();
      await registrationRepo.put(reg);
      await eventRepo.add({ id: `ev-${Date.now()}-${Math.random()}`, registrationId: reg.id, fromStatus: from, toStatus: newStatus, comment: comment || '', userId, timestamp: new Date().toISOString() });
      await auditService.log('registration', reg.id, 'status_change', `${from} → ${newStatus}`, userId);
      return reg;
    },
    async getEvents(regId) { return (await eventRepo.getAll()).filter(e => e.registrationId === regId); },
  };

  return { service, registrationRepo, eventRepo, classRepo, userRepo, auditLogs };
}

export async function runRegistrationLifecycleTests() {
  describe('Integration: Happy Path — Learner submits, Reviewer approves', async () => {
    await it('should complete full approval flow', async () => {
      const { service, userRepo } = createFullTestEnv();
      const learner = makeUser({ id: 'learner1', role: USER_ROLES.LEARNER });
      const reviewer = makeUser({ id: 'rev1', role: USER_ROLES.STAFF_REVIEWER });
      await userRepo.add(learner);
      await userRepo.add(reviewer);

      // Learner creates draft
      const reg = await service.create('learner1', 'class1');
      assertEqual(reg.status, REGISTRATION_STATUS.DRAFT);

      // Learner submits
      await service.transition(reg.id, REGISTRATION_STATUS.SUBMITTED, '', 'learner1');

      // Reviewer moves to Under Review
      await service.transition(reg.id, REGISTRATION_STATUS.UNDER_REVIEW, '', 'rev1');

      // Reviewer approves
      const approved = await service.transition(reg.id, REGISTRATION_STATUS.APPROVED, '', 'rev1');
      assertEqual(approved.status, REGISTRATION_STATUS.APPROVED);

      // Verify audit trail has all events
      const events = await service.getEvents(reg.id);
      assert(events.length >= 3, `Expected >= 3 events, got ${events.length}`);
    });
  });

  describe('Integration: Rejection Flow', async () => {
    await it('should complete rejection with required comment', async () => {
      const { service, userRepo } = createFullTestEnv();
      await userRepo.add(makeUser({ id: 'l1', role: USER_ROLES.LEARNER }));
      await userRepo.add(makeUser({ id: 'r1', role: USER_ROLES.STAFF_REVIEWER }));

      const reg = await service.create('l1', 'c1');
      await service.transition(reg.id, REGISTRATION_STATUS.SUBMITTED, '', 'l1');
      await service.transition(reg.id, REGISTRATION_STATUS.UNDER_REVIEW, '', 'r1');
      const rejected = await service.transition(reg.id, REGISTRATION_STATUS.REJECTED, 'Missing documentation and proof of identity required by policy.', 'r1');
      assertEqual(rejected.status, REGISTRATION_STATUS.REJECTED);
    });
  });

  describe('Integration: Needs More Info → Resubmit flow', async () => {
    await it('should allow resubmission after info request', async () => {
      const { service, userRepo } = createFullTestEnv();
      await userRepo.add(makeUser({ id: 'l1', role: USER_ROLES.LEARNER }));
      await userRepo.add(makeUser({ id: 'r1', role: USER_ROLES.STAFF_REVIEWER }));

      const reg = await service.create('l1', 'c1');
      await service.transition(reg.id, REGISTRATION_STATUS.SUBMITTED, '', 'l1');
      await service.transition(reg.id, REGISTRATION_STATUS.UNDER_REVIEW, '', 'r1');
      await service.transition(reg.id, REGISTRATION_STATUS.NEEDS_MORE_INFO, 'Need ID scan', 'r1');
      // Learner resubmits
      await service.transition(reg.id, REGISTRATION_STATUS.SUBMITTED, '', 'l1');
      await service.transition(reg.id, REGISTRATION_STATUS.UNDER_REVIEW, '', 'r1');
      const approved = await service.transition(reg.id, REGISTRATION_STATUS.APPROVED, '', 'r1');
      assertEqual(approved.status, REGISTRATION_STATUS.APPROVED);
    });
  });

  describe('Integration: Cancellation from multiple states', async () => {
    await it('should allow cancellation from Draft', async () => {
      const { service, userRepo } = createFullTestEnv();
      await userRepo.add(makeUser({ id: 'l1', role: USER_ROLES.LEARNER }));
      const reg = await service.create('l1', 'c1');
      const cancelled = await service.transition(reg.id, REGISTRATION_STATUS.CANCELLED, 'Changed mind', 'l1');
      assertEqual(cancelled.status, REGISTRATION_STATUS.CANCELLED);
    });

    await it('should allow cancellation from Submitted', async () => {
      const { service, userRepo } = createFullTestEnv();
      await userRepo.add(makeUser({ id: 'l1', role: USER_ROLES.LEARNER }));
      const reg = await service.create('l1', 'c1');
      await service.transition(reg.id, REGISTRATION_STATUS.SUBMITTED, '', 'l1');
      const cancelled = await service.transition(reg.id, REGISTRATION_STATUS.CANCELLED, '', 'l1');
      assertEqual(cancelled.status, REGISTRATION_STATUS.CANCELLED);
    });
  });

  describe('Integration: Role-based access across lifecycle', async () => {
    await it('should prevent learner from approving at any stage', async () => {
      const { service, userRepo, registrationRepo } = createFullTestEnv();
      await userRepo.add(makeUser({ id: 'l1', role: USER_ROLES.LEARNER }));
      await registrationRepo.add({ id: 'r1', userId: 'l1', classId: 'c1', status: REGISTRATION_STATUS.UNDER_REVIEW, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });
      await assertThrowsAsync(
        () => service.transition('r1', REGISTRATION_STATUS.APPROVED, '', 'l1'),
        'Only reviewers'
      );
    });

    await it('should prevent instructor from rejecting', async () => {
      const { service, userRepo, registrationRepo } = createFullTestEnv();
      await userRepo.add(makeUser({ id: 'i1', role: USER_ROLES.INSTRUCTOR }));
      await registrationRepo.add({ id: 'r1', userId: 'l1', classId: 'c1', status: REGISTRATION_STATUS.UNDER_REVIEW, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });
      await assertThrowsAsync(
        () => service.transition('r1', REGISTRATION_STATUS.REJECTED, 'Reason that is long enough for test', 'i1'),
        'Only reviewers'
      );
    });
  });
}
"}

