 * Integration Test — Review submission + Moderation + Appeal flow
 */

import { describe, it, assert, assertEqual, assertThrowsAsync, InMemoryStore } from '../test-helpers.js';
import { REPORT_STATUS, REPORT_OUTCOMES } from '../../src/models/Report.js';
import { APPEAL_STATUS } from '../../src/models/Rating.js';

function createIntegrationEnv() {
  const reviewRepo = new InMemoryStore();
  const reportRepo = new InMemoryStore();
  const ratingRepo = new InMemoryStore();
  const appealRepo = new InMemoryStore();
  const auditLogs = [];
  const auditService = { async log(...args) { auditLogs.push(args); } };
  const sensitiveWords = ['spam', 'scam', 'fraud'];

  const moderationService = {
    checkContent(text) {
      if (!text) return { flagged: false, words: [] };
      const lower = text.toLowerCase();
      const found = sensitiveWords.filter(w => lower.includes(w));
      return { flagged: found.length > 0, words: found };
    },
    async submitReport(reporterId, targetId, targetType, reason) {
      const report = { id: `rep-${Date.now()}-${Math.random().toString(36).slice(2)}`, reporterId, targetId, targetType, reason, status: REPORT_STATUS.OPEN, resolution: null, createdAt: new Date().toISOString() };
      await reportRepo.add(report);
      return report;
    },
    async resolveReport(reportId, outcome, resolvedBy) {
      const report = await reportRepo.getById(reportId);
      if (!report) throw new Error('Report not found.');
      if (report.status === REPORT_STATUS.RESOLVED) throw new Error('Already resolved.');
      report.status = REPORT_STATUS.RESOLVED;
      report.resolution = outcome;
      report.resolvedBy = resolvedBy;
      report.resolvedAt = new Date().toISOString();
      await reportRepo.put(report);
      return report;
    },
  };

  const reviewService = {
    async submitReview({ userId, rating, text, images, tags }) {
      if (!Number.isInteger(rating) || rating < 1 || rating > 5) throw new Error('Rating must be between 1 and 5.');
      if (text) {
        const check = moderationService.checkContent(text);
        if (check.flagged) throw new Error(`Prohibited content: ${check.words.join(', ')}`);
      }
      const review = { id: `rev-${Date.now()}-${Math.random().toString(36).slice(2)}`, userId, rating, text: text || '', images: images || [], tags: tags || [], followUpOf: null, createdAt: new Date().toISOString() };
      await reviewRepo.add(review);
      return review;
    },
  };

  const ratingService = {
    async submitRating({ fromUserId, toUserId, score }) {
      if (fromUserId === toUserId) throw new Error('Cannot rate yourself.');
      const rating = { id: `rat-${Date.now()}-${Math.random().toString(36).slice(2)}`, fromUserId, toUserId, score, createdAt: new Date().toISOString() };
      await ratingRepo.add(rating);
      return rating;
    },
    async fileAppeal(ratingId, appealerId, reason) {
      const appeal = { id: `app-${Date.now()}`, ratingId, appealerId, reason, status: APPEAL_STATUS.PENDING, createdAt: new Date().toISOString() };
      await appealRepo.add(appeal);
      return appeal;
    },
    async resolveAppeal(appealId, decision, rationale, reviewerId, adjustedScore) {
      const appeal = await appealRepo.getById(appealId);
      if (appeal.status !== APPEAL_STATUS.PENDING) throw new Error('Already resolved.');
      appeal.status = decision;
      appeal.rationale = rationale;
      appeal.reviewerId = reviewerId;
      await appealRepo.put(appeal);
      if (decision === APPEAL_STATUS.ADJUSTED) {
        const rating = await ratingRepo.getById(appeal.ratingId);
        rating.score = adjustedScore;
        await ratingRepo.put(rating);
      }
      return appeal;
    },
  };

  return { reviewService, moderationService, ratingService, reviewRepo, reportRepo, ratingRepo, appealRepo, auditLogs };
}

export async function runReviewModerationFlowTests() {
  describe('Integration: Review → Report → Resolution', async () => {
    await it('should complete full moderation flow', async () => {
      const env = createIntegrationEnv();

      // User submits review
      const review = await env.reviewService.submitReview({ userId: 'u1', rating: 4, text: 'Great class' });

      // Another user reports it
      const report = await env.moderationService.submitReport('u2', review.id, 'review', 'Suspicious content');
      assertEqual(report.status, REPORT_STATUS.OPEN);

      // Moderator resolves
      const resolved = await env.moderationService.resolveReport(report.id, REPORT_OUTCOMES.DISMISSED, 'mod1');
      assertEqual(resolved.status, REPORT_STATUS.RESOLVED);
      assertEqual(resolved.resolution, REPORT_OUTCOMES.DISMISSED);
    });
  });

  describe('Integration: Review blocked by sensitive words', async () => {
    await it('should block review at service level', async () => {
      const env = createIntegrationEnv();
      await assertThrowsAsync(
        () => env.reviewService.submitReview({ userId: 'u1', rating: 3, text: 'This is a spam review' }),
        'Prohibited content'
      );

      // Verify nothing was persisted
      const all = await env.reviewRepo.getAll();
      assertEqual(all.length, 0);
    });
  });

  describe('Integration: Rating → Appeal → Resolution', async () => {
    await it('should complete full appeal flow with adjustment', async () => {
      const env = createIntegrationEnv();

      // User rates another
      const rating = await env.ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u2', score: 1 });
      assertEqual(rating.score, 1);

      // Rated user appeals
      const appeal = await env.ratingService.fileAppeal(rating.id, 'u2', 'Rating is unfair');
      assertEqual(appeal.status, APPEAL_STATUS.PENDING);

      // Reviewer adjusts
      const resolved = await env.ratingService.resolveAppeal(appeal.id, APPEAL_STATUS.ADJUSTED, 'Adjusting to 3', 'rev1', 3);
      assertEqual(resolved.status, APPEAL_STATUS.ADJUSTED);

      // Verify original rating was updated
      const updated = await env.ratingRepo.getById(rating.id);
      assertEqual(updated.score, 3);
    });
  });

  describe('Integration: Double resolution prevention', async () => {
    await it('should prevent resolving same report twice', async () => {
      const env = createIntegrationEnv();
      const review = await env.reviewService.submitReview({ userId: 'u1', rating: 4, text: 'Good' });
      const report = await env.moderationService.submitReport('u2', review.id, 'review', 'Reason');
      await env.moderationService.resolveReport(report.id, REPORT_OUTCOMES.DISMISSED, 'mod1');
      await assertThrowsAsync(
        () => env.moderationService.resolveReport(report.id, REPORT_OUTCOMES.REMOVED, 'mod1'),
        'Already resolved'
      );
    });
  });
}
"}

