 * Integration Test — Contract template → generation → signing → export flow
 */

import { describe, it, assert, assertEqual, assertThrowsAsync, InMemoryStore } from '../test-helpers.js';

const CONTRACT_STATUS = { INITIATED: 'initiated', SIGNED: 'signed', WITHDRAWN: 'withdrawn', VOIDED: 'voided' };
const CONTRACT_TRANSITIONS = {
  initiated: ['signed', 'withdrawn', 'voided'],
  signed: ['voided'],
  withdrawn: [],
  voided: [],
};

function createContractEnv() {
  const contractRepo = new InMemoryStore();
  const templateRepo = new InMemoryStore();
  const auditLogs = [];
  const auditService = { async log(...args) { auditLogs.push(args); } };

  const service = {
    async createTemplate(data) {
      const placeholders = (data.content.match(/\{[^}]+\}/g) || []);
      const tpl = { id: `tpl-${Date.now()}`, name: data.name, content: data.content, placeholders, active: true, version: 1, effectiveDate: new Date().toISOString(), createdAt: new Date().toISOString() };
      await templateRepo.add(tpl);
      return tpl;
    },
    async generateContract(templateId, variables, createdBy) {
      const tpl = await templateRepo.getById(templateId);
      if (!tpl) throw new Error('Template not found.');
      let content = tpl.content;
      for (const [k, v] of Object.entries(variables)) content = content.replace(new RegExp(`\\{${k}\\}`, 'g'), v);
      const contract = { id: `con-${Date.now()}`, templateId, templateVersion: tpl.version, content, status: CONTRACT_STATUS.INITIATED, signatureData: null, signatureHash: null, signedBy: null, signedAt: null, createdBy, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() };
      await contractRepo.add(contract);
      return contract;
    },
    async signContract(contractId, signatureData, signerName, userId) {
      const contract = await contractRepo.getById(contractId);
      if (!contract) throw new Error('Contract not found.');
      if (contract.status !== CONTRACT_STATUS.INITIATED) throw new Error('Contract can only be signed when in initiated status.');
      if (!signatureData || String(signatureData).trim() === '') throw new Error('Signature is required before signing.');
      if (!signerName || String(signerName).trim() === '') throw new Error('Signer name is required.');
      // Simulate SHA-256 hash
      const hash = `sha256_${contract.content.length}_${signerName}_${Date.now()}`;
      contract.signatureData = signatureData;
      contract.signatureHash = hash;
      contract.signedBy = userId;
      contract.signedAt = new Date().toISOString();
      contract.status = CONTRACT_STATUS.SIGNED;
      contract.updatedAt = new Date().toISOString();
      await contractRepo.put(contract);
      return contract;
    },
    async transitionStatus(contractId, newStatus, userId) {
      const contract = await contractRepo.getById(contractId);
      if (!contract) throw new Error('Contract not found.');
      const allowed = CONTRACT_TRANSITIONS[contract.status] || [];
      if (!allowed.includes(newStatus)) throw new Error(`Cannot transition from ${contract.status} to ${newStatus}.`);
      const from = contract.status;
      contract.status = newStatus;
      contract.updatedAt = new Date().toISOString();
      await contractRepo.put(contract);
      return contract;
    },
    async voidContract(contractId, userId) { return service.transitionStatus(contractId, CONTRACT_STATUS.VOIDED, userId); },
    async withdrawContract(contractId, userId) { return service.transitionStatus(contractId, CONTRACT_STATUS.WITHDRAWN, userId); },
  };

  return { service, contractRepo, templateRepo, auditLogs };
}

export async function runContractSigningFlowTests() {
  describe('Integration: Template → Contract → Sign → Void', async () => {
    await it('should complete full contract lifecycle', async () => {
      const { service } = createContractEnv();

      // Create template
      const tpl = await service.createTemplate({ name: 'Enrollment Agreement', content: 'Dear {LearnerName}, your class {ClassName} starts on {StartDate}.' });
      assert(tpl.placeholders.length === 3, 'Should detect 3 placeholders');

      // Generate contract
      const contract = await service.generateContract(tpl.id, { LearnerName: 'John', ClassName: 'Web Dev', StartDate: '2026-05-01' }, 'admin1');
      assert(contract.content.includes('John'));
      assert(contract.content.includes('Web Dev'));
      assertEqual(contract.status, CONTRACT_STATUS.INITIATED);

      // Sign
      const signed = await service.signContract(contract.id, 'data:image/png;base64,abc', 'John Doe', 'u1');
      assertEqual(signed.status, CONTRACT_STATUS.SIGNED);
      assert(signed.signatureHash);
      assert(signed.signedAt);

      // Void
      const voided = await service.voidContract(contract.id, 'admin1');
      assertEqual(voided.status, CONTRACT_STATUS.VOIDED);
    });
  });

  describe('Integration: Contract signing validation', async () => {
    await it('should reject signing without signature data', async () => {
      const { service } = createContractEnv();
      const tpl = await service.createTemplate({ name: 'Test', content: 'Content' });
      const contract = await service.generateContract(tpl.id, {}, 'admin1');
      await assertThrowsAsync(
        () => service.signContract(contract.id, '', 'John', 'u1'),
        'Signature is required'
      );
    });

    await it('should reject signing without signer name', async () => {
      const { service } = createContractEnv();
      const tpl = await service.createTemplate({ name: 'Test', content: 'Content' });
      const contract = await service.generateContract(tpl.id, {}, 'admin1');
      await assertThrowsAsync(
        () => service.signContract(contract.id, 'sig-data', '', 'u1'),
        'Signer name is required'
      );
    });

    await it('should reject signing already signed contract', async () => {
      const { service } = createContractEnv();
      const tpl = await service.createTemplate({ name: 'Test', content: 'Content' });
      const contract = await service.generateContract(tpl.id, {}, 'admin1');
      await service.signContract(contract.id, 'sig-data', 'John', 'u1');
      await assertThrowsAsync(
        () => service.signContract(contract.id, 'sig2', 'Jane', 'u2'),
        'initiated status'
      );
    });
  });

  describe('Integration: Contract state transitions', async () => {
    await it('should allow initiated → withdrawn', async () => {
      const { service } = createContractEnv();
      const tpl = await service.createTemplate({ name: 'T', content: 'C' });
      const contract = await service.generateContract(tpl.id, {}, 'a');
      const withdrawn = await service.withdrawContract(contract.id, 'a');
      assertEqual(withdrawn.status, CONTRACT_STATUS.WITHDRAWN);
    });

    await it('should reject withdrawn → signed', async () => {
      const { service } = createContractEnv();
      const tpl = await service.createTemplate({ name: 'T', content: 'C' });
      const contract = await service.generateContract(tpl.id, {}, 'a');
      await service.withdrawContract(contract.id, 'a');
      await assertThrowsAsync(
        () => service.transitionStatus(contract.id, CONTRACT_STATUS.SIGNED, 'a'),
        'Cannot transition'
      );
    });

    await it('should reject voided → any transition', async () => {
      const { service } = createContractEnv();
      const tpl = await service.createTemplate({ name: 'T', content: 'C' });
      const contract = await service.generateContract(tpl.id, {}, 'a');
      await service.voidContract(contract.id, 'a');
      await assertThrowsAsync(
        () => service.transitionStatus(contract.id, CONTRACT_STATUS.INITIATED, 'a'),
        'Cannot transition'
      );
    });
  });
}
"}

