      const signed = await service.signContract(contract.id, 'data:image/png;base64,abc', 'John Doe', 'u1');
      assertEqual(signed.status, CONTRACT_STATUS.SIGNED);
      assert(signed.signatureHash);
      assert(signed.signedAt);

      // Void
      const voided = await service.voidContract(contract.id, 'admin1');
      assertEqual(voided.status, CONTRACT_STATUS.VOIDED);
    });
  });

