import { describe, it, assert, assertEqual, assertThrowsAsync, InMemoryStore, makeUser, makeClass, makeQuestion } from '../test-helpers.js';
import { REGISTRATION_STATUS } from '../../src/models/Registration.js';
import { USER_ROLES } from '../../src/models/User.js';
import { APPEAL_STATUS } from '../../src/models/Rating.js';
import { REPORT_STATUS, REPORT_OUTCOMES } from '../../src/models/Report.js';
import { validateQuestionRow } from '../../src/utils/validators.js';

// ============================================================
// Full system simulation
// ============================================================

function createSystem() {
  const repos = {
    users: new InMemoryStore(),
    registrations: new InMemoryStore(),
    events: new InMemoryStore(),
    classes: new InMemoryStore(),
    questions: new InMemoryStore(),
    quizzes: new InMemoryStore(),
    quizResults: new InMemoryStore(),
    wrongQuestions: new InMemoryStore(),
    reviews: new InMemoryStore(),
    reports: new InMemoryStore(),
    ratings: new InMemoryStore(),
    appeals: new InMemoryStore(),
    threads: new InMemoryStore(),
    answers: new InMemoryStore(),
    reputationScores: new InMemoryStore(),
    favorites: new InMemoryStore(),
    browsingHistory: new InMemoryStore(),
  };

  const auditLogs = [];
  const audit = { async log(et, ei, action, details, uid) { auditLogs.push({ entityType: et, entityId: ei, action, details, userId: uid, ts: new Date().toISOString() }); } };

  const sensitiveWords = ['spam', 'scam', 'fraud'];
  const checkContent = (text) => {
    if (!text) return { flagged: false, words: [] };
    const found = sensitiveWords.filter(w => text.toLowerCase().includes(w));
    return { flagged: found.length > 0, words: found };
  };

  const canTransition = (from, to) => {
    const t = { Draft: ['Submitted', 'Cancelled'], Submitted: ['NeedsMoreInfo', 'UnderReview', 'Cancelled', 'Waitlisted'], NeedsMoreInfo: ['Submitted', 'Cancelled'], UnderReview: ['Approved', 'Rejected', 'NeedsMoreInfo', 'Cancelled'], Waitlisted: ['UnderReview', 'Cancelled'], Approved: [], Rejected: [], Cancelled: [] };
    return (t[from] || []).includes(to);
  };

  return {
    repos, auditLogs,

    // Auth
    async createUser(data) {
      const user = makeUser(data);
      await repos.users.add(user);
      return user;
    },

    // Registration
    async createRegistration(userId, classId, notes) {
      if (!userId) throw new Error('userId required');
      const reg = { id: `reg-${Math.random().toString(36).slice(2)}`, userId, classId, notes: notes || '', status: 'Draft', createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() };
      await repos.registrations.add(reg);
      await audit.log('registration', reg.id, 'created', 'Draft', userId);
      return reg;
    },

    async transitionRegistration(regId, newStatus, comment, userId) {
      const reg = await repos.registrations.getById(regId);
      if (!reg) throw new Error('Registration not found.');
      if (!canTransition(reg.status, newStatus)) throw new Error(`Cannot transition from ${reg.status} to ${newStatus}.`);
      const user = await repos.users.getById(userId);
      const isRA = user && ['Administrator', 'Staff Reviewer'].includes(user.role);
      const reviewerOnly = ['UnderReview', 'Approved', 'Rejected', 'NeedsMoreInfo', 'Waitlisted'];
      if (reviewerOnly.includes(newStatus) && !isRA) throw new Error('Insufficient permissions.');
      if (!isRA && reg.userId !== userId) throw new Error('Cannot modify others registrations.');
      if (newStatus === 'Rejected' && (!comment || comment.trim().length < 20)) throw new Error('Rejection comment must be at least 20 characters.');
      const from = reg.status;
      reg.status = newStatus; reg.updatedAt = new Date().toISOString();
      await repos.registrations.put(reg);
      await repos.events.add({ id: `ev-${Date.now()}-${Math.random()}`, registrationId: regId, fromStatus: from, toStatus: newStatus, comment: comment || '', userId, timestamp: new Date().toISOString() });
      await audit.log('registration', regId, 'status_change', `${from} → ${newStatus}`, userId);
      return reg;
    },

    // Quiz
    async createQuestion(data) { const q = makeQuestion(data); await repos.questions.add(q); return q; },
    async createQuiz(title, questionIds) {
      const quiz = { id: `quiz-${Date.now()}`, title, questionIds, createdAt: new Date().toISOString() };
      await repos.quizzes.add(quiz);
      return quiz;
    },
    async submitQuizAnswers(quizId, userId, answers) {
      const quiz = await repos.quizzes.getById(quizId);
      if (!quiz) throw new Error('Quiz not found.');
      let correct = 0, total = 0;
      const graded = [];
      for (const ans of answers) {
        const q = await repos.questions.getById(ans.questionId);
        if (!q) continue;
        if (q.type === 'subjective') {
          graded.push({ questionId: q.id, answer: ans.answer, autoGraded: false, isCorrect: null });
        } else {
          total++;
          const isCorrect = String(ans.answer).trim().toLowerCase() === String(q.correctAnswer).trim().toLowerCase();
          if (isCorrect) correct++;
          graded.push({ questionId: q.id, answer: ans.answer, autoGraded: true, isCorrect });
          if (!isCorrect) await repos.wrongQuestions.add({ id: `wq-${Date.now()}-${Math.random()}`, userId, questionId: q.id, createdAt: new Date().toISOString() });
        }
      }
      const result = { id: `res-${Date.now()}`, quizId, userId, answers: graded, objectiveScore: total > 0 ? Math.round((correct / total) * 100) : null, subjectiveScores: {}, totalScore: null, submittedAt: new Date().toISOString() };
      await repos.quizResults.add(result);
      return result;
    },

    // Review
    async submitReview({ userId, rating, text, images, tags }) {
      if (!Number.isInteger(rating) || rating < 1 || rating > 5) throw new Error('Rating 1-5 required.');
      if (text && text.length > 2000) throw new Error('Max 2000 chars.');
      if (text) { const c = checkContent(text); if (c.flagged) throw new Error(`Prohibited: ${c.words.join(', ')}`); }
      if (images && images.length > 6) throw new Error('Max 6 images.');
      if (images) for (const img of images) if (img.size > 2 * 1024 * 1024) throw new Error('Max 2MB per image.');
      const review = { id: `rev-${Date.now()}-${Math.random().toString(36).slice(2)}`, userId, rating, text: text || '', images: images || [], tags: tags || [], createdAt: new Date().toISOString() };
      await repos.reviews.add(review);
      return review;
    },

    // Rating + Appeal
    async submitRating(from, to, score) {
      if (from === to) throw new Error('Cannot self-rate.');
      const r = { id: `rat-${Date.now()}-${Math.random().toString(36).slice(2)}`, fromUserId: from, toUserId: to, score, createdAt: new Date().toISOString() };
      await repos.ratings.add(r);
      return r;
    },
    async fileAppeal(ratingId, appealerId, reason) {
      const a = { id: `app-${Date.now()}`, ratingId, appealerId, reason, status: 'pending', createdAt: new Date().toISOString() };
      await repos.appeals.add(a);
      return a;
    },
    async resolveAppeal(appealId, decision, rationale, reviewerId, adjustedScore) {
      const a = await repos.appeals.getById(appealId);
      if (a.status !== 'pending') throw new Error('Already resolved.');
      a.status = decision; a.rationale = rationale; a.reviewerId = reviewerId;
      await repos.appeals.put(a);
      if (decision === 'adjusted') {
        const r = await repos.ratings.getById(a.ratingId);
        r.score = adjustedScore;
        await repos.ratings.put(r);
      }
      return a;
    },

    // Report
    async reportContent(reporterId, targetId, reason) {
      const r = { id: `rep-${Date.now()}-${Math.random().toString(36).slice(2)}`, reporterId, targetId, reason, status: 'open', createdAt: new Date().toISOString() };
      await repos.reports.add(r);
      return r;
    },
    async resolveReport(reportId, outcome, resolvedBy) {
      const r = await repos.reports.getById(reportId);
      if (r.status === 'resolved') throw new Error('Already resolved.');
      r.status = 'resolved'; r.resolution = outcome; r.resolvedBy = resolvedBy; r.resolvedAt = new Date().toISOString();
      await repos.reports.put(r);
      return r;
    },

    checkContent,
  };
}

// ============================================================
// E2E Tests
// ============================================================

export async function runE2ETests() {
  describe('E2E: Learner registration journey', async () => {
    await it('should complete full journey: register → submit → review → approve', async () => {
      const sys = createSystem();
      const learner = await sys.createUser({ id: 'learner1', role: USER_ROLES.LEARNER });
      const reviewer = await sys.createUser({ id: 'rev1', role: USER_ROLES.STAFF_REVIEWER });
      const cls = makeClass({ id: 'class1', capacity: 30 });
      await sys.repos.classes.add(cls);

      const reg = await sys.createRegistration('learner1', 'class1', 'Interested in this class');
      assertEqual(reg.status, 'Draft');

      await sys.transitionRegistration(reg.id, 'Submitted', '', 'learner1');
      await sys.transitionRegistration(reg.id, 'UnderReview', '', 'rev1');
      const approved = await sys.transitionRegistration(reg.id, 'Approved', '', 'rev1');
      assertEqual(approved.status, 'Approved');

      assert(sys.auditLogs.length >= 4, 'Should have at least 4 audit entries');
    });
  });

  describe('E2E: Quiz completion journey', async () => {
    await it('should complete: create questions → generate quiz → take → see results', async () => {
      const sys = createSystem();

      const q1 = await sys.createQuestion({ id: 'q1', questionText: 'What is 2+2?', type: 'single', correctAnswer: 'B', difficulty: 3, tags: ['math'] });
      const q2 = await sys.createQuestion({ id: 'q2', questionText: 'Capital of France?', type: 'fill-in', correctAnswer: 'Paris', difficulty: 2, tags: ['geo'] });
      const q3 = await sys.createQuestion({ id: 'q3', questionText: 'Explain gravity', type: 'subjective', difficulty: 4, tags: ['physics'] });

      const quiz = await sys.createQuiz('Final Exam', ['q1', 'q2', 'q3']);

      const result = await sys.submitQuizAnswers(quiz.id, 'learner1', [
        { questionId: 'q1', answer: 'B' },      // correct
        { questionId: 'q2', answer: 'London' },  // wrong
        { questionId: 'q3', answer: 'Gravity is a force that attracts objects' },  // subjective
      ]);

      assertEqual(result.objectiveScore, 50); // 1/2 objective correct
      assertEqual(result.answers.length, 3);
      assertEqual(result.answers[0].isCorrect, true);
      assertEqual(result.answers[1].isCorrect, false);
      assertEqual(result.answers[2].autoGraded, false);

      // Check wrong question was tracked
      const wrongQs = await sys.repos.wrongQuestions.getAll();
      assert(wrongQs.length > 0, 'Wrong question should be tracked');
    });
  });

  describe('E2E: Review + moderation journey', async () => {
    await it('should complete: submit review → report → moderate', async () => {
      const sys = createSystem();

      const review = await sys.submitReview({ userId: 'u1', rating: 5, text: 'Excellent class!', tags: ['helpful'] });
      assert(review.id);

      // Another user reports it
      const report = await sys.reportContent('u2', review.id, 'Seems like a fake review');
      assertEqual(report.status, 'open');

      // Moderator resolves
      const resolved = await sys.resolveReport(report.id, 'dismissed', 'mod1');
      assertEqual(resolved.status, 'resolved');
    });
  });

  describe('E2E: Two-way rating + appeal journey', async () => {
    await it('should handle rating → appeal → adjustment', async () => {
      const sys = createSystem();

      const rating = await sys.submitRating('instructor1', 'learner1', 2);
      assertEqual(rating.score, 2);

      const appeal = await sys.fileAppeal(rating.id, 'learner1', 'Rating seems unfairly low');
      assertEqual(appeal.status, 'pending');

      const resolved = await sys.resolveAppeal(appeal.id, 'adjusted', 'Score adjusted based on evidence', 'rev1', 4);
      assertEqual(resolved.status, 'adjusted');

      const updatedRating = await sys.repos.ratings.getById(rating.id);
      assertEqual(updatedRating.score, 4);
    });
  });

  describe('E2E: Sensitive word blocking across flows', async () => {
    await it('should block spam in reviews', async () => {
      const sys = createSystem();
      await assertThrowsAsync(
        () => sys.submitReview({ userId: 'u1', rating: 3, text: 'This is spam content' }),
        'Prohibited'
      );
    });

    await it('should block fraud in reviews', async () => {
      const sys = createSystem();
      await assertThrowsAsync(
        () => sys.submitReview({ userId: 'u1', rating: 3, text: 'Fraud alert!' }),
        'Prohibited'
      );
    });
  });

  describe('E2E: Rejection without comment fails', async () => {
    await it('should enforce 20-char comment requirement end-to-end', async () => {
      const sys = createSystem();
      await sys.createUser({ id: 'l1', role: USER_ROLES.LEARNER });
      await sys.createUser({ id: 'r1', role: USER_ROLES.STAFF_REVIEWER });

      const reg = await sys.createRegistration('l1', 'c1');
      await sys.transitionRegistration(reg.id, 'Submitted', '', 'l1');
      await sys.transitionRegistration(reg.id, 'UnderReview', '', 'r1');

      await assertThrowsAsync(
        () => sys.transitionRegistration(reg.id, 'Rejected', 'Short', 'r1'),
        'at least 20 characters'
      );

      // Verify registration was NOT changed
      const current = await sys.repos.registrations.getById(reg.id);
      assertEqual(current.status, 'UnderReview');
    });
  });

  describe('E2E: Unauthorized actions fail', async () => {
    await it('should prevent learner from approving registration', async () => {
      const sys = createSystem();
      await sys.createUser({ id: 'l1', role: USER_ROLES.LEARNER });
      await sys.repos.registrations.add({ id: 'r1', userId: 'l1', classId: 'c1', status: 'UnderReview', createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });

      await assertThrowsAsync(
        () => sys.transitionRegistration('r1', 'Approved', '', 'l1'),
        'Insufficient permissions'
      );
    });

    await it('should prevent self-rating', async () => {
      const sys = createSystem();
      await assertThrowsAsync(() => sys.submitRating('u1', 'u1', 5), 'Cannot self-rate');
    });
  });

  describe('E2E: Image validation end-to-end', async () => {
    await it('should reject 7 images', async () => {
      const sys = createSystem();
      await assertThrowsAsync(
        () => sys.submitReview({ userId: 'u1', rating: 3, images: Array(7).fill({ size: 100 }) }),
        'Max 6 images'
      );
    });

    await it('should reject oversized image', async () => {
      const sys = createSystem();
      await assertThrowsAsync(
        () => sys.submitReview({ userId: 'u1', rating: 3, images: [{ size: 3 * 1024 * 1024 }] }),
        'Max 2MB'
      );
    });
  });

  describe('E2E: Validator — bulk import schema', async () => {
    await it('should validate all required columns', async () => {
      const valid = { questionText: 'Q', type: 'single', correctAnswer: 'A', difficulty: 3, tags: 'math' };
      const errors = validateQuestionRow(valid, 1);
      assertEqual(errors.length, 0);
    });

    await it('should catch missing questionText', async () => {
      const errors = validateQuestionRow({ type: 'single', correctAnswer: 'A', difficulty: 3, tags: 'x' }, 1);
      assert(errors.some(e => e.includes('questionText')));
    });

    await it('should catch invalid type', async () => {
      const errors = validateQuestionRow({ questionText: 'Q', type: 'essay', correctAnswer: 'A', difficulty: 3, tags: 'x' }, 1);
      assert(errors.some(e => e.includes('type')));
    });

    await it('should catch difficulty out of range', async () => {
      const errors = validateQuestionRow({ questionText: 'Q', type: 'single', correctAnswer: 'A', difficulty: 7, tags: 'x' }, 1);
      assert(errors.some(e => e.includes('difficulty')));
    });
  });
}
"}

