70	        throw new Error(`Only administrators or staff reviewers can transition to ${newStatus}.`);
71	      }
72	
73	      // Learners/Instructors can only Submit their own drafts or Cancel their own registrations
74	      if (!isReviewerOrAdmin) {
75	        if (!isOwner) {
76	          throw new Error('You can only modify your own registrations.');
77	        }
78	        const selfAllowed = [REGISTRATION_STATUS.SUBMITTED, REGISTRATION_STATUS.CANCELLED];
79	        if (!selfAllowed.includes(newStatus)) {
80	          throw new Error(`You do not have permission to transition to ${newStatus}.`);
81	        }
82	      }
83	    }
84	
85	    // Rejection requires >=20 char comment
86	    if (newStatus === REGISTRATION_STATUS.REJECTED) {
87	      if (!comment || comment.trim().length < 20) {
88	        throw new Error('Rejection comment must be at least 20 characters.');
89	      }
90	    }
91	
92	    const fromStatus = reg.status;
93	    reg.status = newStatus;
94	    reg.updatedAt = now();
95	    await registrationRepository.put(reg);
96	
97	    await this._logEvent(reg.id, fromStatus, newStatus, comment || '', userId);
98	    await auditService.log('registration', reg.id, 'status_change', `${fromStatus} → ${newStatus}${comment ? ': ' + comment : ''}`, userId);
99	
100	    eventBus.emit('registration:transition', { registration: reg, fromStatus, toStatus: newStatus });
101	
102	    // Waitlist promotion: only when a previously APPROVED seat is freed
103	    // (i.e., an approved registration is cancelled, freeing capacity)
104	    if (fromStatus === REGISTRATION_STATUS.APPROVED && newStatus === REGISTRATION_STATUS.CANCELLED) {
105	      await this._checkWaitlistPromotion(reg.classId, userId);
106	    }
107	
108	    return reg;
109	  }
110	
111	  /**
112	   * Batch transition multiple registrations.
113	   */
114	  async batchTransition(registrationIds, newStatus, comment, userId) {
115	    const results = [];
116	    for (const id of registrationIds) {
117	      try {
118	        const reg = await this.transition(id, newStatus, comment, userId);
119	        results.push({ id, success: true, registration: reg });
120	      } catch (err) {
121	        results.push({ id, success: false, error: err.message });
122	      }
123	    }
124	    return results;
