153	   */
154	  async getClassFillRate(classId) {
155	    if (!classId) return 0;
156	    const cls = await classRepository.getById(classId);
157	    if (!cls || !cls.capacity) return 0;
158	
159	    const regs = await registrationRepository.getByClassId(classId);
160	    const approvedCount = regs.filter(r => r.status === REGISTRATION_STATUS.APPROVED).length;
