175	      r => r.classId === classId && r.status === REGISTRATION_STATUS.WAITLISTED
176	    );
177	    if (waitlisted.length === 0) return;
178	
179	    // Sort by creation date (FIFO)
180	    waitlisted.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
181	
182	    // Promote the next in line — use system/admin userId to bypass role check
183	    const next = waitlisted[0];
184	    const fromStatus = next.status;
185	    next.status = REGISTRATION_STATUS.UNDER_REVIEW;
186	    next.updatedAt = now();
187	    await registrationRepository.put(next);
