6	import reviewRepository from '../repositories/ReviewRepository.js';
7	import auditService from './AuditService.js';
8	import moderationService from './ModerationService.js';
9	import { createReview } from '../models/Review.js';
10	import { generateId, now } from '../utils/helpers.js';
11	
12	const MAX_IMAGES = 6;
13	const MAX_IMAGE_SIZE_MB = 2;
14	const MAX_TEXT_LENGTH = 2000;
15	const FOLLOW_UP_WINDOW_DAYS = 14;
16	
17	export class ReviewService {
18	  /**
19	   * Submit a new review.
20	   * Enforces: rating range, text length, image count/size, sensitive word block.
21	   */
22	  async submitReview({ userId, targetUserId, targetClassId, direction, rating, text, images, tags }) {
23	    // Validate rating
24	    if (!Number.isInteger(rating) || rating < 1 || rating > 5) {
25	      throw new Error('Rating must be between 1 and 5.');
26	    }
27	
28	    // Validate text length
29	    if (text && text.length > MAX_TEXT_LENGTH) {
30	      throw new Error(`Review text must be at most ${MAX_TEXT_LENGTH} characters.`);
31	    }
32	
33	    // Sensitive word filtering — block at service level
34	    if (text) {
35	      const modCheck = moderationService.checkContent(text);
36	      if (modCheck.flagged) {
37	        throw new Error(`Review contains prohibited content: ${modCheck.words.join(', ')}. Please revise.`);
38	      }
39	    }
40	
41	    // Validate images
42	    if (images && images.length > MAX_IMAGES) {
43	      throw new Error(`Maximum ${MAX_IMAGES} images allowed.`);
44	    }
45	    if (images) {
46	      for (const img of images) {
47	        if (img.size > MAX_IMAGE_SIZE_MB * 1024 * 1024) {
48	          throw new Error(`Each image must be under ${MAX_IMAGE_SIZE_MB}MB.`);
49	        }
50	      }
51	    }
52	
53	    const review = createReview({
54	      id: generateId(),
55	      userId,
56	      targetUserId,
57	      targetClassId,
58	      direction,
59	      rating,
60	      text: text || '',
61	      images: images || [],
62	      tags: tags || [],
63	    });
64	
65	    await reviewRepository.add(review);
66	    await auditService.log('review', review.id, 'created', `Review submitted: ${rating} stars`, userId);
67	    return review;
68	  }
69	
70	  /**
71	   * Submit a follow-up review (max 1 per original, within 14 days).
72	   * Enforces: ownership, uniqueness, window, sensitive words.
73	   */
74	  async submitFollowUp(originalReviewId, { text, rating, images, tags }, userId) {
75	    const original = await reviewRepository.getById(originalReviewId);
76	    if (!original) throw new Error('Original review not found.');
77	    if (original.userId !== userId) throw new Error('Only the original reviewer can follow up.');
78	
79	    // Check if follow-up already exists
80	    const allReviews = await reviewRepository.getByUserId(userId);
81	    const existingFollowUp = allReviews.find(r => r.followUpOf === originalReviewId);
82	    if (existingFollowUp) {
83	      throw new Error('A follow-up review has already been submitted.');
84	    }
85	
86	    // Check 14-day window
87	    const daysSince = (Date.now() - new Date(original.createdAt).getTime()) / (1000 * 60 * 60 * 24);
88	    if (daysSince > FOLLOW_UP_WINDOW_DAYS) {
89	      throw new Error(`Follow-up reviews must be submitted within ${FOLLOW_UP_WINDOW_DAYS} days.`);
90	    }
91	
92	    // Validate rating
93	    if (rating !== undefined && rating !== null) {
94	      if (!Number.isInteger(rating) || rating < 1 || rating > 5) {
95	        throw new Error('Rating must be between 1 and 5.');
96	      }
97	    }
98	
99	    // Validate text length
100	    if (text && text.length > MAX_TEXT_LENGTH) {
101	      throw new Error(`Review text must be at most ${MAX_TEXT_LENGTH} characters.`);
102	    }
103	
104	    // Sensitive word filtering — block at service level
105	    if (text) {
106	      const modCheck = moderationService.checkContent(text);
107	      if (modCheck.flagged) {
108	        throw new Error(`Follow-up contains prohibited content: ${modCheck.words.join(', ')}. Please revise.`);
109	      }
110	    }
111	
112	    // Validate images
113	    if (images && images.length > MAX_IMAGES) {
114	      throw new Error(`Maximum ${MAX_IMAGES} images allowed.`);
115	    }
116	
117	    const followUp = createReview({
118	      id: generateId(),
119	      userId,
120	      targetUserId: original.targetUserId,
121	      targetClassId: original.targetClassId,
122	      direction: original.direction,
123	      rating: rating || original.rating,
124	      text: text || '',
125	      images: images || [],
126	      tags: tags || [],
127	      followUpOf: originalReviewId,
128	    });
129	
130	    await reviewRepository.add(followUp);
131	    await auditService.log('review', followUp.id, 'follow_up', `Follow-up to review ${originalReviewId}`, userId);
132	    return followUp;
133	  }
134	
135	  async getById(reviewId) {
136	    return reviewRepository.getById(reviewId);
137	  }
138	
139	  async getAll() {
140	    return reviewRepository.getAll();
141	  }
142	
143	  async getByUserId(userId) {
144	    return reviewRepository.getByUserId(userId);
145	  }
146	
147	  async getByTargetUserId(targetUserId) {
148	    return reviewRepository.getByTargetUserId(targetUserId);
149	  }
150	
151	  async getByDirection(direction) {
152	    return reviewRepository.getByDirection(direction);
153	  }
154	}
