1	/**
2	 * QuizService — question bank CRUD, bulk import, paper generation, auto-grading, wrong-question tracking.
3	 */
4	
5	import questionRepository from '../repositories/QuestionRepository.js';
6	import quizRepository from '../repositories/QuizRepository.js';
7	import quizResultRepository from '../repositories/QuizResultRepository.js';
8	import wrongQuestionRepository from '../repositories/WrongQuestionRepository.js';
9	import auditService from './AuditService.js';
10	import { createQuestion, QUESTION_TYPES } from '../models/Question.js';
11	import { createQuiz, createQuizResult } from '../models/Quiz.js';
12	import { createWrongQuestion } from '../models/WrongQuestion.js';
13	import { generateId, now } from '../utils/helpers.js';
14	import { validateQuestionRow } from '../utils/validators.js';
15	
16	export class QuizService {
17	  // --- Question Bank CRUD ---
18	
19	  async createQuestion(data) {
20	    if (!data.questionText || String(data.questionText).trim() === '') {
21	      throw new Error('questionText is required.');
22	    }
23	    const validTypes = Object.values(QUESTION_TYPES);
24	    if (!validTypes.includes(data.type)) {
25	      throw new Error(`type must be one of: ${validTypes.join(', ')}`);
26	    }
27	    if (data.type !== QUESTION_TYPES.SUBJECTIVE && (!data.correctAnswer || String(data.correctAnswer).toString().trim() === '')) {
28	      throw new Error('correctAnswer is required for non-subjective questions.');
29	    }
30	    const diff = Number(data.difficulty);
31	    if (!Number.isInteger(diff) || diff < 1 || diff > 5) {
32	      throw new Error('difficulty must be an integer between 1 and 5.');
33	    }
34	
35	    const question = createQuestion({ id: generateId(), ...data });
36	    await questionRepository.add(question);
37	    await auditService.log('question', question.id, 'created', `Question created: ${question.type}`, data.createdBy || 'system');
38	    return question;
39	  }
40	
41	  async updateQuestion(id, updates) {
42	    const question = await questionRepository.getById(id);
43	    if (!question) throw new Error('Question not found.');
44	    Object.assign(question, updates, { updatedAt: now() });
45	    await questionRepository.put(question);
46	    return question;
47	  }
48	
49	  async deleteQuestion(id) {
50	    await questionRepository.delete(id);
51	  }
52	
53	  async getQuestionById(id) {
54	    return questionRepository.getById(id);
55	  }
56	
57	  async getAllQuestions() {
58	    return questionRepository.getAll();
59	  }
60	
61	  async getQuestionsByType(type) {
62	    return questionRepository.getByType(type);
63	  }
64	
65	  async getQuestionsByDifficulty(difficulty) {
66	    return questionRepository.getByDifficulty(difficulty);
67	  }
68	
69	  // --- Bulk Import ---
70	
71	  /**
72	   * Validate and import questions from parsed JSON/Excel data.
73	   * Rejects entire batch if any row is invalid.
74	   * @param {Array} rows — array of { questionText, type, correctAnswer, difficulty, tags, ... }
75	   * @returns {{ success: boolean, errors?: string[], count?: number }}
76	   */
77	  async bulkImport(rows, createdBy = 'system') {
78	    if (!Array.isArray(rows) || rows.length === 0) {
79	      return { success: false, errors: ['Import data must be a non-empty array.'] };
80	    }
81	
82	    const allErrors = [];
83	    for (let i = 0; i < rows.length; i++) {
84	      const errors = validateQuestionRow(rows[i], i + 1);
85	      allErrors.push(...errors);
86	    }
87	    if (allErrors.length > 0) {
88	      return { success: false, errors: allErrors };
89	    }
90	
91	    const questions = rows.map(row => createQuestion({
92	      id: generateId(),
93	      questionText: row.questionText,
94	      type: row.type,
95	      options: row.options || [],
96	      correctAnswer: row.correctAnswer,
97	      difficulty: Number(row.difficulty),
98	      tags: row.tags,
99	      chapter: row.chapter || '',
100	      explanation: row.explanation || '',
101	    }));
102	
103	    await questionRepository.bulkAdd(questions);
104	    await auditService.log('question', 'bulk', 'bulk_import', `Imported ${questions.length} questions`, createdBy);
105	
106	    return { success: true, count: questions.length };
107	  }
108	
109	  // --- Paper Generation ---
110	
111	  /**
112	   * Generate a quiz paper based on rules.
113	   * @param {object} rules — { totalQuestions, difficultyDistribution: { 3: 0.4, 4: 0.4, 5: 0.2 }, chapterConstraints: { 'ch1': 1 } }
114	   */
115	  async generatePaper(title, classId, rules, createdBy) {
116	    if (!title || String(title).trim() === '') throw new Error('Paper title is required.');
117	    if (!rules || !rules.totalQuestions) throw new Error('Paper rules with totalQuestions are required.');
118	
119	    const allQuestions = await questionRepository.getAll();
120	    if (allQuestions.length === 0) throw new Error('No questions available in the bank.');
121	
122	    const selected = this._selectQuestions(allQuestions, rules);
123	
124	    const quiz = createQuiz({
125	      id: generateId(),
126	      title,
127	      classId,
128	      questionIds: selected.map(q => q.id),
129	      rules,
130	      createdBy,
131	    });
132	
133	    await quizRepository.add(quiz);
134	    await auditService.log('quiz', quiz.id, 'created', `Paper generated: ${title}`, createdBy);
135	    return quiz;
136	  }
137	
138	  _selectQuestions(allQuestions, rules) {
139	    const total = rules.totalQuestions || 30;
140	    const distribution = rules.difficultyDistribution || {};
141	    const chapterMin = rules.chapterConstraints || {};
142	
143	    // Calculate counts per difficulty level
144	    const difficultyCounts = {};
145	    let allocated = 0;
146	    const difficulties = Object.keys(distribution).map(Number).sort();
147	
148	    for (const d of difficulties) {
149	      difficultyCounts[d] = Math.floor(total * distribution[d]);
150	      allocated += difficultyCounts[d];
151	    }
152	    // Distribute remainder to highest difficulty
153	    if (allocated < total && difficulties.length > 0) {
154	      difficultyCounts[difficulties[difficulties.length - 1]] += total - allocated;
155	    }
156	
157	    // Group questions by difficulty
158	    const byDifficulty = {};
159	    for (const q of allQuestions) {
160	      if (!byDifficulty[q.difficulty]) byDifficulty[q.difficulty] = [];
161	      byDifficulty[q.difficulty].push(q);
162	    }
163	
164	    // Shuffle each group
165	    for (const d of Object.keys(byDifficulty)) {
166	      byDifficulty[d] = this._shuffle(byDifficulty[d]);
167	    }
168	
169	    const selected = [];
170	    const usedIds = new Set();
171	
172	    // Satisfy chapter constraints first
173	    for (const [chapter, minCount] of Object.entries(chapterMin)) {
174	      const chapterQs = allQuestions.filter(q => q.chapter === chapter && !usedIds.has(q.id));
175	      for (let i = 0; i < Math.min(minCount, chapterQs.length); i++) {
176	        selected.push(chapterQs[i]);
177	        usedIds.add(chapterQs[i].id);
178	      }
179	    }
180	
181	    // Fill by difficulty
182	    for (const [d, count] of Object.entries(difficultyCounts)) {
183	      const pool = (byDifficulty[d] || []).filter(q => !usedIds.has(q.id));
184	      const needed = count - selected.filter(q => q.difficulty === Number(d)).length;
185	      for (let i = 0; i < Math.min(needed, pool.length); i++) {
186	        selected.push(pool[i]);
187	        usedIds.add(pool[i].id);
188	      }
189	    }
190	
191	    return selected.slice(0, total);
192	  }
193	
194	  _shuffle(arr) {
195	    const a = [...arr];
196	    for (let i = a.length - 1; i > 0; i--) {
197	      const j = Math.floor(Math.random() * (i + 1));
198	      [a[i], a[j]] = [a[j], a[i]];
199	    }
200	    return a;
201	  }
202	
203	  // --- Answer Evaluation ---
204	
205	  /**
206	   * Submit answers for a quiz and auto-grade objective items.
207	   */
208	  async submitAnswers(quizId, userId, answers) {
209	    if (!quizId) throw new Error('quizId is required.');
210	    if (!userId) throw new Error('userId is required.');
211	    if (!Array.isArray(answers)) throw new Error('answers must be an array.');
212	
213	    const quiz = await quizRepository.getById(quizId);
214	    if (!quiz) throw new Error('Quiz not found.');
215	    if (!quiz.questionIds || quiz.questionIds.length === 0) {
216	      throw new Error('Quiz has no questions.');
217	    }
218	
219	    const gradedAnswers = [];
220	    let objectiveCorrect = 0;
221	    let objectiveTotal = 0;
222	
223	    for (const ans of answers) {
224	      const question = await questionRepository.getById(ans.questionId);
225	      if (!question) continue;
226	
227	      const graded = { questionId: ans.questionId, answer: ans.answer, autoGraded: false, isCorrect: null };
228	
229	      if (question.type === QUESTION_TYPES.SUBJECTIVE) {
230	        graded.autoGraded = false;
231	      } else {
232	        graded.autoGraded = true;
233	        objectiveTotal++;
234	        if (question.type === QUESTION_TYPES.MULTIPLE) {
235	          const correct = Array.isArray(question.correctAnswer) ? question.correctAnswer.sort() : [];
236	          const given = Array.isArray(ans.answer) ? ans.answer.sort() : [];
237	          graded.isCorrect = JSON.stringify(correct) === JSON.stringify(given);
238	        } else {
239	          graded.isCorrect = String(ans.answer).trim().toLowerCase() === String(question.correctAnswer).trim().toLowerCase();
240	        }
241	        if (graded.isCorrect) objectiveCorrect++;
242	
243	        // Track wrong questions
244	        if (!graded.isCorrect) {
245	          await this._addWrongQuestion(userId, question, ans.answer, quizId);
246	        }
247	      }
248	
249	      gradedAnswers.push(graded);
250	    }
251	
252	    const result = createQuizResult({
253	      id: generateId(),
254	      quizId,
255	      userId,
256	      answers: gradedAnswers,
257	      objectiveScore: objectiveTotal > 0 ? Math.round((objectiveCorrect / objectiveTotal) * 100) : null,
