{"file_path": "/Users/tsiontesfaye/Projects/EaglePoint/training-ops/repo/tests/unit/test-rating-moderation-service.js", "content": "/**
 * Unit Tests — RatingService, ModerationService, QAService (REAL services, in-memory repos)
 */

import { describe, it, assert, assertEqual, assertThrowsAsync, buildTestServices } from '../test-helpers.js';
import { APPEAL_STATUS } from '../../src/models/Rating.js';
import { REPORT_STATUS, REPORT_OUTCOMES } from '../../src/models/Report.js';
import { REPUTATION_THRESHOLD } from '../../src/models/ReputationScore.js';

export async function runRatingTests() {
  await describe('RatingService.submitRating() (real service)', async () => {
    await it('should create valid rating', async () => {
      const { ratingService } = buildTestServices();
      const r = await ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u2', score: 4 });
      assertEqual(r.score, 4);
    });

    await it('should persist rating', async () => {
      const { ratingService, repos } = buildTestServices();
      const r = await ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u2', score: 3 });
      const fetched = await repos.ratingRepository.getById(r.id);
      assert(fetched !== null);
    });

    await it('should reject self-rating', async () => {
      const { ratingService } = buildTestServices();
      await assertThrowsAsync(() => ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u1', score: 3 }), 'Cannot rate yourself');
    });

    await it('should reject missing fromUserId', async () => {
      const { ratingService } = buildTestServices();
      await assertThrowsAsync(() => ratingService.submitRating({ fromUserId: '', toUserId: 'u2', score: 3 }), 'fromUserId is required');
    });

    await it('should reject score outside 1-5', async () => {
      const { ratingService } = buildTestServices();
      await assertThrowsAsync(() => ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u2', score: 0 }), 'Score must be between');
      await assertThrowsAsync(() => ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u2', score: 6 }), 'Score must be between');
    });
  });

  await describe('RatingService.fileAppeal() (real service)', async () => {
    await it('should file valid appeal', async () => {
      const { ratingService } = buildTestServices();
      const rating = await ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u2', score: 1 });
      const appeal = await ratingService.fileAppeal(rating.id, 'u2', 'Unfair rating');
      assertEqual(appeal.status, APPEAL_STATUS.PENDING);
    });

    await it('should reject duplicate pending appeal', async () => {
      const { ratingService } = buildTestServices();
      const rating = await ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u2', score: 1 });
      await ratingService.fileAppeal(rating.id, 'u2', 'First');
      await assertThrowsAsync(() => ratingService.fileAppeal(rating.id, 'u2', 'Second'), 'already pending');
    });

    await it('should reject empty reason', async () => {
      const { ratingService } = buildTestServices();
      const rating = await ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u2', score: 1 });
      await assertThrowsAsync(() => ratingService.fileAppeal(rating.id, 'u2', ''), 'Appeal reason is required');
    });
  });

  await describe('RatingService.resolveAppeal() (real service)', async () => {
    await it('should uphold appeal with rationale', async () => {
      const { ratingService } = buildTestServices();
      const rating = await ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u2', score: 1 });
      const appeal = await ratingService.fileAppeal(rating.id, 'u2', 'Unfair');
      const resolved = await ratingService.resolveAppeal(appeal.id, APPEAL_STATUS.UPHELD, 'Rating is fair', 'rev1');
      assertEqual(resolved.status, APPEAL_STATUS.UPHELD);
    });

    await it('should adjust rating score and persist', async () => {
      const { ratingService, repos } = buildTestServices();
      const rating = await ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u2', score: 1 });
      const appeal = await ratingService.fileAppeal(rating.id, 'u2', 'Too low');
      await ratingService.resolveAppeal(appeal.id, APPEAL_STATUS.ADJUSTED, 'Adjusting to 3', 'rev1', 3);
      const updated = await repos.ratingRepository.getById(rating.id);
      assertEqual(updated.score, 3);
    });

    await it('should reject double resolution', async () => {
      const { ratingService } = buildTestServices();
      const rating = await ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u2', score: 1 });
      const appeal = await ratingService.fileAppeal(rating.id, 'u2', 'Unfair');
      await ratingService.resolveAppeal(appeal.id, APPEAL_STATUS.UPHELD, 'Fair rating', 'rev1');
      await assertThrowsAsync(
        () => ratingService.resolveAppeal(appeal.id, APPEAL_STATUS.VOIDED, 'Changed mind', 'rev1'),
        'already been resolved'
      );
    });

    await it('should require rationale', async () => {
      const { ratingService } = buildTestServices();
      const rating = await ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u2', score: 1 });
      const appeal = await ratingService.fileAppeal(rating.id, 'u2', 'Unfair');
      await assertThrowsAsync(() => ratingService.resolveAppeal(appeal.id, APPEAL_STATUS.UPHELD, '', 'rev1'), 'rationale is required');
    });

    await it('should require valid adjusted score when adjusting', async () => {
      const { ratingService } = buildTestServices();
      const rating = await ratingService.submitRating({ fromUserId: 'u1', toUserId: 'u2', score: 1 });
      const appeal = await ratingService.fileAppeal(rating.id, 'u2', 'Unfair');
      await assertThrowsAsync(() => ratingService.resolveAppeal(appeal.id, APPEAL_STATUS.ADJUSTED, 'Adjust', 'rev1', null), 'Adjusted score must be');
    });
  });
}

export async function runModerationTests() {
