1	/**
2	 * Server Runtime Tests — real HTTP requests against node server.js.
3	 * Tests actual server behavior: route responses, static file serving, SPA routing.
4	 * Also tests persistence lifecycle: write → close → reopen → read.
5	 */
6	
7	import { describe, it, assert, assertEqual } from '../test-helpers.js';
8	import { InMemoryStore } from '../test-helpers.js';
9	import http from 'node:http';
10	import { spawn } from 'node:child_process';
11	
12	/**
13	 * Make an HTTP GET request and return { statusCode, headers, body }.
14	 */
15	function httpGet(url) {
16	  return new Promise((resolve, reject) => {
17	    http.get(url, (res) => {
18	      let body = '';
19	      res.on('data', chunk => body += chunk);
20	      res.on('end', () => resolve({ statusCode: res.statusCode, headers: res.headers, body }));
21	    }).on('error', reject);
22	  });
23	}
24	
25	/**
26	 * Start server on a random port, run a callback, then kill it.
27	 */
28	async function withServer(fn) {
29	  const port = 9100 + Math.floor(Math.random() * 900);
30	  const child = spawn('node', ['server.js'], {
31	    env: { ...process.env, PORT: String(port) },
32	    cwd: process.cwd(),
33	    stdio: 'pipe',
34	  });
35	
36	  // Wait for server to be ready using HTTP probe — avoids brittle timeout fallback.
37	  // Resolves as soon as the server responds to a request, or rejects after 10s.
38	  await new Promise((resolve, reject) => {
39	    let resolved = false;
40	    const deadline = setTimeout(() => {
41	      if (!resolved) {
42	        resolved = true;
43	        reject(new Error(`Server on port ${port} did not become ready within 10s`));
44	      }
45	    }, 10000);
46	
47	    // Also resolve immediately if the stdout ready message arrives
48	    child.stdout.on('data', (data) => {
49	      if (!resolved && data.toString().includes('running')) {
50	        resolved = true;
51	        clearTimeout(deadline);
52	        resolve();
53	      }
54	    });
55	
56	    // Poll via HTTP until server responds
57	    const probe = () => {
58	      if (resolved) return;
59	      http.get(`http://localhost:${port}/`, (res) => {
60	        res.resume(); // drain
61	        if (!resolved) {
62	          resolved = true;
63	          clearTimeout(deadline);
64	          resolve();
65	        }
66	      }).on('error', () => {
67	        // Not ready yet — retry after 100ms
68	        if (!resolved) setTimeout(probe, 100);
69	      });
70	    };
71	    // Start probing after a brief initial delay
72	    setTimeout(probe, 100);
73	  });
74	
75	  try {
76	    await fn(port);
77	  } finally {
78	    child.kill('SIGTERM');
79	    // Wait for cleanup
80	    await new Promise(r => setTimeout(r, 200));
81	  }
82	}
83	
84	export async function runServerRuntimeTests() {
85	
86	  // ============================================================
87	  // 1. REAL HTTP SERVER TESTS
88	  // ============================================================
89	
90	  await describe('Server runtime: real HTTP requests', async () => {
91	    await it('GET / returns 200 with HTML content', async () => {
92	      await withServer(async (port) => {
93	        const res = await httpGet(`http://localhost:${port}/`);
94	        assertEqual(res.statusCode, 200, 'Root returns 200');
95	        assert(res.body.includes('<!DOCTYPE html>') || res.body.includes('<html'), 'Returns HTML');
96	        assert(res.body.includes('TrainingOps'), 'Contains app title');
97	      });
98	    });
99	
100	    await it('GET /public/index.html returns the SPA shell', async () => {
101	      await withServer(async (port) => {
102	        const res = await httpGet(`http://localhost:${port}/public/index.html`);
103	        assertEqual(res.statusCode, 200);
104	        assert(res.body.includes('<div id="app">'), 'Contains app mount point');
105	      });
106	    });
107	
108	    await it('GET /src/app.js returns JavaScript', async () => {
109	      await withServer(async (port) => {
110	        const res = await httpGet(`http://localhost:${port}/src/app.js`);
111	        assertEqual(res.statusCode, 200);
112	        assert(res.headers['content-type'].includes('javascript'), 'Serves JS content type');
113	        assert(res.body.includes('import'), 'Contains ES module import');
114	      });
115	    });
116	
117	    await it('GET /nonexistent returns SPA fallback (not 404)', async () => {
118	      await withServer(async (port) => {
119	        const res = await httpGet(`http://localhost:${port}/nonexistent`);
120	        // Server serves index.html for SPA routing
121	        assertEqual(res.statusCode, 200, 'SPA fallback returns 200');
122	      });
123	    });
124	
125	    await it('config defaults.json is accessible', async () => {
126	      await withServer(async (port) => {
127	        const res = await httpGet(`http://localhost:${port}/src/config/defaults.json`);
128	        assertEqual(res.statusCode, 200);
129	        const config = JSON.parse(res.body);
130	        assert(config.reputation, 'Config has reputation section');
131	        assertEqual(config.reputation.threshold, 60);
132	        assertEqual(config.moderation.resolutionDeadlineDays, 7);
133	      });
134	    });
135	
136	    await it('directory traversal blocked', async () => {
137	      await withServer(async (port) => {
138	        const res = await httpGet(`http://localhost:${port}/../../../etc/passwd`);
139	        // Should NOT return actual /etc/passwd content
140	        assert(!res.body.includes('root:'), 'No directory traversal');
141	      });
142	    });
143	  });
144	
145	  // ============================================================
146	  // 2. PERSISTENCE ACROSS SESSIONS (InMemoryStore lifecycle)
147	  // ============================================================
148	
149	  await describe('Server runtime: persistence lifecycle simulation', async () => {
150	    await it('data persists across write → read cycle', async () => {
151	      // Simulate: open store → write → read (same session)
152	      const store = new InMemoryStore();
153	      await store.add({ id: 'persist-1', name: 'Test', status: 'active' });
154	      const fetched = await store.getById('persist-1');
155	      assertEqual(fetched.name, 'Test');
156	    });
157	
158	    await it('data persists after multiple operations (simulates session)', async () => {
159	      const store = new InMemoryStore();
160	
161	      // Write phase
162	      for (let i = 0; i < 10; i++) {
163	        await store.add({ id: `item-${i}`, value: i });
164	      }
165	
166	      // Update phase
167	      const item5 = await store.getById('item-5');
168	      item5.value = 500;
169	      await store.put(item5);
170	
171	      // Delete phase
172	      await store.delete('item-9');
173	
174	      // Read phase (simulates reopening)
175	      assertEqual(await store.count(), 9, '9 items remain');
176	      const updated = await store.getById('item-5');
177	      assertEqual(updated.value, 500, 'Update persisted');
178	      const deleted = await store.getById('item-9');
179	      assertEqual(deleted, null, 'Delete persisted');
180	    });
181	
182	    await it('separate store instances are isolated', async () => {
183	      const storeA = new InMemoryStore();
184	      const storeB = new InMemoryStore();
185	
186	      await storeA.add({ id: '1', source: 'A' });
187	      await storeB.add({ id: '1', source: 'B' });
188	
189	      const fromA = await storeA.getById('1');
190	      const fromB = await storeB.getById('1');
191	
192	      assertEqual(fromA.source, 'A', 'Store A has own data');
193	      assertEqual(fromB.source, 'B', 'Store B has own data');
194	    });
195	
196	    await it('bulk operations persist atomically', async () => {
197	      const store = new InMemoryStore();
198	      const records = Array.from({ length: 50 }, (_, i) => ({ id: `bulk-${i}`, value: i }));
199	
200	      await store.bulkAdd(records);
201	      assertEqual(await store.count(), 50, 'All 50 records persisted');
202	
203	      const first = await store.getById('bulk-0');
204	      const last = await store.getById('bulk-49');
205	      assertEqual(first.value, 0);
206	      assertEqual(last.value, 49);
207	    });
208	  });
209	
210	  // ============================================================
211	  // 3. SLA STRICT ENFORCEMENT AT BOUNDARY
212	  // ============================================================
213	
214	  await describe('Server runtime: SLA enforced at exact boundary', async () => {
215	    await it('scheduler double-pass resolves all overdue reports', async () => {
216	      const { buildTestServices } = await import('../test-helpers.js');
217	      const { moderationService, repos } = buildTestServices();
218	      const { REPORT_STATUS } = await import('../src/models/Report.js');
219	      const { REPORT_OUTCOMES } = await import('../src/models/Report.js');
220	
221	      const eightDaysAgo = new Date(Date.now() - 8 * 24 * 60 * 60 * 1000).toISOString();
222	
223	      await repos.reportRepository.add({
224	        id: 'sla-open', reporterId: 'u1', targetId: 't1', targetType: 'review',
225	        reason: 'Issue', status: REPORT_STATUS.OPEN, riskFlag: false, createdAt: eightDaysAgo,
226	      });
227	      await repos.reportRepository.add({
228	        id: 'sla-escalated', reporterId: 'u2', targetId: 't2', targetType: 'review',
229	        reason: 'Issue2', status: REPORT_STATUS.ESCALATED, riskFlag: false, createdAt: eightDaysAgo,
230	      });
231	
232	      // Simulate scheduler: two passes guarantee terminal resolution
233	      const pass1 = await moderationService.enforceDeadlines();
234	      const pass2 = await moderationService.enforceDeadlines();
235	
236	      // After two passes, ALL reports must be resolved
237	      for (const id of ['sla-open', 'sla-escalated']) {
238	        const r = await repos.reportRepository.getById(id);
239	        assertEqual(r.status, REPORT_STATUS.RESOLVED, `${id} is resolved`);
240	        assertEqual(r.resolution, REPORT_OUTCOMES.DISMISSED, `${id} outcome valid`);
241	      }
242	    });
243	  });
244	
245	  // ============================================================
246	  // 4. EXPORT REQUIRES PASSPHRASE
247	  // ============================================================
248	
249	  await describe('Server runtime: export dual-mode behavior', async () => {
250	    await it('export without passphrase produces plaintext with stripped credentials', () => {
251	      // In plaintext mode, passwordHash is stripped and _requiresPasswordReset is set
252	      const user = { id: 'u1', username: 'test', passwordHash: 'hash:salt', role: 'Learner' };
253	      const { passwordHash, ...safe } = user;
254	      const exported = { ...safe, _requiresPasswordReset: true };
255	      assert(!exported.passwordHash, 'Credentials stripped in plaintext mode');
256	      assert(exported._requiresPasswordReset, 'Reset flag set');
257	    });
258	
259	    await it('export with passphrase preserves credentials (encrypted)', async () => {
260	      const { CryptoService } = await import('../src/services/CryptoService.js');
261	      const crypto = new CryptoService();
262	      const data = JSON.stringify({ users: [{ id: 'u1', passwordHash: 'hash:salt' }] });
263	      const encrypted = await crypto.encrypt(data, 'mypass');
264	      const decrypted = await crypto.decrypt(encrypted, 'mypass');
265	      const parsed = JSON.parse(decrypted);
266	      assertEqual(parsed.users[0].passwordHash, 'hash:salt', 'Credentials preserved in encrypted mode');
267	    });
268	  });
269	}
